// Expo Go'da çalışmaz (SDK 53 kısıtı). EAS build gerekir.
// EAS build sonrası otomatik aktif olur.
let _N=null;
function _notif(){
  if(_N)return _N;
  try{
    // Constants ile Expo Go kontrolü
    const C2=require('expo-constants').default;
    const isExpoGo=C2?.appOwnership==='expo'||C2?.executionEnvironment==='storeClient';
    if(isExpoGo){_N=null;return null;}
    _N=require('expo-notifications');
    _N.setNotificationHandler({handleNotification:async()=>({shouldShowAlert:true,shouldPlaySound:true,shouldSetBadge:true})});
    return _N;
  }catch{return null;}
}
async function requestNotificationPermission(){
  try{
    const N=_notif();if(!N)return false;
    const{status:e}=await N.getPermissionsAsync();
    if(e==='granted')return true;
    const{status}=await N.requestPermissionsAsync();
    return status==='granted';
  }catch{return false;}
}
async function scheduleGameReminder(){
  try{
    const N=_notif();if(!N)return;
    const all=await N.getAllScheduledNotificationsAsync();
    for(const n of all){if(n.content?.data?.type==='gameReminder')await N.cancelScheduledNotificationAsync(n.identifier);}
    await N.scheduleNotificationAsync({
      content:{title:'🎮 YKS Takip seni bekliyor!',body:'Günlük sorularını çöz, sıralamada yüksel!',data:{type:'gameReminder'}},
      trigger:{type:'timeInterval',seconds:14400,repeats:true},
    });
  }catch{}
}
async function sendDuelNotification(challengerName){
  try{
    const N=_notif();if(!N)return;
    await N.scheduleNotificationAsync({
      content:{title:'⚔️ Düello daveti!',body:(challengerName||'Birisi')+' seni düelloya davet etti!',data:{type:'duelInvite'}},
      trigger:null,
    });
  }catch{}
}
