async function scanMusicTracks(){
  try{
    const audio=await MediaLibrary.getAssetsAsync({
      mediaType:MediaLibrary.MediaType.audio,
      first:200,
      sortBy:MediaLibrary.SortBy.modificationTime,
    });
    return audio.assets.map(a=>({
      t:a.filename.replace(/\.[^.]+$/,''),
      a:a.albumId||'Cihaz Müziği',
      uri:a.uri,
      id:a.id,
    }));
  }catch{return[];}
}

function useMusicPlayer(){
  const sr=useRef(null);
  const[ti,setTi]=useState(0);
  const[playing,setP]=useState(false);
  const[loading,setL]=useState(false);
  const[tracks,setTracks]=useState([]);
  const[permGranted,setPermGranted]=useState(false);
  const[scanned,setScanned]=useState(false);

  useEffect(()=>{
    (async()=>{
      const granted=await requestAudioPermission();
      setPermGranted(granted);
      if(!granted){setScanned(true);return;}
      try{
        const found=await scanMusicTracks();
        setTracks(found);
      }catch{}
      setScanned(true);
    })();
  },[]);

  const unload=async()=>{if(sr.current){try{await sr.current.unloadAsync();}catch{}sr.current=null;}};
  const play=useCallback(async(idx=0,att=0,list=null)=>{
    const tl=list||tracks;
    if(!tl||tl.length===0)return;
    if(att>=tl.length)return;
    setL(true);await unload();
    try{
      await Audio.setAudioModeAsync({playsInSilentModeIOS:true,staysActiveInBackground:true});
      const{sound}=await Audio.Sound.createAsync({uri:tl[idx].uri},{shouldPlay:true,isLooping:false});
      sr.current=sound;
      sound.setOnPlaybackStatusUpdate(s=>{if(s.didJustFinish){const ni=(idx+1)%tl.length;setTi(ni);play(ni,0,tl);}});
      setTi(idx);setP(true);
    }catch{const ni=(idx+1)%tl.length;setTi(ni);play(ni,att+1,tl);}
    setL(false);
  },[tracks]);

  const pause=async()=>{if(sr.current){try{await sr.current.pauseAsync();}catch{}setP(false);}};
  const resume=async()=>{if(sr.current){try{await sr.current.playAsync();}catch{}setP(true);}};
  const next=()=>{if(!tracks.length)return;const ni=(ti+1)%tracks.length;play(ni,0);};
  const prev=()=>{if(!tracks.length)return;const pi=(ti-1+tracks.length)%tracks.length;play(pi,0);};
  const toggle=()=>{if(!tracks.length)return;if(!sr.current)play(ti,0);else if(playing)pause();else resume();};
  useEffect(()=>()=>{unload();},[]);
  const track=tracks[ti]||{t:scanned?'Müzik bulunamadı':'Taranıyor...',a:'',uri:''};
  return{track,ti,playing,loading,toggle,next,prev,tracks,scanned,permGranted};
}

