const BAD_WORDS=['sik','orospu','piç','göt','amk','amına','bok','oç','yarrak','kaltak','sürtük','ibne','kıç','meme','taşak','salak','aptal','gerizekalı','mal','dangalak','pezevenk','orospu çocuğu','bok yedin','siktir','ananı','bacını','amcık','kahpe','kevaşe','şerefsiz','namussuz','haysiyetsiz','fuck','shit','bitch','asshole','bastard','damn','crap'];
const filterText=txt=>{
  if(!txt)return txt;
  let r=txt;
  BAD_WORDS.forEach(w=>{
    const re=new RegExp(w.replace(/[.*+?^${}()|[\]\\]/g,'\\$&'),'gi');
    r=r.replace(re,'*'.repeat(w.length));
  });
  return r;
};

const DEFAULT_YKS_DATE=new Date('2026-06-13T09:00:00');
const getYKSCountdown=(yksDateStr)=>{
  const target=yksDateStr?new Date(yksDateStr):DEFAULT_YKS_DATE;
  const now=new Date();const diff=target-now;
  if(diff<=0)return{days:0,hours:0,minutes:0,passed:true};
  const days=Math.floor(diff/(1000*60*60*24));
  const hours=Math.floor((diff%(1000*60*60*24))/(1000*60*60));
  const minutes=Math.floor((diff%(1000*60*60))/(1000*60));
  return{days,hours,minutes,passed:false};
};

const getDailyTasks=async(uid)=>{
  try{
    const key=`@yks_tasks_${uid}`;const s=await AsyncStorage.getItem(key);
    if(s){const data=JSON.parse(s);if(data.date===todayStr())return data.tasks;}
    const tasks=DAILY_TASK_DEFS.map(t=>({...t,progress:0,done:false}));
    await AsyncStorage.setItem(key,JSON.stringify({date:todayStr(),tasks}));return tasks;
  }catch{return DAILY_TASK_DEFS.map(t=>({...t,progress:0,done:false}));}
};
const saveDailyTasks=async(uid,tasks)=>{
  try{await AsyncStorage.setItem(`@yks_tasks_${uid}`,JSON.stringify({date:todayStr(),tasks}));}catch{}
};
