const getFavorites=async(uid)=>{
  try{const s=await AsyncStorage.getItem(`@yks_favs_${uid}`);return s?JSON.parse(s):[];}catch{return[];}
};
const addFavorite=async(uid,q)=>{
  const favs=await getFavorites(uid);
  if(!favs.find(f=>f.q===q.q)){favs.push({...q,savedAt:Date.now()});await AsyncStorage.setItem(`@yks_favs_${uid}`,JSON.stringify(favs));}
};
const removeFavorite=async(uid,q)=>{
  const favs=await getFavorites(uid);
  await AsyncStorage.setItem(`@yks_favs_${uid}`,JSON.stringify(favs.filter(f=>f.q!==q.q)));
};
const getWeeklyStats=async(uid)=>{
  try{const s=await AsyncStorage.getItem(`@yks_weekly_${uid}`);return s?JSON.parse(s):{week:weekOfYear(),gamesPlayed:0,ptsEarned:0,correctAnswers:0};}
  catch{return{week:weekOfYear(),gamesPlayed:0,ptsEarned:0,correctAnswers:0};}
};
const updateWeeklyStats=async(uid,delta)=>{
  try{
    const key=`@yks_weekly_${uid}`;const cur=await getWeeklyStats(uid);const wk=weekOfYear();
    const base=cur.week===wk?cur:{week:wk,gamesPlayed:0,ptsEarned:0,correctAnswers:0,prevGames:cur.gamesPlayed,prevPts:cur.ptsEarned};
    await AsyncStorage.setItem(key,JSON.stringify({...base,gamesPlayed:base.gamesPlayed+(delta.games||0),ptsEarned:base.ptsEarned+(delta.pts||0),correctAnswers:base.correctAnswers+(delta.correct||0)}));
  }catch{}
};
const getDailyQuestion=async(uid,allQ)=>{
  try{
    const key=`@yks_dq_${uid}`;const s=await AsyncStorage.getItem(key);
    if(s){const data=JSON.parse(s);if(data.date===todayStr())return data;}
    const idx=dayOfYear()%allQ.length;
    const q={...allQ[idx],choices:shuffle(allQ[idx].choices)};
    const newData={date:todayStr(),q,answered:false,wasCorrect:null};
    await AsyncStorage.setItem(key,JSON.stringify(newData));return newData;
  }catch{return null;}
};
const answerDailyQuestion=async(uid,wasCorrect)=>{
  try{const key=`@yks_dq_${uid}`;const s=await AsyncStorage.getItem(key);
    if(s){const data=JSON.parse(s);await AsyncStorage.setItem(key,JSON.stringify({...data,answered:true,wasCorrect}));}
  }catch{}
};

