/* ── Admin puan dağıtıcı ────────────────────────────── */
const distributeStats=(totalPts)=>{
  // Oyun sayısı: yaklaşık ortalama 30pt/oyun, min 1
  const gamesPlayed=Math.max(1,Math.round(totalPts/28));
  // 10 ders: mathPts,physPts,chemPts,bioPts,hisPts,geoPts,philPts,relPts,turPts,edebiPts
  const fields=['mathPts','physPts','chemPts','bioPts','hisPts','geoPts','philPts','relPts','turPts','edebiPts'];
  const gameFields=['mathGames','physGames','chemGames','bioGames','histGames','geoGames','philGames','relGames','turGames','edebiGames'];
  // Rastgele ağırlık oluştur (seed'li değil ama her çağrıda farklı - sorun değil)
  let weights=fields.map(()=>Math.random()*0.8+0.2);
  const wSum=weights.reduce((a,b)=>a+b,0);
  let remaining=totalPts;
  const subPts={};
  fields.forEach((f,i)=>{
    if(i===fields.length-1){subPts[f]=remaining;}
    else{const v=Math.round(totalPts*(weights[i]/wSum));subPts[f]=v;remaining-=v;}
  });
  const subGames={};
  gameFields.forEach((f,i)=>{subGames[f]=Math.max(0,Math.round(subPts[fields[i]]/28));});
  return{gamesPlayed,...subPts,...subGames,streak:Math.min(30,Math.round(gamesPlayed/3))};
};
