/* ══ VERİTABANI ═════════════════════════════════════ */
let _cache=null;
const db={
  _r:async()=>{
    try{
      const r=await fetch(`${BURL}/latest`,{headers:BH});
      if(!r.ok)throw new Error();
      const j=await r.json();
      _cache=j.record||{users:[],messages:[],reports:[],avatars:{},duels:[]};
      if(!_cache.users)_cache.users=[];
      if(!_cache.messages)_cache.messages=[];
      if(!_cache.reports)_cache.reports=[];
      if(!_cache.avatars)_cache.avatars={};
      return _cache;
    }catch{return _cache||{users:[],messages:[]};}
  },
  _w:async d=>{
    _cache=d;
    // avatarları users içinden çıkar ama avatars map'ine yaz
    const avatars={...(_cache.avatars||{})};
    d.users.forEach(u=>{if(u.avatar)avatars[u.id]=u.avatar;});
    const slim={...d,avatars,users:d.users.map(u=>{const{avatar,...rest}=u;return rest;})};
    try{await fetch(BURL,{method:'PUT',headers:BH,body:JSON.stringify(slim)});}catch{}
  },
  all:async()=>{
    const d=await db._r();
    const avMap=d.avatars||{};
    const users=await Promise.all(d.users.map(async u=>{
      // Önce JSONBin avatars map, yoksa yerel AsyncStorage
      const av=avMap[u.id]||(await AsyncStorage.getItem('@yks_av_'+u.id));
      return av?{...u,avatar:av}:u;
    }));
    return users;
  },
  byEmail:async e=>{
    const d=await db._r();
    const u=d.users.find(u=>u.email===e.toLowerCase().trim())||null;
    if(!u)return null;
    const av=await AsyncStorage.getItem('@yks_av_'+u.id);
    return av?{...u,avatar:av}:u;
  },
  byId:async id=>{
    const d=await db._r();
    const u=d.users.find(u=>u.id===id)||null;
    if(!u)return null;
    const avMap=d.avatars||{};
    const av=avMap[u.id]||(await AsyncStorage.getItem('@yks_av_'+u.id));
    return av?{...u,avatar:av}:u;
  },
  save:async u=>{const d=await db._r();const i=d.users.findIndex(x=>x.id===u.id);if(i>=0)d.users[i]=u;else d.users.push(u);await db._w(d);},
  update:async u=>{
    await db.save(u);
    // Avatar varsa avatars map'e ekle (diğer cihazlar görebilsin)
    if(u.avatar){
      if(!_cache.avatars)_cache.avatars={};
      _cache.avatars[u.id]=u.avatar;
      await AsyncStorage.setItem('@yks_av_'+u.id,u.avatar);
    }
    await AsyncStorage.setItem('@yks_cur_v5',JSON.stringify(u));
    return u;
  },
  // Başka kullanıcının avatarını local cache'den getir
  getAvatar:async(uid)=>{try{return await AsyncStorage.getItem('@yks_av_'+uid);}catch{return null;}},
  thread:async(a,b)=>{const d=await db._r();const t=[a,b].sort().join('_');return d.messages.filter(m=>m.thread===t).sort((x,y)=>x.ts-y.ts);},
  msg:async(f,t2,txt)=>{const d=await db._r();d.messages.push({id:genId(),thread:[f,t2].sort().join('_'),from:f,to:t2,text:txt,ts:Date.now()});await db._w(d);},
  report:async(fromId,toId,reason,detail)=>{
    const d=await db._r();
    if(!d.reports)d.reports=[];
    d.reports.push({id:genId(),fromId,toId,reason,detail,ts:Date.now(),read:false});
    await db._w(d);
  },
  getReports:async()=>{const d=await db._r(true);return d.reports||[];},
  markReportRead:async(rid)=>{
    const d=await db._r();
    const i=(d.reports||[]).findIndex(r=>r.id===rid);
    if(i>=0){d.reports[i].read=true;await db._w(d);}
  },
  deleteReport:async(rid)=>{
    const d=await db._r();
    d.reports=(d.reports||[]).filter(r=>r.id!==rid);
    await db._w(d);
  },
  // Admin notları
  sendAdminNote:async(toId,text)=>{
    const d=await db._r();
    if(!d.adminNotes)d.adminNotes=[];
    d.adminNotes.push({id:genId(),toId,text,ts:Date.now(),read:false});
    await db._w(d);
  },
  getAdminNotes:async(userId)=>{
    const d=await db._r();
    return (d.adminNotes||[]).filter(n=>n.toId===userId);
  },
  markAdminNoteRead:async(nid)=>{
    const d=await db._r();
    if(!d.adminNotes)return;
    const i=d.adminNotes.findIndex(n=>n.id===nid);
    if(i>=0){d.adminNotes[i].read=true;await db._w(d);}
  },
  cur:async()=>{
    try{
      const s=await AsyncStorage.getItem('@yks_cur_v5');
      if(!s)return null;
      const u=JSON.parse(s);
      // Avatar'ı ayrı key'den yükle (en güncel hali)
      const av=await AsyncStorage.getItem('@yks_av_'+u.id);
      return av?{...u,avatar:av}:u;
    }catch{return null;}
  },
  logout:async()=>AsyncStorage.removeItem('@yks_cur_v5'),
  study:async uid=>{try{const s=await AsyncStorage.getItem('@yks_study_v5_'+uid);return s?JSON.parse(s):mkStudy();}catch{return mkStudy();}},
  setStudy:async(uid,d)=>AsyncStorage.setItem('@yks_study_v5_'+uid,JSON.stringify(d)),
};

