const Btn=({label,onPress,color=C.primary,style={},disabled=false,small=false})=>(
  <TouchableOpacity onPress={onPress} disabled={disabled} activeOpacity={0.82}
    style={[{backgroundColor:disabled?C.light:color,borderRadius:10,padding:small?10:14,alignItems:'center'},style]}>
    <Text style={{color:'#fff',fontWeight:'700',fontSize:small?13:15}}>{label}</Text>
  </TouchableOpacity>
);
const Inp=({placeholder,value,onChangeText,secureTextEntry=false,keyboardType='default',style={},multiline=false})=>(
  <TextInput placeholder={placeholder} value={value} onChangeText={onChangeText}
    secureTextEntry={secureTextEntry} keyboardType={keyboardType}
    placeholderTextColor={C.light} autoCapitalize="none" multiline={multiline}
    style={[st.inp,style]}/>
);
const Card=memo(({children,style={}})=><View style={[st.card,style]}>{children}</View>);
const RankBadge=({pts,size='sm'})=>{
  const r=getRank(pts||0),big=size==='lg';
  return(<View style={{backgroundColor:r.bg,borderRadius:big?12:8,paddingHorizontal:big?12:8,paddingVertical:big?6:3,flexDirection:'row',alignItems:'center',gap:4}}>
    <Text style={{fontSize:big?20:12}}>{r.e}</Text>
    <Text style={{color:r.c,fontWeight:'700',fontSize:big?16:11}}>{r.l}</Text>
  </View>);
};
const Hdr=({title,subtitle,onBack,right})=>(
  <View style={st.hdr}>
    {onBack&&<TouchableOpacity onPress={onBack} style={st.back}><Text style={{fontSize:18}}>←</Text></TouchableOpacity>}
    <View style={{flex:1,marginLeft:onBack?8:0}}>
      <Text style={st.hdrT}>{title}</Text>
      {subtitle&&<Text style={st.hdrS}>{subtitle}</Text>}
    </View>
    {right}
  </View>
);
const Avatar=({user,size=42,onPress})=>{
  const av=user?.avatar;
  const s={width:size,height:size,borderRadius:size/2};
  const inner=av
    ?<Image key={av.slice(-20)} source={{uri:av.startsWith('data:')?av:'data:image/jpeg;base64,'+av}} style={[s,{borderWidth:2,borderColor:C.primary}]}/>
    :<View style={[s,{backgroundColor:C.primary,alignItems:'center',justifyContent:'center'}]}>
       <Text style={{color:'#fff',fontWeight:'800',fontSize:size*0.38}}>{(user?.name||'?')[0].toUpperCase()}</Text>
     </View>;
  return onPress?<TouchableOpacity onPress={onPress}>{inner}</TouchableOpacity>:inner;
};
const MiniPlayer=({music})=>{
  const{track,playing,loading,toggle,next,prev,tracks,scanned,permGranted}=music;
  if(!scanned)return(
    <View style={{marginBottom:14,backgroundColor:'#1e1b4b',borderRadius:12,borderWidth:1,borderColor:'#312e81',padding:12,alignItems:'center'}}>
      <Text style={{color:'#c7d2fe',fontSize:11}}>🎵 Müzik izni bekleniyor...</Text>
    </View>
  );
  if(!permGranted)return(
    <View style={{marginBottom:14,backgroundColor:'#1e1b4b',borderRadius:12,borderWidth:1,borderColor:'#312e81',padding:12,alignItems:'center'}}>
      <Text style={{color:'#c7d2fe',fontSize:11}}>🔒 Müzik erişim izni verilmedi</Text>
      <Text style={{color:'rgba(199,210,254,0.5)',fontSize:10,marginTop:2}}>Telefon ayarlarından izin ver</Text>
    </View>
  );
  if(!tracks.length)return(
    <View style={{marginBottom:14,backgroundColor:'#1e1b4b',borderRadius:12,borderWidth:1,borderColor:'#312e81',padding:12,alignItems:'center'}}>
      <Text style={{color:'#c7d2fe',fontSize:11}}>🎵 Cihazda müzik bulunamadı</Text>
      <Text style={{color:'rgba(199,210,254,0.5)',fontSize:10,marginTop:2}}>MP3 dosyalarını Downloads veya Music klasörüne koy</Text>
    </View>
  );
  return(<Card style={{marginBottom:14,flexDirection:'row',alignItems:'center',gap:8,backgroundColor:'#1e1b4b',borderColor:'#312e81'}}>
    <View style={{flex:1}}>
      <Text style={{color:'#c7d2fe',fontSize:10,fontWeight:'600'}}>{playing?'♪ Çalıyor':'♪ Müzik'}</Text>
      <Text style={{color:'#fff',fontSize:12,fontWeight:'700'}} numberOfLines={1}>{track.t}</Text>
      <Text style={{color:'#a5b4fc',fontSize:10}} numberOfLines={1}>{tracks.length} şarkı • cihaz müziği</Text>
    </View>
    {[{e:'⏮',f:prev},{e:loading?'⏳':playing?'⏸':'▶',f:toggle},{e:'⏭',f:next}].map(b=>(
      <TouchableOpacity key={b.e} onPress={b.f}
        style={{width:34,height:34,borderRadius:17,backgroundColor:'rgba(255,255,255,0.15)',alignItems:'center',justifyContent:'center'}}>
        <Text style={{fontSize:14,color:'#fff'}}>{b.e}</Text>
      </TouchableOpacity>
    ))}
  </Card>);
};


/* ══ AUTH ════════════════════════════════════════════ */
function AuthScreen({onLogin}){
  const[mode,setMode]=useState('login');
  const[name,setName]=useState('');
  const[email,setEmail]=useState('');
  const[pass,setPass]=useState('');
  const[busy,setBusy]=useState(false);
  const doLogin=async()=>{
    const e=email.toLowerCase().trim();
    if(!e||!pass){Alert.alert('Hata','E-posta ve şifre gerekli');return;}
    setBusy(true);
    try{
      const u=await db.byEmail(e);
      if(!u){Alert.alert('Hata','Bu e-posta ile kayıtlı hesap yok.');setBusy(false);return;}
      if(u.password!==pass){Alert.alert('Hata','Şifre hatalı.');setBusy(false);return;}
      await AsyncStorage.setItem('@yks_cur_v5',JSON.stringify(u));
      if(u.avatar)await AsyncStorage.setItem('@yks_av_'+u.id,u.avatar);
      onLogin(u);
    }catch{Alert.alert('Bağlantı Hatası','İnternet bağlantınızı kontrol edin.');}
    setBusy(false);
  };
  const doReg=async()=>{
    const e=email.toLowerCase().trim(),n=name.trim();
    if(!n||!e||!pass){Alert.alert('Hata','Tüm alanları doldurun');return;}
    if(pass.length<6){Alert.alert('Hata','Şifre min. 6 karakter');return;}
    setBusy(true);
    try{
      if(await db.byEmail(e)){Alert.alert('Hata','Bu e-posta zaten kayıtlı');setBusy(false);return;}
      const u={id:genId(),name:n,email:e,password:pass,avatar:null,bio:'',points:0,mathPts:0,physPts:0,chemPts:0,bioPts:0,hisPts:0,geoPts:0,philPts:0,relPts:0,gamesPlayed:0,createdAt:new Date().toISOString()};
      await db.save(u);
      await AsyncStorage.setItem('@yks_cur_v5',JSON.stringify(u));
      onLogin(u);
    }catch{Alert.alert('Bağlantı Hatası','İnternet bağlantınızı kontrol edin.');}
    setBusy(false);
  };
  return(
    <SafeAreaView style={{flex:1,backgroundColor:'#aebf57',paddingTop:TOP_INSET}}>
      <StatusBar barStyle="light-content" backgroundColor='#aebf57' translucent={false}/>
      <KeyboardAvoidingView behavior={Platform.OS==='ios'?'padding':'height'} style={{flex:1}}>
        <ScrollView contentContainerStyle={{flexGrow:1,justifyContent:'center',padding:24}}>
          <View style={{alignItems:'center',marginBottom:36}}>
            <View style={{width:76,height:76,borderRadius:24,backgroundColor:'rgba(255,255,255,0.2)',alignItems:'center',justifyContent:'center',marginBottom:14}}>
              <Text style={{fontSize:36}}>📚</Text></View>
            <Text style={{fontSize:28,fontWeight:'900',color:'#fff',letterSpacing:1}}>YKS TAKİP</Text>
            <Text style={{color:'rgba(255,255,255,0.75)',fontSize:14,marginTop:4}}>8 Ders · Sıralama · Başarımlar</Text>
          </View>
          <Card>
            <View style={{flexDirection:'row',backgroundColor:C.bg,borderRadius:10,padding:4,marginBottom:20}}>
              {[['login','Giriş Yap'],['register','Üye Ol']].map(([m,l])=>(
                <TouchableOpacity key={m} onPress={()=>setMode(m)} style={{flex:1,padding:10,borderRadius:8,alignItems:'center',backgroundColor:mode===m?'#aebf57':'transparent'}}>
                  <Text style={{fontWeight:'700',fontSize:14,color:mode===m?'#fff':C.mid}}>{l}</Text>
                </TouchableOpacity>
              ))}
            </View>
            {mode==='register'&&<Inp placeholder="Ad Soyad" value={name} onChangeText={setName}/>}
            <Inp placeholder="E-posta" value={email} onChangeText={setEmail} keyboardType="email-address"/>
            <Inp placeholder="Şifre (min. 6)" value={pass} onChangeText={setPass} secureTextEntry style={{marginBottom:0}}/>
            <View style={{height:14}}/>
            {busy?<ActivityIndicator color={C.primary}/>:<Btn label={mode==='login'?'Giriş Yap':'Hesap Oluştur'} onPress={mode==='login'?doLogin:doReg}/>}
          </Card>
        </ScrollView>
      </KeyboardAvoidingView>
    </SafeAreaView>
  );
}

/* ══ PROFİL GÖRÜNTÜLEME (başka kullanıcı) ═══════════ */
function ViewProfile({userId,me,onBack,onMessage}){
  const[u,setU]=useState(null);
  const[busy,setBusy]=useState(true);
  useEffect(()=>{db.byId(userId).then(x=>{setU(x);setBusy(false);});},[userId]);
  if(busy)return<SafeAreaView style={{flex:1,backgroundColor:C.bg,justifyContent:'center',alignItems:'center'}}><ActivityIndicator color={C.primary}/></SafeAreaView>;
  if(!u)return<SafeAreaView style={{flex:1,backgroundColor:C.bg}}><Hdr title="Profil" onBack={onBack}/><View style={{flex:1,alignItems:'center',justifyContent:'center'}}><Text style={{color:C.light}}>Kullanıcı bulunamadı</Text></View></SafeAreaView>;
  const r=getRank(u.points||0);
  const earned=ACHIEVEMENTS.filter(a=>a.check(u));
  return(
    <SafeAreaView style={{flex:1,backgroundColor:C.bg,paddingTop:TOP_INSET}}>
      <Hdr title="Profil" onBack={onBack}/>
      <ScrollView contentContainerStyle={{padding:16}}>
        <Card style={{alignItems:'center',padding:24,marginBottom:14,backgroundColor:r.bg}}>
          <Avatar user={u} size={80}/>
          <Text style={{fontSize:20,fontWeight:'800',color:C.text,marginTop:12}}>{u.name}</Text>
          <View style={{marginTop:8}}><RankBadge pts={u.points||0} size="lg"/></View>
          {u.bio?<Text style={{color:C.mid,fontSize:13,marginTop:10,textAlign:'center',fontStyle:'italic'}}>"{u.bio}"</Text>:null}
          <Text style={{color:C.light,fontSize:11,marginTop:8}}>Kayıt: {new Date(u.createdAt).toLocaleDateString('tr-TR')}</Text>
        </Card>
        <View style={{flexDirection:'row',gap:10,marginBottom:14}}>
          {[{l:'Puan',v:u.points||0,c:C.amber,e:'⭐'},{l:'Oyun',v:u.gamesPlayed||0,c:C.purple,e:'🎮'},{l:'Başarım',v:earned.length,c:C.primary,e:'🏅'}].map(s=>(
            <Card key={s.l} style={{flex:1,alignItems:'center',padding:10}}>
              <Text>{s.e}</Text>
              <Text style={{fontSize:18,fontWeight:'800',color:s.c,marginTop:4}}>{s.v}</Text>
              <Text style={{fontSize:9,color:C.light,marginTop:2}}>{s.l}</Text>
            </Card>
          ))}
        </View>
        {me.id!==u.id&&<Btn label={`💬 ${u.name} ile Mesajlaş`} onPress={()=>onMessage(u)} style={{marginBottom:14}}/>}
        {earned.length>0&&<Card>
          <Text style={{fontSize:13,fontWeight:'700',marginBottom:10}}>🏅 Kazanılan Başarımlar</Text>
          <View style={{flexDirection:'row',flexWrap:'wrap',gap:8}}>
            {earned.map(a=>(
              <View key={a.id} style={{backgroundColor:C.bg,borderRadius:8,padding:8,alignItems:'center',minWidth:72}}>
                <Text style={{fontSize:22}}>{a.emoji}</Text>
                <Text style={{fontSize:9,color:C.mid,textAlign:'center',marginTop:2}}>{a.title}</Text>
              </View>
            ))}
          </View>
        </Card>}
        <Card style={{marginTop:14}}>
          <Text style={{fontSize:13,fontWeight:'700',marginBottom:10}}>Ders Puanları</Text>
          {[{l:'Matematik',p:u.mathPts||0,e:'🔢',c:C.blue},{l:'Fizik',p:u.physPts||0,e:'⚡',c:C.amber},
            {l:'Kimya',p:u.chemPts||0,e:'⚗️',c:C.primary},{l:'Biyoloji',p:u.bioPts||0,e:'🧬',c:C.pink},
            {l:'Tarih',p:u.hisPts||0,e:'📜',c:C.orange},{l:'Coğrafya',p:u.geoPts||0,e:'🗺️',c:C.teal},
            {l:'Felsefe',p:u.philPts||0,e:'🏛️',c:C.purple},{l:'Din Kültürü',p:u.relPts||0,e:'🕌',c:C.cyan},
          ].map(g=>(<View key={g.l} style={{flexDirection:'row',alignItems:'center',marginBottom:6}}>
            <Text style={{width:24}}>{g.e}</Text>
            <Text style={{flex:1,fontSize:13,color:C.mid}}>{g.l}</Text>
            <Text style={{fontWeight:'700',color:g.c,fontSize:13}}>{g.p}</Text>
          </View>))}
        </Card>
      </ScrollView>
    </SafeAreaView>
  );
}

