/* ══ YKS GERİ SAYIM ══════════════════════════════ */
function YKSCountdownWidget({yksDate}){
  const[countdown,setCountdown]=useState(getYKSCountdown(yksDate));
  useEffect(()=>{const t=setInterval(()=>setCountdown(getYKSCountdown(yksDate)),60000);return()=>clearInterval(t);},[yksDate]);
  if(countdown.passed)return null;
  return(
    <Card style={{marginBottom:14,backgroundColor:'#1e1b4b',borderColor:'#312e81'}}>
      <Text style={{color:'#c7d2fe',fontSize:11,fontWeight:'700',marginBottom:10}}>📅 YKS GERİ SAYIM</Text>
      <View style={{flexDirection:'row',justifyContent:'space-around'}}>
        {[{v:countdown.days,l:'GÜN'},{v:countdown.hours,l:'SAAT'},{v:countdown.minutes,l:'DAKİKA'}].map(item=>(
          <View key={item.l} style={{alignItems:'center'}}>
            <View style={{backgroundColor:'rgba(255,255,255,0.15)',borderRadius:10,paddingHorizontal:14,paddingVertical:8}}>
              <Text style={{fontSize:26,fontWeight:'900',color:'#fff'}}>{String(item.v).padStart(2,'0')}</Text>
            </View>
            <Text style={{color:'#a5b4fc',fontSize:9,fontWeight:'700',marginTop:4}}>{item.l}</Text>
          </View>
        ))}
      </View>
      <Text style={{color:'#818cf8',fontSize:10,textAlign:'center',marginTop:10}}>💪 Bugün çalışmak yarın kazanmak demek!</Text>
    </Card>
  );
}

/* ══ STREAKi WİDGET ══════════════════════════════ */
function StreakWidget({streak}){
  if(!streak||streak<1)return null;
  return(
    <Card style={{marginBottom:14,backgroundColor:'#fff7ed',borderColor:'#fed7aa',flexDirection:'row',alignItems:'center',gap:12}}>
      <View style={{alignItems:'center'}}>
        <Text style={{fontSize:36}}>🔥</Text>
        <Text style={{fontSize:22,fontWeight:'900',color:C.orange,marginTop:-4}}>{streak}</Text>
      </View>
      <View style={{flex:1}}>
        <Text style={{fontSize:15,fontWeight:'800',color:C.text}}>
          {streak>=30?'🌋 Efsane Seri!':streak>=7?'⚡ Muhteşem Seri!':'🔥 Gün Serisi!'}
        </Text>
        <Text style={{fontSize:12,color:C.mid,marginTop:3}}>
          {streak>=30?'30 gün boyunca her gün girdiniz! 🏆':streak>=7?`${streak} gün üst üste! 7'de 100 bonus puan!`:`${streak} gün üst üste. Devam et!`}
        </Text>
        {streak<7&&(
          <View style={{flexDirection:'row',gap:4,marginTop:6}}>
            {Array.from({length:7}).map((_,i)=>(
              <View key={i} style={{width:20,height:6,borderRadius:3,backgroundColor:i<streak?C.orange:C.border}}/>
            ))}
            <Text style={{fontSize:9,color:C.light,marginLeft:4}}>7'ye {7-streak} kaldı</Text>
          </View>
        )}
      </View>
    </Card>
  );
}

/* ══ GÜNLÜK GÖREVLER ══════════════════════════════ */
function DailyTasksWidget({tasks}){
  if(!tasks)return null;
  const done=tasks.filter(t=>t.done).length;
  return(
    <Card style={{marginBottom:14}}>
      <View style={{flexDirection:'row',justifyContent:'space-between',alignItems:'center',marginBottom:10}}>
        <Text style={{fontSize:13,fontWeight:'800',color:C.text}}>📋 Günlük Görevler</Text>
        <View style={{backgroundColor:done===tasks.length?C.primary:C.amber+'22',borderRadius:10,paddingHorizontal:10,paddingVertical:3}}>
          <Text style={{fontSize:11,fontWeight:'700',color:done===tasks.length?C.primary:C.amber}}>{done}/{tasks.length}</Text>
        </View>
      </View>
      {tasks.map(t=>(
        <View key={t.id} style={{flexDirection:'row',alignItems:'center',gap:10,paddingVertical:6,borderBottomWidth:1,borderBottomColor:C.border}}>
          <Text style={{fontSize:20}}>{t.done?'✅':t.emoji}</Text>
          <View style={{flex:1}}>
            <Text style={{fontSize:12,fontWeight:'600',color:t.done?C.light:C.text,textDecorationLine:t.done?'line-through':'none'}}>{t.desc}</Text>
            <View style={{flexDirection:'row',alignItems:'center',gap:6,marginTop:3}}>
              <View style={{flex:1,height:4,backgroundColor:C.border,borderRadius:2}}>
                <View style={{width:`${Math.min(100,(t.progress/t.target)*100)}%`,height:'100%',backgroundColor:t.done?C.primary:C.amber,borderRadius:2}}/>
              </View>
              <Text style={{fontSize:9,color:C.light}}>{t.progress}/{t.target}</Text>
            </View>
          </View>
          <Text style={{fontSize:11,fontWeight:'700',color:C.primary}}>+{t.pts}pt</Text>
        </View>
      ))}
    </Card>
  );
}

/* ══ GÜNLÜK SORU ══════════════════════════════════ */
function DailyQuestionWidget({dq,onAnswer,user}){
  if(!dq)return null;
  const[sel,setSel]=useState(null);
  const handled=dq.answered;
  const lbs=['A','B','C','D'];
  const handlePick=async(ch)=>{
    if(handled||sel)return;setSel(ch);
    const correct=ch===dq.q.ans;
    await answerDailyQuestion(user.id,correct);
    if(onAnswer)onAnswer(correct);
  };
  return(
    <Card style={{marginBottom:14,borderColor:C.purple+'44',backgroundColor:'#faf5ff'}}>
      <View style={{flexDirection:'row',alignItems:'center',gap:8,marginBottom:10}}>
        <Text style={{fontSize:20}}>🌟</Text>
        <Text style={{fontSize:13,fontWeight:'800',color:C.purple}}>Günün Sorusu</Text>
        {handled&&<View style={{marginLeft:'auto',backgroundColor:dq.wasCorrect?'#dcfce7':'#fee2e2',borderRadius:8,paddingHorizontal:8,paddingVertical:3}}>
          <Text style={{fontSize:10,fontWeight:'700',color:dq.wasCorrect?C.primary:C.red}}>{dq.wasCorrect?'✓ Doğru!':'✗ Yanlış'}</Text>
        </View>}
      </View>
      <Text style={{fontSize:14,fontWeight:'700',color:C.text,marginBottom:10,lineHeight:20}}>{dq.q.q}</Text>
      <View style={{gap:6}}>
        {(dq.q.choices||[]).map((ch,ci)=>{
          let bg=C.bg,tc=C.text,brd=C.border;
          if(handled||sel){
            if(ch===dq.q.ans){bg='#dcfce7';tc=C.primary;brd=C.primary;}
            else if(ch===sel&&ch!==dq.q.ans){bg='#fee2e2';tc=C.red;brd=C.red;}
          }
          return(
            <TouchableOpacity key={ci} onPress={()=>handlePick(ch)} disabled={handled||!!sel}
              style={{flexDirection:'row',alignItems:'center',gap:8,padding:9,borderRadius:8,backgroundColor:bg,borderWidth:1.5,borderColor:brd}}>
              <Text style={{fontSize:11,fontWeight:'700',color:tc,width:18}}>{lbs[ci]}</Text>
              <Text style={{fontSize:13,color:tc,flex:1}}>{ch}</Text>
            </TouchableOpacity>
          );
        })}
      </View>
      {!handled&&<Text style={{fontSize:10,color:C.light,textAlign:'center',marginTop:8}}>24 saatte bir yenilenir</Text>}
    </Card>
  );
}

/* ══ ZAYIF KONU ══════════════════════════════════ */
function WeakTopicWidget({user}){
  const subjectMap=[
    {l:'Türkçe',   pts:user.turPts||0,  games:user.turGames||0,  e:'📖'},
    {l:'Matematik',pts:user.mathPts||0, games:user.mathGames||0, e:'🔢'},
    {l:'Fizik',    pts:user.physPts||0, games:user.physGames||0, e:'⚡'},
    {l:'Kimya',    pts:user.chemPts||0, games:user.chemGames||0, e:'⚗️'},
    {l:'Biyoloji', pts:user.bioPts||0,  games:user.bioGames||0,  e:'🧬'},
    {l:'Tarih',    pts:user.hisPts||0,  games:user.histGames||0, e:'📜'},
    {l:'Coğrafya', pts:user.geoPts||0,  games:user.geoGames||0,  e:'🗺️'},
    {l:'Felsefe',  pts:user.philPts||0, games:user.philGames||0, e:'🏛️'},
    {l:'Din Kül.', pts:user.relPts||0,  games:user.relGames||0,  e:'🕌'},
    {l:'Edebiyat', pts:user.edebiPts||0,games:user.edebiGames||0,e:'✍️'},
  ];
  const played=subjectMap.filter(s=>s.games>0);
  if(played.length===0)return null;
  const withAvg=played.map(s=>({...s,avg:s.pts/s.games}));
  const weakest=withAvg.sort((a,b)=>a.avg-b.avg)[0];
  if(weakest.avg>60)return null;
  return(
    <Card style={{marginBottom:14,backgroundColor:'#fef3c7',borderColor:C.amber+'66',flexDirection:'row',alignItems:'center',gap:12}}>
      <Text style={{fontSize:32}}>{weakest.e}</Text>
      <View style={{flex:1}}>
        <Text style={{fontSize:13,fontWeight:'800',color:C.orange}}>⚠️ Zayıf Konu Tespiti</Text>
        <Text style={{fontSize:12,color:C.text,marginTop:2}}>
          {weakest.l} oyunlarında ortalama {Math.round(weakest.avg)} puan alıyorsun.
        </Text>
        <Text style={{fontSize:11,color:C.mid,marginTop:2}}>Bugün bu konuya odaklanmanı öneririz! 💪</Text>
      </View>
    </Card>
  );
}

/* ══ HAFTALIK RAPOR ══════════════════════════════ */
