/* ══════════/* ══════════════════════════════════════════════════════════════════
   DAİRESEL KONU KARTI
══════════════════════════════════════════════════════════════════ */
function CTopicCard({topic,index,total,theta,onPress}){
  const RADIUS=WW*1.2;
  const CX=-RADIUS+WW*0.2;
  const CY=WH/2-80;
  const SZ=112;
  const base=(index/Math.max(total-1,1))*Math.PI*0.82;
  const aStyle=useAnimatedStyle(()=>{
    const ang=base+theta.value;
    const x=CX+RADIUS*Math.cos(ang);
    const y=CY+RADIUS*Math.sin(ang);
    const c=Math.cos(ang);
    const sc=c<0.65?0:c>1?1.2:0.4+(c-0.65)/0.35*0.8;
    const op=c<0.6?0:c>0.85?1:(c-0.6)/0.25;
    return{
      transform:[{translateX:x-SZ/2},{translateY:y-SZ/2},{scale:sc}],
      opacity:op,
      zIndex:Math.round((c+1)*50),
    };
  });
  return(
    <RAnimated.View style={[{position:'absolute',width:SZ,height:SZ},aStyle]}>
      <TouchableOpacity onPress={onPress} activeOpacity={0.82} style={{
        flex:1,backgroundColor:topic.bg||'#fff',borderRadius:22,
        justifyContent:'center',alignItems:'center',
        elevation:8,shadowColor:'#000',shadowOpacity:0.3,shadowRadius:10,
        padding:10,borderWidth:1.5,borderColor:'rgba(255,255,255,0.4)'
      }}>
        <Text style={{fontSize:30,marginBottom:5}}>{topic.emoji}</Text>
        <Text style={{textAlign:'center',fontWeight:'800',fontSize:9.5,color:'#1e293b',lineHeight:13}}
          numberOfLines={3}>{topic.name}</Text>
        <View style={{marginTop:5,backgroundColor:'rgba(0,0,0,0.08)',borderRadius:6,paddingHorizontal:6,paddingVertical:2}}>
          <Text style={{fontSize:8,color:'#475569',fontWeight:'700'}}>20 SORU</Text>
        </View>
      </TouchableOpacity>
    </RAnimated.View>
  );
}

/* ══════════════════════════════════════════════════════════════════
   DAİRESEL KONU MENÜSÜ EKRANI
══════════════════════════════════════════════════════════════════ */
function CircularTopicMenuScreen({subject,onBack,go}){
  const RADIUS=WW*1.2;
  const topics=subject?.topics||[];
  const theta=useSharedValue(0.08);
  const saved=useSharedValue(0.08);
  const pan=Gesture.Pan()
    .onUpdate(e=>{theta.value=saved.value+e.translationY/RADIUS;})
    .onEnd(()=>{
      saved.value=theta.value;
      if(topics.length>1){
        const step=Math.PI*0.82/(topics.length-1);
        const idx=Math.round(-theta.value/step);
        const ci=Math.max(0,Math.min(topics.length-1,idx));
        const target=-ci*step;
        theta.value=withSpring(target,{damping:16,stiffness:110,mass:0.8});
        saved.value=target;
      }
    });
  if(!subject)return null;
  return(
    <View style={{flex:1,backgroundColor:subject.color||'#1A4595'}}>
      {/* Üst panel */}
      <View style={{paddingTop:TOP_INSET+12,paddingHorizontal:16,paddingBottom:16,
        flexDirection:'row',alignItems:'center',gap:12,
        backgroundColor:'rgba(0,0,0,0.18)'}}>
        <TouchableOpacity onPress={onBack} style={{width:40,height:40,borderRadius:20,
          backgroundColor:'rgba(255,255,255,0.15)',alignItems:'center',justifyContent:'center'}}>
          <Text style={{color:'#fff',fontSize:20,fontWeight:'700'}}>←</Text>
        </TouchableOpacity>
        <View style={{flex:1}}>
          <Text style={{color:'#fff',fontSize:18,fontWeight:'900'}}>{subject.emoji} {subject.name}</Text>
          <Text style={{color:'rgba(255,255,255,0.6)',fontSize:11.5,marginTop:2}}>
            {topics.length} konu • Konuya tıkla → 20 soruluk test
          </Text>
        </View>
      </View>
      {/* Dairesel öğeler */}
      <GestureDetector gesture={pan}>
        <RAnimated.View style={[StyleSheet.absoluteFill,{top:80}]}>
          {topics.map((t,i)=>(
            <CTopicCard
              key={t.id} topic={t} index={i} total={topics.length}
              theta={theta}
              onPress={()=>go('topicQuiz',{topic:t,color:subject?.color||'#4338ca'})}
            />
          ))}
        </RAnimated.View>
      </GestureDetector>
      {/* Seçim halkası (sağ taraf) */}
      <View style={{
        position:'absolute',right:12,top:WH/2-40,
        width:62,height:62,borderRadius:31,
        backgroundColor:'rgba(255,255,255,0.08)',
        borderWidth:2.5,borderColor:'rgba(255,255,255,0.45)',
        alignItems:'center',justifyContent:'center',
        pointerEvents:'none'
      }}>
        <Text style={{color:'rgba(255,255,255,0.6)',fontSize:9,fontWeight:'900',textAlign:'center'}}>◄{'\n'}SEÇ</Text>
      </View>
      {/* Alt ipucu */}
      <View style={{position:'absolute',bottom:BOTTOM+28,left:0,right:0,alignItems:'center'}}>
        <View style={{backgroundColor:'rgba(0,0,0,0.25)',borderRadius:20,paddingHorizontal:16,paddingVertical:7}}>
          <Text style={{color:'rgba(255,255,255,0.55)',fontSize:12}}>↕ Yukarı / Aşağı kaydır</Text>
        </View>
      </View>
    </View>
  );
}

/* ══════════════════════════════════════════════════════════════════
   AI TARAFINDAN OLUŞTURULAN 20 SORULUK TEST
══════════════════════════════════════════════════════════════════ */
function TopicTest20Screen({topic,subject,onBack,user,setUser}){
  const[phase,setPhase]=useState('load');
  const[qs,setQs]=useState([]);
  const[qi,setQi]=useState(0);
  const[ans,setAns]=useState([]);
  const[sel,setSel]=useState(null);
  const[fb,setFb]=useState(false);

  useEffect(()=>{load();},[]);

  const load=async()=>{
    setPhase('load');setQi(0);setAns([]);setSel(null);setFb(false);setQs([]);
    try{
      // Statik soru bankasından al
      const bank=STATIC_QDB[topic?.id]||[];
      if(bank.length>0){
        // Karıştır ve 20 tane al
        const shuffled=[...bank].sort(()=>Math.random()-0.5);
        const selected=shuffled.slice(0,Math.min(20,shuffled.length));
        // Her sorunun şıklarını da karıştır
        const ready=selected.map(q=>{
          const choices=[...q.c].sort(()=>Math.random()-0.5);
          return{...q,c:choices};
        });
        setQs(ready);
        setPhase('quiz');
        return;
      }
      // Statik banka yoksa placeholder
      Alert.alert('Bilgi','Bu konu için sorular hazırlanıyor. Yakında eklenecek!',
        [{text:'Tamam',onPress:onBack}]);
    }catch(e){
      console.log('Load error:',e.message);
      Alert.alert('Hata','Sorular yüklenemedi: '+e.message,
        [{text:'Tamam',onPress:onBack}]);
    }
  };

  const pick=(ch)=>{
    if(sel!==null||phase!=='quiz')return;
    setSel(ch);setFb(true);
    const ok=ch===(qs[qi].a);
    setTimeout(()=>{
      const na=[...ans,{ok,ch,a:qs[qi].a}];
      setAns(na);setSel(null);setFb(false);
      if(qi+1>=qs.length){
        const sc=na.filter(x=>x.ok).length;
        if(sc>=16&&user){
          db.update({...user,points:(user.points||0)+75}).then(u=>{if(u)setUser(u);});
        }
        setPhase('result');
      } else {setQi(qi+1);}
    },1300);
  };

  // ── Yükleniyor ──
  if(phase==='load')return(
    <View style={{flex:1,backgroundColor:subject?.color||'#1d4ed8',alignItems:'center',justifyContent:'center',padding:24}}>
      <Text style={{fontSize:68,marginBottom:18}}>{topic?.emoji||'📚'}</Text>
      <Text style={{color:'#fff',fontSize:22,fontWeight:'900',textAlign:'center',marginBottom:8}}>{topic?.name}</Text>
      <Text style={{color:'rgba(255,255,255,0.65)',fontSize:13,marginBottom:36,textAlign:'center',lineHeight:20}}>
        20 soru yapay zeka tarafından{'\n'}hazırlanıyor, lütfen bekle...
      </Text>
      <ActivityIndicator color="#fff" size="large"/>
    </View>
  );

  // ── Sonuç ──
  if(phase==='result'){
    const sc=ans.filter(x=>x.ok).length;
    const pct=Math.round(sc/20*100);
    const emoji=pct>=85?'🏆':pct>=60?'👍':pct>=40?'😐':'😔';
    const msg=pct>=85?'Mükemmel!':pct>=60?'İyi iş!':pct>=40?'Geliştirebilirsin':'Tekrar çalış';
    return(
      <View style={{flex:1,backgroundColor:subject?.color||'#1d4ed8'}}>
        <SafeAreaView style={{flex:1,alignItems:'center',justifyContent:'center',padding:24}}>
          <Text style={{fontSize:76,marginBottom:14}}>{emoji}</Text>
          <Text style={{color:'#fff',fontSize:34,fontWeight:'900',marginBottom:4}}>{sc} / 20</Text>
          <Text style={{color:'rgba(255,255,255,0.9)',fontSize:18,fontWeight:'700',marginBottom:4}}>{msg}</Text>
          <Text style={{color:'rgba(255,255,255,0.6)',fontSize:13,marginBottom:8}}>{topic?.name}</Text>
          <Text style={{color:'rgba(255,255,255,0.5)',fontSize:12,marginBottom:24}}>Başarı: %{pct}</Text>
          {pct>=85&&(
            <View style={{backgroundColor:'rgba(255,255,255,0.15)',borderRadius:14,padding:12,marginBottom:20,width:'100%',alignItems:'center'}}>
              <Text style={{color:'#fff',fontWeight:'800',fontSize:14}}>🏆 +75 puan kazandın!</Text>
            </View>
          )}
          {/* Yanlışlar özeti */}
          <View style={{flexDirection:'row',gap:10,marginBottom:24,width:'100%'}}>
            <View style={{flex:1,backgroundColor:'rgba(34,197,94,0.2)',borderRadius:12,padding:12,alignItems:'center',borderWidth:1,borderColor:'#22c55e44'}}>
              <Text style={{color:'#86efac',fontSize:22,fontWeight:'900'}}>{sc}</Text>
              <Text style={{color:'rgba(255,255,255,0.6)',fontSize:10,fontWeight:'700'}}>DOĞRU</Text>
            </View>
            <View style={{flex:1,backgroundColor:'rgba(239,68,68,0.2)',borderRadius:12,padding:12,alignItems:'center',borderWidth:1,borderColor:'#ef444444'}}>
              <Text style={{color:'#fca5a5',fontSize:22,fontWeight:'900'}}>{20-sc}</Text>
              <Text style={{color:'rgba(255,255,255,0.6)',fontSize:10,fontWeight:'700'}}>YANLIŞ</Text>
            </View>
          </View>
          <View style={{flexDirection:'row',gap:10,width:'100%'}}>
            <TouchableOpacity onPress={load} style={{flex:1,backgroundColor:'rgba(255,255,255,0.2)',borderRadius:14,padding:15,alignItems:'center'}}>
              <Text style={{color:'#fff',fontWeight:'800',fontSize:14}}>🔄 Tekrar Çöz</Text>
            </TouchableOpacity>
            <TouchableOpacity onPress={onBack} style={{flex:1,backgroundColor:'rgba(255,255,255,0.92)',borderRadius:14,padding:15,alignItems:'center'}}>
              <Text style={{color:subject?.color||'#1d4ed8',fontWeight:'900',fontSize:14}}>← Konulara Dön</Text>
            </TouchableOpacity>
          </View>
        </SafeAreaView>
      </View>
    );
  }

  // ── Test ──
  const q=qs[qi]||{};
  const prog=qi/20;
  return(
    <View style={{flex:1,backgroundColor:'#0f172a'}}>
      <SafeAreaView style={{flex:1}}>
        {/* Header */}
        <View style={{paddingHorizontal:16,paddingTop:TOP_INSET,paddingBottom:12,
          backgroundColor:'#0f172a',borderBottomWidth:1,borderBottomColor:'rgba(255,255,255,0.06)'}}>
          <View style={{flexDirection:'row',alignItems:'center',justifyContent:'space-between',marginBottom:10}}>
            <TouchableOpacity onPress={onBack} style={{padding:4}}>
              <Text style={{color:'rgba(255,255,255,0.4)',fontSize:22}}>✕</Text>
            </TouchableOpacity>
            <View style={{alignItems:'center',flex:1,paddingHorizontal:10}}>
              <Text style={{color:'#fff',fontWeight:'900',fontSize:12}} numberOfLines={1}>{topic?.emoji} {topic?.name}</Text>
              <Text style={{color:'rgba(255,255,255,0.4)',fontSize:10}}>{subject?.name}</Text>
            </View>
            <View style={{backgroundColor:(subject?.color||'#6366f1')+'28',borderRadius:10,
              paddingHorizontal:11,paddingVertical:6}}>
              <Text style={{color:subject?.color||'#818cf8',fontWeight:'900',fontSize:12}}>{qi+1}/20</Text>
            </View>
          </View>
          {/* Progress bar */}
          <View style={{height:5,backgroundColor:'rgba(255,255,255,0.08)',borderRadius:3,overflow:'hidden'}}>
            <View style={{height:5,width:(prog*100)+'%',borderRadius:3,
              backgroundColor:subject?.color||'#6366f1'}}/>
          </View>
        </View>
        <ScrollView contentContainerStyle={{padding:16,paddingBottom:44}}>
          {/* Soru kutusu */}
          <View style={{backgroundColor:'rgba(255,255,255,0.05)',borderRadius:20,padding:22,
            marginBottom:18,borderWidth:1,borderColor:'rgba(255,255,255,0.08)',minHeight:130,
            justifyContent:'center'}}>
            <Text style={{color:'rgba(255,255,255,0.35)',fontSize:10,fontWeight:'800',
              letterSpacing:2,marginBottom:10}}>SORU {qi+1}</Text>
            <Text style={{color:'#f1f5f9',fontSize:16,fontWeight:'700',lineHeight:26}}>{q.s||q.q||''}</Text>
          </View>
          {/* Şıklar */}
          {(q.c||q.choices||[]).map((ch,ci)=>{
            let bg='rgba(255,255,255,0.05)';
            let bc='rgba(255,255,255,0.09)';
            let tc='#e2e8f0';
            let badge=null;
            if(fb){
              if(ch===q.a){bg='rgba(34,197,94,0.18)';bc='#22c55e';tc='#86efac';badge='✓';}
              else if(ch===sel){bg='rgba(239,68,68,0.18)';bc='#ef4444';tc='#fca5a5';badge='✗';}
            }
            return(
              <TouchableOpacity key={ci} onPress={()=>pick(ch)}
                disabled={sel!==null} activeOpacity={0.72}>
                <View style={{backgroundColor:bg,borderRadius:14,padding:15,marginBottom:10,
                  flexDirection:'row',alignItems:'center',gap:12,borderWidth:1.5,borderColor:bc}}>
                  <View style={{width:34,height:34,borderRadius:17,
                    backgroundColor:'rgba(255,255,255,0.07)',
                    alignItems:'center',justifyContent:'center',flexShrink:0}}>
                    <Text style={{color:'rgba(255,255,255,0.5)',fontWeight:'800',fontSize:12}}>{'ABCD'[ci]}</Text>
                  </View>
                  <Text style={{flex:1,color:tc,fontSize:14,fontWeight:'600',lineHeight:20}}>{ch}</Text>
                  {badge&&<Text style={{fontSize:18}}>{badge}</Text>}
                </View>
              </TouchableOpacity>
            );
          })}
        </ScrollView>
      </SafeAreaView>
    </View>
  );
}

/* ══════════════════════════════════════════════════════════════════
   SINIF + DERS SEÇİCİ EKRANI
══════════════════════════════════════════════════════════════════ */
function GradeSubjectScreen({onBack,go}){
  const[grade,setGrade]=useState('9');
  const subs=FULL_CURRICULUM[grade]||[];
  return(
    <SafeAreaView style={{flex:1,backgroundColor:C.bg,paddingTop:TOP_INSET}}>
      <Hdr title="📚 Konu Testleri" subtitle="Sınıf ve ders seç → Konuya tıkla → 20 soruluk test" onBack={onBack}/>
      {/* Sınıf seçimi */}
      <View style={{flexDirection:'row',padding:12,gap:8}}>
        {['9','10','11','12'].map(g=>(
          <TouchableOpacity key={g} onPress={()=>setGrade(g)} style={{
            flex:1,paddingVertical:14,borderRadius:14,alignItems:'center',
            backgroundColor:grade===g?C.primary:'transparent',
            borderWidth:2,borderColor:grade===g?C.primary:C.border
          }}>
            <Text style={{color:grade===g?'#fff':C.mid,fontWeight:'900',fontSize:14}}>{g}.</Text>
            <Text style={{color:grade===g?'rgba(255,255,255,0.75)':C.sub,fontWeight:'600',fontSize:10}}>Sınıf</Text>
          </TouchableOpacity>
        ))}
      </View>
      {/* Dersler listesi */}
      <ScrollView contentContainerStyle={{padding:12,gap:12}}>
        {subs.map(sub=>(
          <TouchableOpacity key={sub.id} onPress={()=>go('circularTopics',{subject:sub})} activeOpacity={0.88}>
            <View style={{backgroundColor:sub.color,borderRadius:20,padding:18,
              flexDirection:'row',alignItems:'center',gap:14,
              shadowColor:sub.color,shadowOpacity:0.4,shadowRadius:14,elevation:7}}>
              <View style={{width:54,height:54,borderRadius:27,
                backgroundColor:'rgba(255,255,255,0.2)',
                alignItems:'center',justifyContent:'center'}}>
                <Text style={{fontSize:28}}>{sub.emoji}</Text>
              </View>
              <View style={{flex:1}}>
                <Text style={{color:'#fff',fontSize:15,fontWeight:'900',marginBottom:3}}>{sub.name}</Text>
                <Text style={{color:'rgba(255,255,255,0.65)',fontSize:12}}>
                  {sub.topics.length} konu · Her konu 20 soru (yapay zeka)
                </Text>
              </View>
              <View style={{backgroundColor:'rgba(255,255,255,0.18)',borderRadius:10,
                paddingHorizontal:10,paddingVertical:7}}>
                <Text style={{color:'#fff',fontWeight:'800',fontSize:11}}>Keşfet ›</Text>
              </View>
            </View>
          </TouchableOpacity>
        ))}
      </ScrollView>
    </SafeAreaView>
  );
}

