/* ══ BİLDİRİM SİSTEMİ ══════════════════════════════ */

// Bildirimler — EAS build gerektirir, Expo Go'da devre dışı



/* ══ DÜELLO SİSTEMİ ══════════════════════════════════ */
// Düello soruları — karışık tüm bankalardan
function getDuelQuestions(n=10){
  const all=[...MATH_Q,...PHYS_Q,...CHEM_Q,...TUR_Q,...HIST_Q,...GEO_Q,...PHIL_Q,...BIO_Q];
  return shuffle(all).slice(0,n).map(q=>({...q,choices:shuffle(q.choices)}));
}

function DuelScreen({onBack,user,setUser,incomingInvite,onClearInvite}){
  const[tab,setTab]=useState('lobby');
  const[users,setUsers]=useState([]);
  const[loading,setLoading]=useState(true);
  const[activeDuel,setActiveDuel]=useState(null);
  const[timer,setTimer]=useState(60);
  const[search,setSearch]=useState('');
  const timerRef=useRef(null);
  const pollRef=useRef(null);

  useEffect(()=>{
    db.all().then(all=>{setUsers(all.filter(u=>u.id!==user.id));setLoading(false);});
  },[]);

  // Gelen davet prop'tan al (FullApp'ten geliyor)
  useEffect(()=>{
    if(incomingInvite&&!activeDuel){
      setActiveDuel({...incomingInvite,isChallenger:false});
      onClearInvite&&onClearInvite();
    }
  },[incomingInvite]);

  // Aktif duel durumunu dinle
  useEffect(()=>{
    const poll=setInterval(async()=>{
      const d=await db._r();
      const duels=d.duels||[];
      // Kabul edilmiş benim davetim — başla
      if(activeDuel&&activeDuel.isChallenger&&activeDuel.status==='pending'){
        const fresh=duels.find(duel=>duel.id===activeDuel.id);
        if(fresh&&fresh.status==='accepted'){
          setActiveDuel(prev=>({...prev,status:'active',startTs:fresh.startTs,questions:fresh.questions}));
          startTimer();
        }
        if(fresh&&fresh.status==='declined'){
          setActiveDuel(null);
          Alert.alert('❌ Reddedildi',activeDuel.opponent.name+' daveti reddetti.');
        }
      }
      // Aktif maç — rakip cevaplarını kontrol et
      if(activeDuel&&activeDuel.status==='active'){
        const fresh=duels.find(duel=>duel.id===activeDuel.id);
        if(fresh){
          const oppKey=activeDuel.isChallenger?'toAnswers':'fromAnswers';
          if(fresh[oppKey]&&fresh[oppKey].length>0){
            setActiveDuel(prev=>({...prev,oppAnswers:fresh[oppKey],oppDone:fresh[oppKey].length>=fresh.questions.length}));
          }
          if(fresh.status==='finished'){
            setActiveDuel(prev=>({...prev,...fresh,status:'finished'}));
            clearInterval(timerRef.current);
          }
        }
      }
    },2500);
    pollRef.current=poll;
    return()=>clearInterval(poll);
  },[activeDuel,tab,user.id]);

  const startTimer=()=>{
    setTimer(60);
    clearInterval(timerRef.current);
    timerRef.current=setInterval(()=>{
      setTimer(t=>{
        if(t<=1){clearInterval(timerRef.current);finishDuel();return 0;}
        return t-1;
      });
    },1000);
  };

  // Rakibe düello daveti gönder
  const challengeUser=async(opponent)=>{
    const duelId='d_'+genId();
    const questions=getDuelQuestions(10);
    const d=await db._r();
    if(!d.duels)d.duels=[];
    const duelObj={id:duelId,fromId:user.id,toId:opponent.id,
      status:'pending',ts:Date.now(),questions,
      fromAnswers:[],toAnswers:[]};
    d.duels.push(duelObj);
    // Eski duellları temizle (24 saatten eski)
    d.duels=d.duels.filter(duel=>Date.now()-duel.ts<86400000);
    await db._w(d);
    setActiveDuel({...duelObj,opponent,isChallenger:true,myAnswers:[],oppAnswers:[],status:'pending'});
    // Push bildirimi gönder
    if(opponent.pushToken){
      await sendPushNotification(opponent.pushToken,
        '⚔️ Düello Daveti!',
        user.name+' seni düelloya davet etti! Kabul ediyor musun?',
        {type:'duelInvite',duelId,fromName:user.name}
      );
    }
  };

  // Daveti kabul et
  const acceptDuel=async()=>{
    if(!activeDuel)return;
    const d=await db._r();
    const duelIdx=d.duels.findIndex(duel=>duel.id===activeDuel.id);
    if(duelIdx<0)return;
    const startTs=Date.now();
    d.duels[duelIdx].status='accepted';
    d.duels[duelIdx].startTs=startTs;
    await db._w(d);
    setActiveDuel(prev=>({...prev,status:'active',startTs,questions:d.duels[duelIdx].questions}));
    startTimer();
    // Karşı tarafa bildirim
    const challenger=d.users.find(u=>u.id===activeDuel.fromId);
    if(challenger?.pushToken){
      await sendPushNotification(challenger.pushToken,'✅ Düello Kabul!',activeDuel.opponent.name+' daveti kabul etti! Maç başlıyor!',{type:'duelAccepted'});
    }
  };

  // Daveti reddet
  const declineDuel=async()=>{
    if(!activeDuel)return;
    const d=await db._r();
    const duelIdx=d.duels.findIndex(duel=>duel.id===activeDuel.id);
    if(duelIdx>=0){d.duels[duelIdx].status='declined';await db._w(d);}
    setActiveDuel(null);
  };

  // Cevap ver
  const answerQuestion=async(choice)=>{
    if(!activeDuel||activeDuel.status!=='active')return;
    const qIdx=activeDuel.myAnswers.length;
    if(qIdx>=activeDuel.questions.length)return;
    const correct=choice===activeDuel.questions[qIdx].ans;
    const newAnswers=[...activeDuel.myAnswers,{choice,correct}];
    setActiveDuel(prev=>({...prev,myAnswers:newAnswers}));
    // JSONBin'e yaz
    const d=await db._r();
    const duelIdx=d.duels.findIndex(duel=>duel.id===activeDuel.id);
    if(duelIdx>=0){
      const ansKey=activeDuel.isChallenger?'fromAnswers':'toAnswers';
      d.duels[duelIdx][ansKey]=newAnswers;
      if(newAnswers.length>=activeDuel.questions.length){
        await finishDuelDB(d,duelIdx,newAnswers);
      } else {
        await db._w(d);
      }
    }
  };

  const finishDuelDB=async(d,duelIdx,myAnswers)=>{
    const duel=d.duels[duelIdx];
    const myKey=activeDuel.isChallenger?'fromAnswers':'toAnswers';
    const oppKey=activeDuel.isChallenger?'toAnswers':'fromAnswers';
    const oppAns=duel[oppKey]||[];
    const myScore=myAnswers.filter(a=>a.correct).length;
    const oppScore=oppAns.filter(a=>a.correct).length;
    const bothDone=myAnswers.length>=duel.questions.length&&oppAns.length>=duel.questions.length;
    if(bothDone||timer<=0){
      d.duels[duelIdx].status='finished';
      d.duels[duelIdx].fromScore=activeDuel.isChallenger?myScore:oppScore;
      d.duels[duelIdx].toScore=activeDuel.isChallenger?oppScore:myScore;
    }
    await db._w(d);
    clearInterval(timerRef.current);
  };

  const finishDuel=async()=>{
    const d=await db._r();
    const duelIdx=d.duels?.findIndex(duel=>duel.id===activeDuel?.id)??-1;
    if(duelIdx>=0)await finishDuelDB(d,duelIdx,activeDuel.myAnswers||[]);
    setActiveDuel(prev=>prev?{...prev,status:'finished'}:null);
  };

  // ── Davet ekranı (gelen davet) ──
  if(activeDuel&&activeDuel.status==='pending'&&!activeDuel.isChallenger){
    return(
      <View style={{flex:1,backgroundColor:'#0f0c29',alignItems:'center',justifyContent:'center',padding:24}}>
        <Text style={{fontSize:60,marginBottom:16}}>⚔️</Text>
        <Text style={{color:'#fff',fontSize:22,fontWeight:'900',textAlign:'center',marginBottom:8}}>Düello Daveti!</Text>
        <View style={{backgroundColor:'rgba(255,255,255,0.1)',borderRadius:16,padding:16,marginBottom:24,alignItems:'center'}}>
          <Avatar user={activeDuel.opponent} size={64}/>
          <Text style={{color:'#fff',fontSize:18,fontWeight:'800',marginTop:10}}>{activeDuel.opponent.name}</Text>
          <RankBadge pts={activeDuel.opponent.points||0}/>
          <Text style={{color:'rgba(255,255,255,0.7)',fontSize:14,marginTop:8}}>Seni düelloya davet etti!</Text>
          <Text style={{color:'rgba(255,255,255,0.5)',fontSize:12,marginTop:4}}>10 soru · 60 saniye</Text>
        </View>
        <TouchableOpacity onPress={acceptDuel} style={{backgroundColor:'#22c55e',borderRadius:14,paddingHorizontal:40,paddingVertical:14,width:'100%',alignItems:'center',marginBottom:12}}>
          <Text style={{color:'#fff',fontWeight:'900',fontSize:16}}>✅ Kabul Et</Text>
        </TouchableOpacity>
        <TouchableOpacity onPress={declineDuel} style={{backgroundColor:'rgba(255,255,255,0.1)',borderRadius:14,paddingHorizontal:40,paddingVertical:14,width:'100%',alignItems:'center'}}>
          <Text style={{color:'rgba(255,255,255,0.7)',fontWeight:'700',fontSize:15}}>❌ Reddet</Text>
        </TouchableOpacity>
      </View>
    );
  }

  // ── Bekleme ekranı (davet gönderildi, onay bekleniyor) ──
  if(activeDuel&&activeDuel.status==='pending'&&activeDuel.isChallenger){
    return(
      <View style={{flex:1,backgroundColor:'#0f0c29',alignItems:'center',justifyContent:'center',padding:24}}>
        <Text style={{fontSize:60,marginBottom:16}}>⏳</Text>
        <Text style={{color:'#fff',fontSize:20,fontWeight:'900',textAlign:'center',marginBottom:8}}>Onay Bekleniyor</Text>
        <View style={{backgroundColor:'rgba(255,255,255,0.1)',borderRadius:16,padding:16,marginBottom:24,alignItems:'center'}}>
          <Avatar user={activeDuel.opponent} size={56}/>
          <Text style={{color:'#fff',fontSize:16,fontWeight:'800',marginTop:10}}>{activeDuel.opponent.name}</Text>
          <Text style={{color:'rgba(255,255,255,0.6)',fontSize:13,marginTop:6}}>Daveti kabul etmesini bekliyorsun...</Text>
        </View>
        <ActivityIndicator color="#22c55e" size="large" style={{marginBottom:20}}/>
        <TouchableOpacity onPress={()=>{declineDuel();setActiveDuel(null);}} style={{backgroundColor:'rgba(255,255,255,0.1)',borderRadius:12,paddingHorizontal:24,paddingVertical:10}}>
          <Text style={{color:'rgba(255,255,255,0.7)',fontWeight:'600'}}>İptal Et</Text>
        </TouchableOpacity>
      </View>
    );
  }

  // ── Aktif maç ──
  if(activeDuel&&activeDuel.status==='active'){
    const myAnswers=activeDuel.myAnswers||[];
    const qIdx=myAnswers.length;
    const questions=activeDuel.questions||[];
    const allDone=qIdx>=questions.length;
    const myScore=myAnswers.filter(a=>a.correct).length;
    const oppScore=(activeDuel.oppAnswers||[]).filter(a=>a.correct).length;
    const q=questions[qIdx];
    return(
      <View style={{flex:1,backgroundColor:'#0f0c29'}}>
        {/* Skor başlık */}
        <View style={{backgroundColor:'#1a1740',paddingTop:TOP_INSET+10,paddingBottom:14,paddingHorizontal:16}}>
          <View style={{flexDirection:'row',alignItems:'center',justifyContent:'space-between',marginBottom:10}}>
            <View style={{alignItems:'center'}}>
              <Avatar user={user} size={40}/>
              <Text style={{color:'#22c55e',fontSize:20,fontWeight:'900',marginTop:4}}>{myScore}</Text>
              <Text style={{color:'rgba(255,255,255,0.6)',fontSize:10}}>Sen</Text>
            </View>
            <View style={{alignItems:'center'}}>
              <View style={{backgroundColor:timer<=10?'#dc2626':'rgba(255,255,255,0.1)',borderRadius:20,paddingHorizontal:14,paddingVertical:6}}>
                <Text style={{color:timer<=10?'#fff':'rgba(255,255,255,0.9)',fontSize:20,fontWeight:'900'}}>⏱ {timer}s</Text>
              </View>
              <Text style={{color:'rgba(255,255,255,0.5)',fontSize:10,marginTop:4}}>{qIdx}/{questions.length} soru</Text>
            </View>
            <View style={{alignItems:'center'}}>
              <Avatar user={activeDuel.opponent} size={40}/>
              <Text style={{color:'#f97316',fontSize:20,fontWeight:'900',marginTop:4}}>{oppScore}</Text>
              <Text style={{color:'rgba(255,255,255,0.6)',fontSize:10}}>{activeDuel.opponent.name.split(' ')[0]}</Text>
            </View>
          </View>
          {/* Progress bar */}
          <View style={{height:4,backgroundColor:'rgba(255,255,255,0.1)',borderRadius:2}}>
            <View style={{height:4,backgroundColor:'#22c55e',borderRadius:2,width:(qIdx/Math.max(1,questions.length)*100)+'%'}}/>
          </View>
        </View>
        {allDone?(
          <View style={{flex:1,alignItems:'center',justifyContent:'center',padding:24}}>
            <Text style={{color:'#fff',fontSize:22,fontWeight:'900',marginBottom:8}}>Tüm sorular bitti!</Text>
            <Text style={{color:'rgba(255,255,255,0.6)',fontSize:15}}>Rakibin bitmesini bekliyorsun...</Text>
            <ActivityIndicator color="#22c55e" style={{marginTop:20}}/>
          </View>
        ):(
          <ScrollView contentContainerStyle={{padding:16}}>
            <View style={{backgroundColor:'rgba(255,255,255,0.08)',borderRadius:16,padding:18,marginBottom:16}}>
              <Text style={{color:'rgba(255,255,255,0.5)',fontSize:11,fontWeight:'800',marginBottom:8}}>SORU {qIdx+1}/{questions.length}</Text>
              <Text style={{color:'#fff',fontSize:17,fontWeight:'700',lineHeight:26}}>{q?.q}</Text>
            </View>
            {(q?.choices||[]).map((ch,ci)=>(
              <TouchableOpacity key={ci} onPress={()=>answerQuestion(ch)} activeOpacity={0.8}>
                <View style={{backgroundColor:'rgba(255,255,255,0.08)',borderRadius:14,padding:16,marginBottom:10,
                  flexDirection:'row',alignItems:'center',gap:12,borderWidth:1,borderColor:'rgba(255,255,255,0.12)'}}>
                  <View style={{width:32,height:32,borderRadius:16,backgroundColor:'rgba(255,255,255,0.15)',alignItems:'center',justifyContent:'center'}}>
                    <Text style={{color:'#fff',fontWeight:'800'}}>{'ABCD'[ci]}</Text>
                  </View>
                  <Text style={{flex:1,color:'#fff',fontSize:15,fontWeight:'600'}}>{ch}</Text>
                </View>
              </TouchableOpacity>
            ))}
          </ScrollView>
        )}
      </View>
    );
  }

  // ── Sonuç ekranı ──
  if(activeDuel&&activeDuel.status==='finished'){
    const isChallenger=activeDuel.isChallenger;
    const myScore=(activeDuel.myAnswers||[]).filter(a=>a.correct).length;
    const oppScore=(activeDuel.oppAnswers||[]).filter(a=>a.correct).length;
    const won=myScore>oppScore;
    const draw=myScore===oppScore;
    return(
      <View style={{flex:1,backgroundColor:'#0f0c29',alignItems:'center',justifyContent:'center',padding:24}}>
        <Text style={{fontSize:70,marginBottom:12}}>{draw?'🤝':won?'🏆':'😔'}</Text>
        <Text style={{color:'#fff',fontSize:26,fontWeight:'900',marginBottom:4}}>
          {draw?'Berabere!':won?'Kazandın!':'Kaybettin!'}
        </Text>
        <Text style={{color:'rgba(255,255,255,0.6)',fontSize:14,marginBottom:24}}>
          {activeDuel.opponent.name} ile düello
        </Text>
        <View style={{flexDirection:'row',gap:16,marginBottom:32}}>
          <View style={{alignItems:'center',backgroundColor:'rgba(34,197,94,0.15)',borderRadius:16,padding:16,minWidth:90,borderWidth:1,borderColor:'#22c55e44'}}>
            <Text style={{fontSize:30,fontWeight:'900',color:'#22c55e'}}>{myScore}</Text>
            <Text style={{fontSize:11,color:'rgba(255,255,255,0.5)',fontWeight:'600'}}>SEN</Text>
          </View>
          <View style={{alignItems:'center',backgroundColor:'rgba(249,115,22,0.15)',borderRadius:16,padding:16,minWidth:90,borderWidth:1,borderColor:'#f9731644'}}>
            <Text style={{fontSize:30,fontWeight:'900',color:'#f97316'}}>{oppScore}</Text>
            <Text style={{fontSize:11,color:'rgba(255,255,255,0.5)',fontWeight:'600'}}>{activeDuel.opponent.name.split(' ')[0].toUpperCase()}</Text>
          </View>
        </View>
        <TouchableOpacity onPress={()=>setActiveDuel(null)} style={{backgroundColor:'#6d28d9',borderRadius:14,paddingHorizontal:32,paddingVertical:14,marginBottom:12,width:'100%',alignItems:'center'}}>
          <Text style={{color:'#fff',fontWeight:'800',fontSize:16}}>Tekrar Oyna</Text>
        </TouchableOpacity>
        <TouchableOpacity onPress={onBack}>
          <Text style={{color:'rgba(255,255,255,0.5)',fontWeight:'600'}}>Ana Ekrana Dön</Text>
        </TouchableOpacity>
      </View>
    );
  }

  // ── Lobi ekranı ──
  const filteredUsers=users.filter(u=>!search||u.name.toLowerCase().includes(search.toLowerCase())||u.email.toLowerCase().includes(search.toLowerCase()));
  return(
    <View style={{flex:1,backgroundColor:'#0f0c29'}}>
      <View style={{backgroundColor:'#1a1740',paddingTop:TOP_INSET+12,paddingBottom:14,paddingHorizontal:16}}>
        <View style={{flexDirection:'row',alignItems:'center',gap:12,marginBottom:12}}>
          <TouchableOpacity onPress={onBack} style={{width:36,height:36,borderRadius:18,backgroundColor:'rgba(255,255,255,0.1)',alignItems:'center',justifyContent:'center'}}>
            <Text style={{color:'#fff',fontSize:18,fontWeight:'700'}}>←</Text>
          </TouchableOpacity>
          <View style={{flex:1}}>
            <Text style={{color:'#fff',fontSize:20,fontWeight:'900'}}>⚔️ Düello</Text>
            <Text style={{color:'rgba(255,255,255,0.5)',fontSize:12,marginTop:2}}>Rakip seç · 10 soru · 60 saniye</Text>
          </View>
          <View style={{backgroundColor:'rgba(109,40,217,0.3)',borderRadius:10,paddingHorizontal:10,paddingVertical:5,borderWidth:1,borderColor:'rgba(109,40,217,0.5)'}}>
            <Text style={{color:'#c4b5fd',fontSize:11,fontWeight:'700'}}>{users.length} oyuncu</Text>
          </View>
        </View>
        {/* Arama çubuğu */}
        <View style={{flexDirection:'row',alignItems:'center',backgroundColor:'rgba(255,255,255,0.08)',borderRadius:12,paddingHorizontal:12,gap:8,borderWidth:1,borderColor:'rgba(255,255,255,0.12)'}}>
          <Text style={{fontSize:14}}>🔍</Text>
          <TextInput
            value={search} onChangeText={setSearch}
            placeholder="Oyuncu ara..." placeholderTextColor="rgba(255,255,255,0.3)"
            style={{flex:1,color:'#fff',fontSize:14,paddingVertical:10}}
          />
          {search.length>0&&<TouchableOpacity onPress={()=>setSearch('')}><Text style={{color:'rgba(255,255,255,0.4)',fontSize:16}}>✕</Text></TouchableOpacity>}
        </View>
      </View>
      {loading?<ActivityIndicator color="#6d28d9" style={{marginTop:40}}/>:
       filteredUsers.length===0?
       <View style={{flex:1,alignItems:'center',justifyContent:'center'}}>
         <Text style={{fontSize:48}}>{search?'🔍':'😴'}</Text>
         <Text style={{color:'rgba(255,255,255,0.5)',fontSize:15,marginTop:12}}>{search?`"${search}" bulunamadı`:'Henüz kayıtlı oyuncu yok'}</Text>
       </View>:
       <FlatList data={filteredUsers.sort((a,b)=>(b.points||0)-(a.points||0))} keyExtractor={u=>u.id}
         contentContainerStyle={{padding:16,gap:10}}
         renderItem={({item})=>(
           <TouchableOpacity onPress={()=>challengeUser(item)} activeOpacity={0.85}>
             <View style={{backgroundColor:'rgba(255,255,255,0.06)',borderRadius:16,padding:14,
               flexDirection:'row',alignItems:'center',gap:12,borderWidth:1,borderColor:'rgba(255,255,255,0.08)'}}>
               <Avatar user={item} size={48}/>
               <View style={{flex:1}}>
                 <Text style={{color:'#fff',fontSize:15,fontWeight:'800'}}>{item.name}</Text>
                 <RankBadge pts={item.points||0}/>
               </View>
               <View style={{backgroundColor:'#6d28d9',borderRadius:10,paddingHorizontal:14,paddingVertical:8}}>
                 <Text style={{color:'#fff',fontWeight:'800',fontSize:13}}>⚔️ Davet</Text>
               </View>
             </View>
           </TouchableOpacity>
         )}/>}
    </View>
  );
}

function MainApp({user:initUser,onLogout}){
  const[user,setUser]=useState(initUser);
  const[tab,setTab]=useState('home');
  const[scr,setScr]=useState(null);
  const[extra,setExtra]=useState(null);
  const music=useMusicPlayer();
  const go=(s,p)=>{setScr(s);setExtra(p||null);};
  const back=()=>{setScr(null);setExtra(null);};
  // Screens
  // ── In-app düello bildirim banner ──
  const[duelBanner,setDuelBanner]=useState(null); // {duelId, fromName, fromUser}
  const bannerAnim=useRef(new Animated.Value(-100)).current;
  const duelPollRef=useRef(null);
  useEffect(()=>{
    // Gelen düello davetlerini dinle (ana ekranda)
    duelPollRef.current=setInterval(async()=>{
      if(scr==='duel')return; // Duel ekranı zaten açık
      try{
        const d=await db._r();
        const duels=d.duels||[];
        const invite=duels.find(duel=>duel.toId===user.id&&duel.status==='pending'&&Date.now()-duel.ts<60000);
        if(invite&&(!duelBanner||duelBanner.duelId!==invite.id)){
          const challenger=d.users.find(u=>u.id===invite.fromId);
          if(challenger){
            setDuelBanner({duelId:invite.id,fromName:challenger.name,fromUser:challenger});
            Animated.spring(bannerAnim,{toValue:0,useNativeDriver:true}).start();
            setTimeout(()=>{
              Animated.timing(bannerAnim,{toValue:-120,duration:400,useNativeDriver:true}).start(()=>setDuelBanner(null));
            },12000);
          }
        }
      }catch{}
    },3000);
    return()=>clearInterval(duelPollRef.current);
  },[user.id,scr,duelBanner]);

  const dismissBanner=()=>{
    Animated.timing(bannerAnim,{toValue:-120,duration:300,useNativeDriver:true}).start(()=>setDuelBanner(null));
  };
  const openDuelFromBanner=()=>{
    dismissBanner();
    go('duel',null);
  };

  const isAdminUser=isAdmin(user);
  if(GAME_IDS.includes(scr))return<GameScreen type={scr} onBack={back} user={user} setUser={setUser}/>;
  if(scr==='chat')return<ChatScreen user={user} peer={extra} onBack={back}/>;
  if(scr==='viewProfile')return<ViewProfile userId={extra} me={user} onBack={back} onMessage={u=>{setScr('chat');setExtra(u);}}/>
  if(scr==='pomodoro')return<PomodoroScreen onBack={back} user={user} setUser={setUser}/>
  if(scr==='favorites')return<FavoritesScreen onBack={back} user={user}/>
  if(scr==='duel')return<DuelScreen onBack={back} user={user} setUser={setUser}/>;
  if(scr==='subjectTopics')return<SubjectTopicsScreen gameId={extra?.gameId} onBack={back} go={startGame}/>;
  if(scr==='topicQuiz')return<TopicQuizScreen topic={extra?.topic} color={extra?.color||'#4338ca'} onBack={back} user={user} setUser={setUser}/>;
  if(scr==='matchGame')return<MatchingGameScreen setId={extra?.setId} onBack={back} user={user} setUser={setUser}/>;
  if(scr==='writingGame')return<WritingGameScreen gameId={extra?.gameId} onBack={back} user={user} setUser={setUser}/>;
  if(scr==='chemLab')return<ChemistryLabScreen onBack={back}/>;
  if(scr==='gradeSubject')return<GradeSubjectScreen onBack={back} go={go}/>;
  if(scr==='circularTopics')return<CircularTopicMenuScreen subject={extra?.subject} onBack={back} go={startGame}/>;
  const renderTab=()=>{
    switch(tab){
      case 'home':  return<HomeTab  user={user} go={go} music={music}/>;
      case 'games': return<GamesTab go={go}/>;
      case 'board': return<BoardTab user={user} go={go}/>;
      case 'achs':  return<AchsTab  user={user}/>;
      case 'set':   return<SettingsTab user={user} setUser={setUser} onLogout={onLogout} go={go}/>;
      case 'admin': return isAdminUser?<AdminTab user={user} setUser={setUser}/>:null;
      default: return null;
    }
  };
  return(
    <SafeAreaView style={{flex:1,backgroundColor:C.bg}}>
      <StatusBar barStyle="dark-content" backgroundColor={C.bg}/>
      {/* In-app düello bildirim banner */}
      {duelBanner&&(
        <Animated.View style={{position:'absolute',top:0,left:0,right:0,zIndex:999,transform:[{translateY:bannerAnim}]}}>
          <View style={{backgroundColor:'#1a1740',margin:12,borderRadius:16,padding:14,
            flexDirection:'row',alignItems:'center',gap:12,
            shadowColor:'#6d28d9',shadowOpacity:0.5,shadowRadius:16,elevation:10,
            borderWidth:1,borderColor:'rgba(109,40,217,0.4)'}}>
            <Text style={{fontSize:28}}>⚔️</Text>
            <View style={{flex:1}}>
              <Text style={{color:'#fff',fontSize:13,fontWeight:'900'}}>{duelBanner.fromName} seni düelloya davet etti!</Text>
              <Text style={{color:'rgba(255,255,255,0.5)',fontSize:11,marginTop:2}}>10 soru · 60 saniye</Text>
            </View>
            <TouchableOpacity onPress={openDuelFromBanner} style={{backgroundColor:'#6d28d9',borderRadius:10,paddingHorizontal:12,paddingVertical:7}}>
              <Text style={{color:'#fff',fontWeight:'800',fontSize:12}}>Gör ›</Text>
            </TouchableOpacity>
            <TouchableOpacity onPress={dismissBanner} style={{padding:4}}>
              <Text style={{color:'rgba(255,255,255,0.4)',fontSize:18}}>✕</Text>
            </TouchableOpacity>
          </View>
        </Animated.View>
      )}
      <View style={{flex:1}}>{renderTab()}</View>
      <View style={[st.tabBar,{paddingBottom:BOTTOM+6}]}>
        {TABS.map(t=>(
          <TouchableOpacity key={t.id} onPress={()=>setTab(t.id)} style={st.tabItem}>
            <Text style={{fontSize:20}}>{t.e}</Text>
            <Text style={{fontSize:8,fontWeight:'600',color:tab===t.id?C.primary:C.light,marginTop:1}}>{t.l}</Text>
          </TouchableOpacity>
        ))}
      </View>
    </SafeAreaView>
  );
}


/* ══ ANA SAYFA ═══════════════════════════════════════ */
function HomeTab({user,go,music,setTab}){
  const r=getRank(user.points||0),nr=getNext(user.points||0);
  const prog=nr?Math.max(0.02,(user.points-r.min)/(nr.min-r.min)):1;
  const[dailyTasks,setDailyTasks]=useState(null);
  const[dailyQ,setDailyQ]=useState(null);
  const[weeklyStats,setWeeklyStats]=useState(null);
  const[showReport,setShowReport]=useState(false);
  useEffect(()=>{
    getDailyTasks(user.id).then(setDailyTasks);
    getDailyQuestion(user.id,ALL_Q_BANK).then(setDailyQ);
    getWeeklyStats(user.id).then(setWeeklyStats);
  },[]);
  return(
    <ScrollView style={{flex:1}} contentContainerStyle={{padding:16}}>
      <View style={{flexDirection:'row',justifyContent:'space-between',alignItems:'center',marginBottom:16}}>
        <TouchableOpacity onPress={()=>go('set')} style={{flexDirection:'row',alignItems:'center',gap:12}}>
          <Avatar user={user} size={46}/>
          <View>
            <Text style={{fontSize:13,color:C.mid}}>Hoş geldin,</Text>
            <Text style={{fontSize:18,fontWeight:'800',color:C.text}}>{user.name} 👋</Text>
          </View>
        </TouchableOpacity>
        <View style={{alignItems:'flex-end',gap:4}}>
          <RankBadge pts={user.points||0}/>
          {weeklyStats&&<TouchableOpacity onPress={()=>setShowReport(true)} style={{backgroundColor:C.purple+'15',borderRadius:8,paddingHorizontal:8,paddingVertical:3}}>
            <Text style={{fontSize:10,color:C.purple,fontWeight:'700'}}>📊 Haftalık Rapor</Text>
          </TouchableOpacity>}
        </View>
      </View>
      <MiniPlayer music={music}/>
      <YKSCountdownWidget yksDate={user.yksDate}/>
      <StreakWidget streak={user.streak}/>
      <Card style={{marginBottom:14,backgroundColor:r.bg}}>
        <View style={{flexDirection:'row',justifyContent:'space-between',alignItems:'center'}}>
          <View>
            <Text style={{fontSize:12,color:C.mid,marginBottom:6}}>Mevcut Rank</Text>
            <RankBadge pts={user.points||0} size="lg"/>
            <Text style={{fontSize:13,color:C.mid,marginTop:8}}>{user.points||0} puan</Text>
          </View>
          <Text style={{fontSize:60}}>{r.e}</Text>
        </View>
        {nr&&(<View style={{marginTop:12}}>
          <View style={{flexDirection:'row',justifyContent:'space-between',marginBottom:6}}>
            <Text style={{fontSize:11,color:C.mid}}>Sonraki: {nr.e} {nr.l}</Text>
            <Text style={{fontSize:11,color:C.mid}}>{nr.min-(user.points||0)} pt kaldı</Text>
          </View>
          <View style={{backgroundColor:'rgba(0,0,0,0.1)',borderRadius:4,height:8,overflow:'hidden'}}>
            <View style={{width:`${Math.round(prog*100)}%`,height:'100%',backgroundColor:r.c,borderRadius:4}}/>
          </View>
        </View>)}
      </Card>
      <View style={{flexDirection:'row',gap:10,marginBottom:14}}>
        {[{l:'Toplam Puan',v:user.points||0,e:'⭐',c:C.amber},{l:'Oyun Sayısı',v:user.gamesPlayed||0,e:'🎮',c:C.purple}].map(s=>(
          <Card key={s.l} style={{flex:1,alignItems:'center'}}>
            <Text style={{fontSize:22}}>{s.e}</Text>
            <Text style={{fontSize:20,fontWeight:'800',color:s.c,marginTop:4}}>{s.v}</Text>
            <Text style={{fontSize:10,color:C.light,marginTop:2}}>{s.l}</Text>
          </Card>
        ))}
      </View>
      <WeakTopicWidget user={user}/>
      <DailyTasksWidget tasks={dailyTasks}/>
      <DailyQuestionWidget dq={dailyQ} onAnswer={()=>getDailyQuestion(user.id,ALL_Q_BANK).then(setDailyQ)} user={user}/>
      <Text style={{fontSize:13,fontWeight:'700',color:C.mid,marginBottom:8}}>HIZLI ERİŞİM</Text>
      <View style={{flexDirection:'row',gap:10,marginBottom:10}}>
        <TouchableOpacity onPress={()=>setTab('games')} style={{flex:1}}>
          <Card style={{alignItems:'center',padding:16,borderLeftWidth:3,borderLeftColor:C.blue}}>
            <Text style={{fontSize:30}}>🎮</Text>
            <Text style={{fontSize:13,fontWeight:'700',color:C.text,marginTop:6}}>Oyunlar</Text>
            <Text style={{fontSize:10,color:C.light}}>10 ders</Text>
          </Card>
        </TouchableOpacity>
        <TouchableOpacity onPress={()=>setTab('study')} style={{flex:1}}>
          <Card style={{alignItems:'center',padding:16,borderLeftWidth:3,borderLeftColor:C.primary}}>
            <Text style={{fontSize:30}}>📊</Text>
            <Text style={{fontSize:13,fontWeight:'700',color:C.text,marginTop:6}}>Çalışma</Text>
            <Text style={{fontSize:10,color:C.light}}>Haftalık takip</Text>
          </Card>
        </TouchableOpacity>
      </View>
      <View style={{flexDirection:'row',gap:10,marginBottom:10}}>
        <TouchableOpacity onPress={()=>go('pomodoro')} style={{flex:1}}>
          <Card style={{alignItems:'center',padding:16,borderLeftWidth:3,borderLeftColor:C.red}}>
            <Text style={{fontSize:30}}>🍅</Text>
            <Text style={{fontSize:13,fontWeight:'700',color:C.text,marginTop:6}}>Pomodoro</Text>
            <Text style={{fontSize:10,color:C.light}}>25dk · +20pt</Text>
          </Card>
        </TouchableOpacity>
        <TouchableOpacity onPress={()=>go('favorites')} style={{flex:1}}>
          <Card style={{alignItems:'center',padding:16,borderLeftWidth:3,borderLeftColor:C.pink}}>
            <Text style={{fontSize:30}}>❤️</Text>
            <Text style={{fontSize:13,fontWeight:'700',color:C.text,marginTop:6}}>Favoriler</Text>
            <Text style={{fontSize:10,color:C.light}}>Zor sorular</Text>
          </Card>
        </TouchableOpacity>
      </View>
      <View style={{flexDirection:'row',gap:10,marginBottom:14}}>
        <TouchableOpacity onPress={()=>go('duel')} style={{flex:1}}>
          <Card style={{alignItems:'center',padding:16,borderLeftWidth:3,borderLeftColor:C.purple}}>
            <Text style={{fontSize:30}}>⚔️</Text>
            <Text style={{fontSize:13,fontWeight:'700',color:C.text,marginTop:6}}>Düello</Text>
            <Text style={{fontSize:10,color:C.light}}>Rakiple yarış</Text>
          </Card>
        </TouchableOpacity>
        <View style={{flex:1}}/>
      </View>
      {weeklyStats&&<WeeklyReportModal visible={showReport} onClose={()=>setShowReport(false)} weeklyStats={weeklyStats} user={user}/>}
    </ScrollView>
  );
}

