function checkChemReaction(contents){
  const fmls=new Set(contents.map(e=>e.formula));
  for(const r of CHEM_REACTIONS){if(r.reactants.every(rx=>fmls.has(rx)))return r;}
  return null;
}
let _labInst=0;
function labId(){return`lab_${Date.now()}_${++_labInst}`;}

/* ── Beherglas Görseli ── */
function LabBeakerView({liquidColor,isReacting,beakerRef,onLayout}){
  const glowAnim=useRef(new Animated.Value(0)).current;
  useEffect(()=>{
    if(isReacting){
      Animated.loop(Animated.sequence([
        Animated.timing(glowAnim,{toValue:1,duration:600,useNativeDriver:false}),
        Animated.timing(glowAnim,{toValue:0,duration:600,useNativeDriver:false}),
      ])).start();
    } else {
      glowAnim.stopAnimation();glowAnim.setValue(0);
    }
  },[isReacting]);
  const glowOpacity=glowAnim.interpolate({inputRange:[0,1],outputRange:[0.3,1]});
  const isLiquid=liquidColor&&liquidColor!=='transparent';
  return(
    <View ref={beakerRef} onLayout={onLayout}
      style={{alignItems:'center',marginBottom:8}}>
      {/* Beherglas gövdesi */}
      <View style={{width:100,height:120,position:'relative',alignItems:'center'}}>
        {/* Beaker body */}
        <View style={{
          position:'absolute',bottom:0,width:90,height:105,
          borderWidth:2.5,borderColor:'rgba(144,205,244,0.55)',
          borderTopWidth:0,borderBottomLeftRadius:12,borderBottomRightRadius:12,
          backgroundColor:'rgba(10,20,50,0.5)',overflow:'hidden',
        }}>
          {/* Liquid fill */}
          {isLiquid&&(
            <Animated.View style={{
              position:'absolute',bottom:0,left:0,right:0,height:'65%',
              backgroundColor:liquidColor,opacity:glowOpacity,
            }}/>
          )}
          {/* Ölçü çizgileri */}
          {[70,50,30].map(pct=>(
            <View key={pct} style={{position:'absolute',top:`${100-pct}%`,left:4,width:12,height:1,backgroundColor:'rgba(144,205,244,0.3)'}}/>
          ))}
        </View>
        {/* Top opening rim */}
        <View style={{
          position:'absolute',top:0,width:100,height:16,
          borderWidth:2.5,borderColor:'rgba(144,205,244,0.55)',
          borderRadius:4,backgroundColor:'rgba(10,20,50,0.5)',
        }}/>
        {/* Reaction bubbles */}
        {isReacting&&[1,2,3].map(i=>(
          <Animated.View key={i} style={{
            position:'absolute',
            bottom:8+i*22,left:20+i*18,
            width:8,height:8,borderRadius:4,
            backgroundColor:liquidColor,opacity:glowOpacity,
          }}/>
        ))}
      </View>
      {/* Beaker base */}
      <View style={{width:100,height:6,backgroundColor:'rgba(144,205,244,0.2)',borderRadius:3,marginTop:2}}/>
    </View>
  );
}

/* ── Kimyasal Kart ── */
function LabChemCard({chemical,small}){
  return(
    <View style={{
      alignItems:'center',justifyContent:'flex-end',
      paddingHorizontal:small?4:6,paddingVertical:small?4:6,
      borderRadius:12,minWidth:small?48:60,
      backgroundColor:`${chemical.color}18`,
      borderWidth:1.5,borderColor:`${chemical.color}55`,
    }}>
      <Image
        source={chemical.image}
        style={{width:small?32:44,height:small?40:56}}
        resizeMode="contain"
      />
      <Text style={{color:'#fff',fontSize:small?9:11,fontWeight:'900',marginTop:3}}>{chemical.formula}</Text>
      {!small&&<Text style={{color:'rgba(255,255,255,0.45)',fontSize:7,marginTop:1,textAlign:'center'}} numberOfLines={1}>{chemical.name}</Text>}
    </View>
  );
}

/* ── Sürüklenebilir Element ── */
function LabDraggable({element,beakerBounds,onDropped}){
  const tx=useSharedValue(0);
  const ty=useSharedValue(0);
  const sc=useSharedValue(1);
  const zi=useSharedValue(1);

  const gesture=Gesture.Pan()
    .onStart(()=>{zi.value=999;sc.value=withSpring(1.25,{damping:10});})
    .onUpdate(e=>{tx.value=e.translationX;ty.value=e.translationY;})
    .onEnd(e=>{
      zi.value=1;sc.value=withSpring(1);
      const fx=e.absoluteX,fy=e.absoluteY;
      if(beakerBounds&&fx>=beakerBounds.x-16&&fx<=beakerBounds.x+beakerBounds.width+16
        &&fy>=beakerBounds.y-16&&fy<=beakerBounds.y+beakerBounds.height+16){
        runOnJS(onDropped)(element.instanceId);
      } else {
        tx.value=withSpring(0,{damping:14});
        ty.value=withSpring(0,{damping:14});
      }
    });

  const aStyle=useAnimatedStyle(()=>({
    transform:[{translateX:tx.value},{translateY:ty.value},{scale:sc.value}],
    zIndex:zi.value,elevation:zi.value>1?20:3,
  }));

  return(
    <GestureDetector gesture={gesture}>
      <RAnimated.View style={[{marginHorizontal:5,marginBottom:8},aStyle]}>
        <LabChemCard chemical={element}/>
      </RAnimated.View>
    </GestureDetector>
  );
}

/* ── Floating Tepkime Metni ── */
function ChemFloatingText({reaction,onEnd}){
  const ty=useSharedValue(0);
  const op=useSharedValue(1);
  const sc=useSharedValue(0.4);
  useEffect(()=>{
    sc.value=withSpring(1,{damping:7,stiffness:130});
    ty.value=withTiming(-170,{duration:3200,easing:Easing.out(Easing.cubic)});
    op.value=withTiming(0,{duration:3200,easing:Easing.in(Easing.quad)},(fin)=>{if(fin)runOnJS(onEnd)();});
  },[]);
  const aStyle=useAnimatedStyle(()=>({transform:[{translateY:ty.value},{scale:sc.value}],opacity:op.value}));
  return(
    <RAnimated.View pointerEvents="none"
      style={[{position:'absolute',bottom:10,alignSelf:'center',alignItems:'center',zIndex:50},aStyle]}>
      <Text style={{fontSize:28}}>{reaction.emoji}</Text>
      <View style={{
        paddingHorizontal:18,paddingVertical:8,borderRadius:16,marginTop:4,
        backgroundColor:`${reaction.resultColor}22`,
        borderWidth:2.5,borderColor:`${reaction.resultColor}90`,
      }}>
        <Text style={{
          color:reaction.resultColor,fontSize:20,fontFamily:'monospace',fontWeight:'900',
          textShadowColor:'#000',textShadowOffset:{width:0,height:2},textShadowRadius:8,
        }}>{reaction.product}</Text>
      </View>
      <View style={{marginTop:6,paddingHorizontal:12,paddingVertical:4,borderRadius:20,backgroundColor:'rgba(0,0,0,0.6)'}}>
        <Text style={{color:reaction.resultColor,fontSize:10,fontWeight:'600',textAlign:'center'}}>{reaction.desc}</Text>
      </View>
    </RAnimated.View>
  );
}

/* ── Kısmi Tepkime İpucu ── */
function ReactionHint({beakerContents}){
  const formulas=beakerContents.map(c=>c.formula);
  const partial=CHEM_REACTIONS.find(r=>
    r.reactants.some(req=>formulas.includes(req))&&
    !r.reactants.every(req=>formulas.includes(req))
  );
  if(!partial)return null;
  const missing=partial.reactants.filter(r=>!formulas.includes(r));
  return(
    <View style={{
      marginTop:6,paddingHorizontal:14,paddingVertical:8,borderRadius:14,
      backgroundColor:'rgba(236,201,75,0.1)',borderWidth:1,borderColor:'rgba(236,201,75,0.35)',
      maxWidth:260,alignSelf:'center',
    }}>
      <Text style={{color:'rgba(236,201,75,0.9)',fontSize:10,textAlign:'center',lineHeight:16}}>
        {'💡 Eksik: '}
        <Text style={{fontWeight:'900'}}>{missing.join(', ')}</Text>
        {' → '}<Text style={{fontWeight:'900'}}>{partial.product}</Text>
      </Text>
    </View>
  );
}

/* ── Yanıp Sönen Dolap Hotspot ── */
function LabCabinetHotspot({onPress}){
  const pulse=useSharedValue(0);
  useEffect(()=>{
    pulse.value=withRepeat(withTiming(1,{duration:900,easing:Easing.inOut(Easing.ease)}),-1,true);
  },[]);
  const borderStyle=useAnimatedStyle(()=>({
    borderColor:`rgba(88,166,255,${0.3+pulse.value*0.7})`,
    shadowOpacity:0.15+pulse.value*0.85,
    shadowRadius:4+pulse.value*16,
  }));
  return(
    <TouchableOpacity onPress={onPress} activeOpacity={0.7}
      style={{position:'absolute',top:WH*0.14,left:WW*0.34,width:WW*0.32,height:WH*0.20,zIndex:100}}>
      <RAnimated.View style={[{
        flex:1,borderWidth:2.5,borderRadius:10,
        shadowColor:'#58A6FF',shadowOffset:{width:0,height:0},elevation:0,
      },borderStyle]}/>
    </TouchableOpacity>
  );
}

/* ══ KİMYA LABORATUVARI EKRANI ══════════════════════════════════════ */
function ChemistryLabScreen({onBack}){
  const[catalogVisible,setCatalogVisible]=useState(false);
  const[selectedIds,setSelectedIds]=useState(new Set());
  const[tableEls,setTableEls]=useState([]);
  const[beakerContents,setBeakerContents]=useState([]);
  const[beakerLiquidColor,setBeakerLiquidColor]=useState('transparent');
  const[isReacting,setIsReacting]=useState(false);
  const[hintVisible,setHintVisible]=useState(false);
  const[activeReaction,setActiveReaction]=useState(null);
  const[reactionLog,setReactionLog]=useState([]);
  const[showLog,setShowLog]=useState(false);
  const[beakerBounds,setBeakerBounds]=useState(null);

  const tableRef=useRef([]);
  const beakerViewRef=useRef(null);
  const reactionTimerRef=useRef(null);

  useEffect(()=>{tableRef.current=tableEls;},[tableEls]);

  const measureBeaker=useCallback(()=>{
    beakerViewRef.current?.measureInWindow((x,y,w,h)=>setBeakerBounds({x,y,width:w,height:h}));
  },[]);

  const toggleSelect=useCallback((id)=>{
    setSelectedIds(prev=>{const n=new Set(prev);n.has(id)?n.delete(id):n.add(id);return n;});
  },[]);

  const confirmAdd=useCallback(()=>{
    const els=CHEM_CATALOG.filter(e=>selectedIds.has(e.id)).map(e=>({...e,instanceId:labId()}));
    setTableEls(prev=>[...prev,...els]);
    setSelectedIds(new Set());
    setCatalogVisible(false);
  },[selectedIds]);

  const handleDrop=useCallback((instanceId)=>{
    const el=tableRef.current.find(e=>e.instanceId===instanceId);
    if(!el)return;
    setTableEls(prev=>prev.filter(e=>e.instanceId!==instanceId));
    setBeakerContents(prev=>{
      const updated=[...prev,el];
      // Liquid color
      if(el.type==='liquid'){setBeakerLiquidColor(el.color);}
      else{setBeakerLiquidColor(c=>c==='transparent'?'rgba(160,174,192,0.4)':c);}
      // Check reaction
      const rxn=checkChemReaction(updated);
      if(rxn){
        if(reactionTimerRef.current)clearTimeout(reactionTimerRef.current);
        setIsReacting(true);
        setBeakerLiquidColor(rxn.resultColor+'BB');
        setActiveReaction(rxn);
        setReactionLog(log=>[{
          ...rxn,
          id:`log-${Date.now()}`,
          text:`${rxn.reactants.join(' + ')} → ${rxn.product}`,
          time:new Date().toLocaleTimeString('tr-TR',{hour:'2-digit',minute:'2-digit'}),
        },...log].slice(0,20));
        reactionTimerRef.current=setTimeout(()=>{
          setBeakerContents([]);
          setBeakerLiquidColor('transparent');
          setIsReacting(false);
        },3400);
      }
      return updated;
    });
  },[]);

  const handleFloatEnd=useCallback(()=>{setActiveReaction(null);},[]);
  const clearBeaker=()=>{
    setBeakerContents([]);setBeakerLiquidColor('transparent');
    setIsReacting(false);setActiveReaction(null);
    if(reactionTimerRef.current)clearTimeout(reactionTimerRef.current);
  };
  const closeCatalog=()=>{setSelectedIds(new Set());setCatalogVisible(false);};

  return(
    <View style={{flex:1,backgroundColor:'#060D1F'}}>
      <StatusBar barStyle="light-content" backgroundColor="#060D1F"/>

      {/* ── Arka Plan Dekorasyon ── */}
      <View style={{position:'absolute',inset:0,overflow:'hidden'}} pointerEvents="none">
        {/* Grid lines */}
        {Array.from({length:12}).map((_,i)=>(
          <View key={`h${i}`} style={{position:'absolute',top:`${i*8}%`,left:0,right:0,height:1,backgroundColor:'rgba(99,179,237,0.04)'}}/>
        ))}
        {Array.from({length:8}).map((_,i)=>(
          <View key={`v${i}`} style={{position:'absolute',left:`${i*14}%`,top:0,bottom:'38%',width:1,backgroundColor:'rgba(99,179,237,0.04)'}}/>
        ))}
        {/* Center glow */}
        <View style={{position:'absolute',top:'25%',left:'25%',width:'50%',height:'30%',
          backgroundColor:'rgba(66,153,225,0.03)',borderRadius:999}}/>
      </View>

      {/* ── Top Bar ── */}
      <View style={{
        flexDirection:'row',alignItems:'center',justifyContent:'space-between',
        paddingHorizontal:16,paddingTop:TOP_INSET+10,paddingBottom:12,
        borderBottomWidth:1,borderBottomColor:'rgba(99,179,237,0.15)',
        backgroundColor:'rgba(6,13,31,0.95)',zIndex:100,
      }}>
        <View style={{flexDirection:'row',alignItems:'center',gap:10}}>
          <TouchableOpacity onPress={onBack}
            style={{width:36,height:36,borderRadius:18,backgroundColor:'rgba(99,179,237,0.1)',
              borderWidth:1,borderColor:'rgba(99,179,237,0.25)',alignItems:'center',justifyContent:'center'}}>
            <Text style={{color:'#90CDF4',fontSize:16,fontWeight:'800'}}>←</Text>
          </TouchableOpacity>
          <View>
            <Text style={{color:'#E2E8F0',fontSize:15,fontWeight:'800',lineHeight:18}}>⚗️ Kimya Laboratuvarı</Text>
            <Text style={{color:'rgba(144,205,244,0.5)',fontSize:9}}>Etkileşimli 2D Deney Ekranı</Text>
          </View>
        </View>
        <View style={{flexDirection:'row',gap:8,alignItems:'center'}}>
          {/* İpucu butonu */}
          <TouchableOpacity onPress={()=>setHintVisible(true)}
            style={{width:36,height:36,borderRadius:18,backgroundColor:'rgba(236,201,75,0.12)',
              borderWidth:1,borderColor:'rgba(236,201,75,0.35)',alignItems:'center',justifyContent:'center'}}>
            <Text style={{fontSize:16}}>💡</Text>
          </TouchableOpacity>
          {/* Log butonu */}
          <TouchableOpacity onPress={()=>setShowLog(v=>!v)}
            style={{width:36,height:36,borderRadius:18,backgroundColor:'rgba(99,179,237,0.1)',
              borderWidth:1,borderColor:'rgba(99,179,237,0.2)',alignItems:'center',justifyContent:'center'}}>
            <Text style={{fontSize:16}}>📋</Text>
            {reactionLog.length>0&&(
              <View style={{position:'absolute',top:-4,right:-4,width:18,height:18,borderRadius:9,
                backgroundColor:'#E53E3E',alignItems:'center',justifyContent:'center'}}>
                <Text style={{color:'#fff',fontSize:9,fontWeight:'800'}}>{reactionLog.length}</Text>
              </View>
            )}
          </TouchableOpacity>
        </View>
      </View>

      {/* ── Kombinasyon İpucu Modal ── */}
      <Modal visible={hintVisible} transparent animationType="fade" onRequestClose={()=>setHintVisible(false)}>
        <View style={{flex:1,backgroundColor:'rgba(0,0,0,0.75)',justifyContent:'center',alignItems:'center',padding:20}}>
          <View style={{backgroundColor:'#0D1A2E',borderRadius:20,width:'100%',maxHeight:'80%',
            borderWidth:1.5,borderColor:'rgba(236,201,75,0.4)',overflow:'hidden'}}>
            {/* Başlık */}
            <View style={{flexDirection:'row',alignItems:'center',padding:16,
              borderBottomWidth:1,borderBottomColor:'rgba(236,201,75,0.2)',
              backgroundColor:'rgba(236,201,75,0.08)'}}>
              <Text style={{flex:1,color:'#ECC94B',fontSize:15,fontWeight:'900'}}>💡 Yapılabilecek Tepkimeler</Text>
              <TouchableOpacity onPress={()=>setHintVisible(false)}
                style={{width:30,height:30,borderRadius:15,backgroundColor:'rgba(229,62,62,0.2)',
                  alignItems:'center',justifyContent:'center'}}>
                <Text style={{color:'#FC8181',fontSize:14,fontWeight:'700'}}>✕</Text>
              </TouchableOpacity>
            </View>
            <ScrollView style={{padding:12}} contentContainerStyle={{gap:8,paddingBottom:8}}>
              {CHEM_REACTIONS.map((r,i)=>(
                <View key={i} style={{
                  flexDirection:'row',alignItems:'center',
                  backgroundColor:'rgba(255,255,255,0.04)',
                  borderRadius:12,padding:10,gap:10,
                  borderWidth:1,borderColor:'rgba(255,255,255,0.08)'}}>
                  <Text style={{fontSize:18}}>{r.emoji}</Text>
                  <View style={{flex:1}}>
                    <Text style={{color:'#ECC94B',fontSize:11,fontWeight:'900',fontFamily:'monospace'}}>
                      {r.reactants.join(' + ')}
                    </Text>
                    <Text style={{color:'rgba(255,255,255,0.45)',fontSize:9,marginTop:2}}>{r.desc.split('→')[0].trim()}</Text>
                  </View>
                  <Text style={{color:'rgba(255,255,255,0.2)',fontSize:18}}>→ ?</Text>
                </View>
              ))}
            </ScrollView>
            <View style={{padding:12,borderTopWidth:1,borderTopColor:'rgba(255,255,255,0.08)'}}>
              <Text style={{color:'rgba(255,255,255,0.3)',fontSize:9,textAlign:'center'}}>
                Maddeleri masaya ekle ve behere sürükle — sonuçları kendin keşfet!
              </Text>
            </View>
          </View>
        </View>
      </Modal>

      {/* ── Tepkime Log Paneli ── */}
      {showLog&&(
        <View style={{
          position:'absolute',top:TOP_INSET+62,right:12,zIndex:200,width:WW*0.75,maxHeight:320,
          backgroundColor:'rgba(6,13,31,0.97)',borderRadius:16,
          borderWidth:1,borderColor:'rgba(99,179,237,0.25)',
          shadowColor:'#000',shadowOpacity:0.5,shadowRadius:12,elevation:20,overflow:'hidden',
        }}>
          <View style={{flexDirection:'row',justifyContent:'space-between',alignItems:'center',
            paddingHorizontal:14,paddingVertical:10,borderBottomWidth:1,borderBottomColor:'rgba(99,179,237,0.15)'}}>
            <Text style={{color:'#90CDF4',fontSize:13,fontWeight:'800'}}>📋 Tepkime Günlüğü</Text>
            <TouchableOpacity onPress={()=>setShowLog(false)}>
              <Text style={{color:'rgba(144,205,244,0.5)',fontSize:18}}>✕</Text>
            </TouchableOpacity>
          </View>
          {reactionLog.length===0?(
            <View style={{padding:20,alignItems:'center'}}>
              <Text style={{color:'rgba(144,205,244,0.4)',fontSize:11,textAlign:'center',lineHeight:18}}>
                {'Henüz tepkime gerçekleşmedi.\nMaddeleri behere sürükle!'}
              </Text>
            </View>
          ):(
            <ScrollView style={{maxHeight:240,padding:10}}>
              {reactionLog.map((entry)=>(
                <View key={entry.id} style={{
                  padding:10,borderRadius:10,marginBottom:6,
                  backgroundColor:`${entry.resultColor}12`,
                  borderWidth:1,borderColor:`${entry.resultColor}30`,
                }}>
                  <Text style={{color:entry.resultColor,fontSize:10,fontFamily:'monospace',fontWeight:'800'}}>{entry.text}</Text>
                  <Text style={{color:'rgba(255,255,255,0.5)',fontSize:9,marginTop:2}}>{entry.desc}</Text>
                  <Text style={{color:'rgba(255,255,255,0.25)',fontSize:8,marginTop:1}}>{entry.time}</Text>
                </View>
              ))}
            </ScrollView>
          )}
          <View style={{padding:10,borderTopWidth:1,borderTopColor:'rgba(99,179,237,0.12)'}}>
            <Text style={{color:'rgba(144,205,244,0.4)',fontSize:9}}>💡 {CHEM_REACTIONS.length} farklı tepkime keşfedilebilir</Text>
          </View>
        </View>
      )}

      <ScrollView style={{flex:1}} contentContainerStyle={{flexGrow:1}} scrollEnabled={false}>

        {/* ── Beherglas Zonu ── */}
        <View style={{flex:1,alignItems:'center',justifyContent:'center',paddingTop:16,minHeight:WH*0.44}}>
          {/* Hedef etiket */}
          <View style={{
            paddingHorizontal:14,paddingVertical:5,borderRadius:20,marginBottom:8,
            backgroundColor:'rgba(0,0,0,0.28)',borderWidth:1,borderColor:'rgba(99,179,237,0.2)',
          }}>
            <Text style={{color:'rgba(144,205,244,0.75)',fontSize:10,fontWeight:'700'}}>🔬 BEHERGLAS — HEDEF ALAN</Text>
          </View>

          {/* Beherglas + floating text wrapper */}
          <View style={{alignItems:'center',position:'relative'}}>
            {/* Floating tepkime */}
            {activeReaction&&(
              <ChemFloatingText reaction={activeReaction} onEnd={handleFloatEnd}/>
            )}

            {/* Beaker */}
            <LabBeakerView
              beakerRef={beakerViewRef}
              onLayout={()=>setTimeout(measureBeaker,200)}
              liquidColor={isReacting?beakerLiquidColor:(beakerLiquidColor==='transparent'?null:beakerLiquidColor)}
              isReacting={isReacting}
            />
          </View>

          {/* İçerik pills */}
          {beakerContents.length>0&&(
            <View style={{flexDirection:'row',flexWrap:'wrap',justifyContent:'center',gap:5,marginTop:4,paddingHorizontal:16,maxWidth:WW*0.85}}>
              {beakerContents.map((chem,i)=>(
                <View key={`${chem.instanceId||chem.id}-${i}`} style={{
                  paddingHorizontal:8,paddingVertical:3,borderRadius:20,
                  backgroundColor:`${chem.color}22`,borderWidth:1,borderColor:`${chem.color}55`,
                }}>
                  <Text style={{color:chem.color,fontSize:10,fontFamily:'monospace',fontWeight:'800'}}>{chem.formula}</Text>
                </View>
              ))}
              <TouchableOpacity onPress={clearBeaker}
                style={{paddingHorizontal:8,paddingVertical:3,borderRadius:20,
                  backgroundColor:'rgba(229,62,62,0.12)',borderWidth:1,borderColor:'rgba(229,62,62,0.35)',
                  flexDirection:'row',alignItems:'center',gap:3}}>
                <Text style={{color:'rgba(252,129,129,0.85)',fontSize:10}}>🗑</Text>
                <Text style={{color:'rgba(252,129,129,0.85)',fontSize:9,fontWeight:'700'}}>Temizle</Text>
              </TouchableOpacity>
            </View>
          )}

          {/* Kısmi tepkime ipucu */}
          {beakerContents.length>0&&!isReacting&&(
            <ReactionHint beakerContents={beakerContents}/>
          )}
        </View>

        {/* ── Laboratuvar Masası ── */}
        <View style={{
          minHeight:WH*0.32,
          backgroundColor:'#1a0f0a',
          borderTopWidth:3,borderTopColor:'#6B3A1F',
        }}>
          {/* Tahta doku çizgileri */}
          {[8,22,38,56,75].map(pct=>(
            <View key={pct} style={{position:'absolute',top:`${pct}%`,left:0,right:0,height:1,backgroundColor:'rgba(255,200,120,0.04)'}}/>
          ))}

          {/* Masa etiketi */}
          <View style={{position:'absolute',top:8,left:14,paddingHorizontal:7,paddingVertical:3,
            borderRadius:5,borderWidth:1,borderColor:'rgba(180,120,60,0.15)'}}>
            <Text style={{color:'rgba(180,120,60,0.5)',fontSize:8,fontWeight:'700',letterSpacing:1.5}}>LABORATUVAR MASASI</Text>
          </View>

          {/* Temizle butonu */}
          {tableEls.length>0&&(
            <TouchableOpacity onPress={()=>setTableEls([])}
              style={{position:'absolute',top:8,right:12,flexDirection:'row',alignItems:'center',gap:4,
                paddingHorizontal:9,paddingVertical:4,borderRadius:8,
                backgroundColor:'rgba(229,62,62,0.1)',borderWidth:1,borderColor:'rgba(229,62,62,0.25)'}}>
              <Text style={{color:'rgba(252,129,129,0.7)',fontSize:9}}>🗑</Text>
              <Text style={{color:'rgba(252,129,129,0.7)',fontSize:8,fontWeight:'700'}}>Masayı Temizle</Text>
            </TouchableOpacity>
          )}

          {tableEls.length===0?(
            <View style={{flex:1,alignItems:'center',justifyContent:'center',paddingVertical:36,paddingTop:42}}>
              <Text style={{fontSize:28,marginBottom:8}}>⚛️</Text>
              <Text style={{color:'rgba(180,120,60,0.38)',fontSize:11,textAlign:'center',lineHeight:18}}>
                {'Kimyasal dolabını aç, maddeleri seç ve masaya ekle.\nArdından beherglas\'a sürükle!'}
              </Text>
              <TouchableOpacity onPress={()=>setCatalogVisible(true)}
                style={{marginTop:14,paddingHorizontal:18,paddingVertical:9,borderRadius:14,
                  backgroundColor:'rgba(66,153,225,0.15)',borderWidth:1,borderColor:'rgba(99,179,237,0.3)'}}>
                <Text style={{color:'rgba(144,205,244,0.85)',fontSize:12,fontWeight:'700'}}>🗄️ Dolabı Aç</Text>
              </TouchableOpacity>
            </View>
          ):(
            <View style={{paddingTop:32,paddingHorizontal:12,paddingBottom:16,
              flexDirection:'row',flexWrap:'wrap',alignItems:'flex-start'}}>
              {tableEls.map(el=>(
                <LabDraggable key={el.instanceId} element={el} beakerBounds={beakerBounds} onDropped={handleDrop}/>
              ))}
            </View>
          )}

          {/* Alt ipucu */}
          {tableEls.length>0&&(
            <View style={{paddingBottom:BOTTOM+6,paddingTop:4,alignItems:'center'}}>
              <View style={{paddingHorizontal:12,paddingVertical:4,borderRadius:20,
                backgroundColor:'rgba(0,0,0,0.2)',borderWidth:1,borderColor:'rgba(180,120,60,0.15)'}}>
                <Text style={{color:'rgba(180,120,60,0.42)',fontSize:9}}>
                  {tableEls.length} madde masada • tut ve behere sürükle
                </Text>
              </View>
            </View>
          )}
        </View>
      </ScrollView>

      {/* ── Kimyasal Dolabı Modal ── */}
      <Modal visible={catalogVisible} animationType="slide" onRequestClose={closeCatalog}>
        <SafeAreaView style={{flex:1,backgroundColor:'#120A04'}}>
          {/* Başlık */}
          <View style={{flexDirection:'row',alignItems:'center',paddingHorizontal:16,paddingVertical:14,
            backgroundColor:'#2A1810',borderBottomWidth:2,borderBottomColor:'#5C3010'}}>
            <Text style={{flex:1,color:'#F5CBA7',fontSize:17,fontWeight:'900'}}>🧪 Kimyasal Dolabı</Text>
            <TouchableOpacity onPress={closeCatalog}
              style={{width:36,height:36,borderRadius:18,backgroundColor:'rgba(229,62,62,0.25)',
                alignItems:'center',justifyContent:'center'}}>
              <Text style={{color:'#FC8181',fontSize:18,fontWeight:'700'}}>✕</Text>
            </TouchableOpacity>
          </View>

          {/* Kategorili liste */}
          <ScrollView style={{flex:1}} contentContainerStyle={{paddingBottom:120}}>
            {[
              {label:'🪨 Elementler & Katılar', filter:(i)=>i.type==='solid'},
              {label:'🌡️ Cıva (Sıvı Metal)',    filter:(i)=>i.type==='metal_liquid'},
              {label:'🧪 Sıvılar & Asitler',    filter:(i)=>i.type==='liquid'},
              {label:'💨 Gazlar',               filter:(i)=>i.type==='gas'},
            ].map((cat,ci)=>{
              const items=CHEM_CATALOG.filter(cat.filter);
              if(items.length===0)return null;
              return(
                <View key={ci}>
                  {/* Kategori başlığı */}
                  <View style={{backgroundColor:'#2A1810',paddingHorizontal:16,paddingVertical:8,
                    borderBottomWidth:1,borderTopWidth:ci>0?2:0,borderColor:'#5C3010',
                    flexDirection:'row',alignItems:'center',gap:8}}>
                    <Text style={{color:'#F5CBA7',fontSize:13,fontWeight:'900'}}>{cat.label}</Text>
                    <View style={{backgroundColor:'#5C3010',borderRadius:10,paddingHorizontal:7,paddingVertical:2}}>
                      <Text style={{color:'#F5CBA7',fontSize:10,fontWeight:'700'}}>{items.length}</Text>
                    </View>
                  </View>
                  {/* 2'li grid */}
                  <View style={{flexDirection:'row',flexWrap:'wrap',padding:12,gap:12}}>
                    {items.map(item=>{
                      const sel=selectedIds.has(item.id);
                      return(
                        <TouchableOpacity key={item.id} onPress={()=>toggleSelect(item.id)} activeOpacity={0.7}
                          style={{width:(WW-48)/2,position:'relative'}}>
                          <View style={{
                            width:'100%',alignItems:'center',paddingVertical:12,paddingHorizontal:4,
                            borderRadius:16,
                            backgroundColor:sel?item.color+'35':'#1C1008',
                            borderWidth:2,borderColor:sel?item.color:'#3D2010',
                          }}>
                            <Image source={item.image} style={{width:100,height:130}} resizeMode="contain"/>
                            <Text style={{color:sel?'#fff':'#F5CBA7',fontSize:13,fontWeight:'900',
                              marginTop:8,fontFamily:'monospace'}}>{item.formula}</Text>
                            <Text style={{color:'rgba(245,203,167,0.55)',fontSize:10,marginTop:3,textAlign:'center'}}
                              numberOfLines={1}>{item.name}</Text>
                          </View>
                          {sel&&(
                            <View style={{position:'absolute',top:-6,right:-4,width:22,height:22,borderRadius:11,
                              backgroundColor:item.color,alignItems:'center',justifyContent:'center',
                              borderWidth:2,borderColor:'#fff',elevation:5}}>
                              <Text style={{color:'#fff',fontSize:11,fontWeight:'900'}}>✓</Text>
                            </View>
                          )}
                        </TouchableOpacity>
                      );
                    })}
                  </View>
                </View>
              );
            })}
          </ScrollView>

          {/* Alt bar */}
          <View style={{position:'absolute',bottom:0,left:0,right:0,
            backgroundColor:'#2A1810',borderTopWidth:2,borderTopColor:'#5C3010',
            paddingHorizontal:16,paddingVertical:14,paddingBottom:BOTTOM+14,
            flexDirection:'row',alignItems:'center',gap:12}}>
            <View style={{flex:1}}>
              <Text style={{color:'#F5CBA7',fontSize:14,fontWeight:'700'}}>
                {selectedIds.size===0?'Şişeye dokun, seç':selectedIds.size+' madde seçildi'}
              </Text>
              <Text style={{color:'rgba(245,203,167,0.5)',fontSize:10,marginTop:2}} numberOfLines={1}>
                {selectedIds.size>0
                  ?[...selectedIds].map(id=>CHEM_CATALOG.find(c=>c.id===id)?.formula).filter(Boolean).join(' + ')
                  :'Birden fazla seçebilirsin'}
              </Text>
            </View>
            <TouchableOpacity onPress={confirmAdd} disabled={selectedIds.size===0}
              style={{backgroundColor:selectedIds.size===0?'#2A1810':'#3B82F6',
                borderRadius:14,paddingVertical:14,paddingHorizontal:20,
                borderWidth:selectedIds.size===0?1:0,borderColor:'#5C3010'}}>
              <Text style={{color:selectedIds.size===0?'rgba(245,203,167,0.4)':'#fff',
                fontSize:14,fontWeight:'900'}}>Masaya Ekle ›</Text>
            </TouchableOpacity>
          </View>
        </SafeAreaView>
      </Modal>
    </View>
  );
}


