/* ══ KONU QUIZ EKRANI ════════════════════════════════ */
function TopicQuizScreen({topic,color,onBack,user,setUser}){
  const questions=useMemo(()=>[...topic.q].sort(()=>Math.random()-0.5),[]);
  const[idx,setIdx]=useState(0);
  const[sel,setSel]=useState(null);
  const[score,setScore]=useState(0);
  const[wrong,setWrong]=useState(0);
  const[done,setDone]=useState(false);
  const[hintOpen,setHintOpen]=useState(false);
  const startTime=useRef(Date.now());

  const current=questions[idx];
  const opts=useMemo(()=>{
    if(!current)return[];
    return [...current.w,current.a].sort(()=>Math.random()-0.5);
  },[idx]);

  const advance=useCallback((nextIdx)=>{
    if(nextIdx>=questions.length){setDone(true);}
    else{setIdx(nextIdx);setSel(null);}
  },[questions.length]);

  const pick=(opt)=>{
    if(sel)return;
    setSel(opt);
    const correct=opt===current.a;
    if(correct){setScore(s=>s+1);}else{setWrong(w=>w+1);}
    setTimeout(()=>advance(idx+1),700);
  };

  const restart=()=>{setIdx(0);setSel(null);setScore(0);setWrong(0);setDone(false);startTime.current=Date.now();};

  const savePoints=async()=>{
    if(!user||!setUser)return;
    const elapsed=Math.round((Date.now()-startTime.current)/1000);
    const pts=score*10+Math.max(0,(questions.length*30-elapsed))*2;
    try{const upd={...user,points:(user.points||0)+pts};const saved=await db.update(upd);setUser(saved);}catch(e){}
  };

  if(done){
    const pct=Math.round(score/questions.length*100);
    const elapsed=Math.round((Date.now()-startTime.current)/1000);
    const earnedPts=score*10+Math.max(0,(questions.length*30-elapsed))*2;
    return(
      <View style={{flex:1,backgroundColor:'#fff',alignItems:'center',justifyContent:'center',padding:24}}>
        <View style={{width:110,height:110,borderRadius:55,backgroundColor:color,alignItems:'center',justifyContent:'center',marginBottom:20,shadowColor:color,shadowOpacity:0.4,shadowRadius:20}}>
          <Text style={{fontSize:38}}>{pct>=70?'🏆':pct>=50?'👍':'💪'}</Text>
        </View>
        <Text style={{fontSize:24,fontWeight:'900',color:'#1e293b',marginBottom:4}}>Tamamlandı!</Text>
        <Text style={{fontSize:16,color:'#64748b',marginBottom:20}}>{topic.title}</Text>
        <View style={{backgroundColor:'#f0fdf4',borderRadius:16,paddingVertical:12,paddingHorizontal:28,marginBottom:24,borderWidth:2,borderColor:'#16a34a'}}>
          <Text style={{fontSize:28,fontWeight:'900',color:'#16a34a',textAlign:'center'}}>+{earnedPts} puan</Text>
          <Text style={{fontSize:12,color:'#64748b',textAlign:'center',marginTop:2}}>{score}×10 doğru + hız bonusu</Text>
        </View>
        <View style={{flexDirection:'row',gap:14,marginBottom:28}}>
          <View style={{alignItems:'center',backgroundColor:'#f8fafc',borderRadius:16,padding:16,minWidth:76,borderWidth:1,borderColor:'#e2e8f0'}}>
            <Text style={{fontSize:26,fontWeight:'900',color:'#16a34a'}}>{score}</Text>
            <Text style={{fontSize:11,color:'#64748b',fontWeight:'600'}}>DOĞRU</Text>
          </View>
          <View style={{alignItems:'center',backgroundColor:'#f8fafc',borderRadius:16,padding:16,minWidth:76,borderWidth:1,borderColor:'#e2e8f0'}}>
            <Text style={{fontSize:26,fontWeight:'900',color:'#dc2626'}}>{wrong}</Text>
            <Text style={{fontSize:11,color:'#64748b',fontWeight:'600'}}>YANLIŞ</Text>
          </View>
          <View style={{alignItems:'center',backgroundColor:'#f8fafc',borderRadius:16,padding:16,minWidth:76,borderWidth:1,borderColor:'#e2e8f0'}}>
            <Text style={{fontSize:26,fontWeight:'900',color:color}}>{pct}%</Text>
            <Text style={{fontSize:11,color:'#64748b',fontWeight:'600'}}>BAŞARI</Text>
          </View>
        </View>
        <TouchableOpacity onPress={()=>{savePoints();restart();}} style={{backgroundColor:color,borderRadius:14,paddingHorizontal:32,paddingVertical:14,marginBottom:12,width:'100%',alignItems:'center'}}>
          <Text style={{color:'#fff',fontWeight:'800',fontSize:16}}>Tekrar Oyna</Text>
        </TouchableOpacity>
        <TouchableOpacity onPress={()=>{savePoints();onBack();}} style={{width:'100%',alignItems:'center',paddingVertical:12}}>
          <Text style={{color:'#64748b',fontWeight:'600',fontSize:14}}>← Konulara Dön</Text>
        </TouchableOpacity>
      </View>
    );
  }

  if(!current)return null;

  return(
    <View style={{flex:1,backgroundColor:'#fff'}}>
      {/* ── Hint Modal ── */}
      {hintOpen&&current.hint&&(
        <Modal visible={hintOpen} transparent animationType="fade" onRequestClose={()=>setHintOpen(false)}>
          <View style={{flex:1,backgroundColor:'rgba(0,0,0,0.55)',justifyContent:'center',alignItems:'center',padding:28}}>
            <View style={{backgroundColor:'#fff',borderRadius:20,width:'100%',padding:24,
              borderWidth:2,borderColor:'#ECC94B',shadowColor:'#ECC94B',shadowOpacity:0.3,shadowRadius:20}}>
              <Text style={{fontSize:18,fontWeight:'900',color:'#92400e',marginBottom:12,textAlign:'center'}}>💡 İpucu</Text>
              <Text style={{fontSize:15,color:'#374151',lineHeight:24,textAlign:'center',marginBottom:20}}>{current.hint}</Text>
              <TouchableOpacity onPress={()=>setHintOpen(false)}
                style={{backgroundColor:color,borderRadius:12,paddingVertical:12,alignItems:'center'}}>
                <Text style={{color:'#fff',fontWeight:'800',fontSize:15}}>Anladım</Text>
              </TouchableOpacity>
            </View>
          </View>
        </Modal>
      )}
      <View style={{backgroundColor:color,paddingTop:TOP_INSET+12,paddingBottom:20,paddingHorizontal:16}}>
        <View style={{flexDirection:'row',alignItems:'center',gap:12,marginBottom:14}}>
          <TouchableOpacity onPress={onBack} style={{width:36,height:36,borderRadius:18,backgroundColor:'rgba(255,255,255,0.2)',alignItems:'center',justifyContent:'center'}}>
            <Text style={{color:'#fff',fontSize:18,fontWeight:'700'}}>←</Text>
          </TouchableOpacity>
          <Text style={{color:'#fff',fontSize:16,fontWeight:'800',flex:1}}>{topic.title}</Text>
          {current.hint&&(
            <TouchableOpacity onPress={()=>setHintOpen(true)}
              style={{width:36,height:36,borderRadius:18,backgroundColor:'rgba(255,255,255,0.2)',alignItems:'center',justifyContent:'center',marginRight:4}}>
              <Text style={{fontSize:18}}>💡</Text>
            </TouchableOpacity>
          )}
          <Text style={{color:'rgba(255,255,255,0.9)',fontSize:14,fontWeight:'700'}}>{idx+1}/{questions.length}</Text>
        </View>
        <View style={{height:5,backgroundColor:'rgba(255,255,255,0.25)',borderRadius:3}}>
          <View style={{height:5,backgroundColor:'#fff',borderRadius:3,width:(idx/questions.length*100)+'%'}}/>
        </View>
      </View>
      <ScrollView contentContainerStyle={{padding:20}}>
        <View style={{backgroundColor:'#f8fafc',borderRadius:18,padding:20,marginBottom:20,borderWidth:1,borderColor:'#e2e8f0'}}>
          <Text style={{fontSize:11,fontWeight:'800',color:color,marginBottom:10,letterSpacing:0.5}}>SORU {idx+1}</Text>
          <Text style={{fontSize:17,fontWeight:'700',color:'#1e293b',lineHeight:26}}>{current.q}</Text>
        </View>
        {opts.map((opt,i)=>{
          let bg='#fff',border='#e2e8f0',textC='#1e293b';
          if(sel){
            if(opt===current.a){bg='#f0fdf4';border='#16a34a';textC='#15803d';}
            else if(opt===sel&&opt!==current.a){bg='#fef2f2';border='#dc2626';textC='#b91c1c';}
          }
          return(
            <TouchableOpacity key={i} onPress={()=>pick(opt)} activeOpacity={0.8} disabled={!!sel}>
              <View style={{backgroundColor:bg,borderRadius:14,padding:16,marginBottom:10,borderWidth:2,borderColor:border,flexDirection:'row',alignItems:'center',gap:12}}>
                <View style={{width:32,height:32,borderRadius:16,backgroundColor:sel&&opt===current.a?'#16a34a':sel&&opt===sel?'#dc2626':color+'20',alignItems:'center',justifyContent:'center'}}>
                  <Text style={{fontWeight:'800',color:sel&&(opt===current.a||opt===sel)?'#fff':color}}>{String.fromCharCode(65+i)}</Text>
                </View>
                <Text style={{flex:1,fontSize:15,fontWeight:'600',color:textC,lineHeight:22}}>{opt}</Text>
                {sel&&opt===current.a&&<Text style={{fontSize:18}}>✅</Text>}
                {sel&&opt===sel&&opt!==current.a&&<Text style={{fontSize:18}}>❌</Text>}
              </View>
            </TouchableOpacity>
          );
        })}
      </ScrollView>
    </View>
  );
}
/* ══ YAZAR-ESER EŞLEŞTİRME EKRANI ═══════════════════ */
function MatchingGameScreen({setId,onBack,user,setUser}){
  const ms=MATCH_SETS.find(m=>m.id===setId);
  if(!ms)return null;

  const[pairs]=useState(()=>[...ms.pairs].sort(()=>Math.random()-0.5));
  const leftItems=useMemo(()=>[...pairs].sort(()=>Math.random()-0.5),[pairs]);
  const rightItems=useMemo(()=>[...pairs].sort(()=>Math.random()-0.5),[pairs]);

  const[leftSel,setLeftSel]=useState(null);
  const[matched,setMatched]=useState([]); // array of L values
  const[wrongPair,setWrongPair]=useState(null); // {L,R}
  const[errors,setErrors]=useState(0);
  const[done,setDone]=useState(false);
  const startTime=useRef(Date.now());
  const shakeAnim=useRef(new Animated.Value(0)).current;

  useEffect(()=>{
    if(matched.length>0&&matched.length===pairs.length)setDone(true);
  },[matched]);

  const shake=()=>{
    Animated.sequence([
      Animated.timing(shakeAnim,{toValue:8,duration:60,useNativeDriver:true}),
      Animated.timing(shakeAnim,{toValue:-8,duration:60,useNativeDriver:true}),
      Animated.timing(shakeAnim,{toValue:6,duration:60,useNativeDriver:true}),
      Animated.timing(shakeAnim,{toValue:0,duration:60,useNativeDriver:true}),
    ]).start();
  };

  const pickLeft=(item)=>{
    if(matched.includes(item.L))return;
    setLeftSel(item.L===leftSel?null:item.L);
    setWrongPair(null);
  };

  const pickRight=(item)=>{
    if(!leftSel)return;
    if(matched.find(L=>pairs.find(p=>p.L===L&&p.R===item.R)))return;
    const pair=pairs.find(p=>p.L===leftSel);
    if(pair&&pair.R===item.R){
      setMatched(m=>[...m,leftSel]);
      setLeftSel(null);
      setWrongPair(null);
    } else {
      setErrors(e=>e+1);
      setWrongPair({L:leftSel,R:item.R});
      shake();
      setTimeout(()=>{setWrongPair(null);setLeftSel(null);},900);
    }
  };

  const restart=()=>{
    setLeftSel(null);setMatched([]);setWrongPair(null);setErrors(0);setDone(false);
    startTime.current=Date.now();
  };

  const savePoints=async()=>{
    if(!user||!setUser)return;
    const elapsed=Math.round((Date.now()-startTime.current)/1000);
    const pts=Math.max(50,pairs.length*20-errors*10);
    try{const upd={...user,points:(user.points||0)+pts};const saved=await db.update(upd);setUser(saved);}catch(e){}
  };

  if(done){
    const pts=Math.max(50,pairs.length*20-errors*10);
    return(
      <View style={{flex:1,backgroundColor:'#fff',alignItems:'center',justifyContent:'center',padding:28}}>
        <Text style={{fontSize:64,marginBottom:10}}>🎉</Text>
        <Text style={{fontSize:26,fontWeight:'900',color:'#1e293b',marginBottom:6}}>Tebrikler!</Text>
        <Text style={{fontSize:15,color:'#64748b',marginBottom:20,textAlign:'center'}}>{ms.title}</Text>
        <View style={{backgroundColor:'#f0fdf4',borderRadius:16,paddingVertical:14,paddingHorizontal:32,marginBottom:24,borderWidth:2,borderColor:'#16a34a'}}>
          <Text style={{fontSize:28,fontWeight:'900',color:'#16a34a',textAlign:'center'}}>+{pts} puan</Text>
          <Text style={{fontSize:12,color:'#64748b',textAlign:'center',marginTop:2}}>{errors===0?'Mükemmel, sıfır hata! 🏆':errors+' hata yapıldı'}</Text>
        </View>
        <View style={{flexDirection:'row',gap:16,marginBottom:28}}>
          <View style={{alignItems:'center',backgroundColor:'#f8fafc',borderRadius:16,padding:16,minWidth:80,borderWidth:1,borderColor:'#e2e8f0'}}>
            <Text style={{fontSize:26,fontWeight:'900',color:'#16a34a'}}>{pairs.length}</Text>
            <Text style={{fontSize:11,color:'#64748b',fontWeight:'600'}}>EŞLEŞTİ</Text>
          </View>
          <View style={{alignItems:'center',backgroundColor:'#f8fafc',borderRadius:16,padding:16,minWidth:80,borderWidth:1,borderColor:'#e2e8f0'}}>
            <Text style={{fontSize:26,fontWeight:'900',color:'#dc2626'}}>{errors}</Text>
            <Text style={{fontSize:11,color:'#64748b',fontWeight:'600'}}>HATA</Text>
          </View>
        </View>
        <TouchableOpacity onPress={()=>{savePoints();restart();}} style={{backgroundColor:ms.color,borderRadius:14,paddingHorizontal:32,paddingVertical:14,marginBottom:12,width:'100%',alignItems:'center'}}>
          <Text style={{color:'#fff',fontWeight:'800',fontSize:16}}>Tekrar Oyna</Text>
        </TouchableOpacity>
        <TouchableOpacity onPress={()=>{savePoints();onBack();}} style={{width:'100%',alignItems:'center',paddingVertical:12}}>
          <Text style={{color:'#64748b',fontWeight:'600',fontSize:14}}>← Geri Dön</Text>
        </TouchableOpacity>
      </View>
    );
  }

  // Progress dots
  const progress=matched.length/pairs.length;

  return(
    <View style={{flex:1,backgroundColor:'#fff'}}>
      {/* Header */}
      <View style={{paddingTop:TOP_INSET+12,paddingBottom:16,paddingHorizontal:16,backgroundColor:'#fff',borderBottomWidth:1,borderBottomColor:'#f1f5f9'}}>
        <View style={{flexDirection:'row',alignItems:'center',gap:12,marginBottom:14}}>
          <TouchableOpacity onPress={onBack} style={{width:36,height:36,borderRadius:18,backgroundColor:'#f1f5f9',alignItems:'center',justifyContent:'center'}}>
            <Text style={{fontSize:16,color:'#475569',fontWeight:'700'}}>←</Text>
          </TouchableOpacity>
          <View style={{flex:1}}>
            <Text style={{fontSize:17,fontWeight:'900',color:'#1e293b'}}>{ms.emoji} {ms.title}</Text>
            <Text style={{fontSize:12,color:'#94a3b8',marginTop:1}}>{matched.length}/{pairs.length} eşleşti · {errors} hata</Text>
          </View>
        </View>
        {/* Progress bar */}
        <View style={{height:6,backgroundColor:'#f1f5f9',borderRadius:3}}>
          <View style={{height:6,backgroundColor:ms.color,borderRadius:3,width:(progress*100)+'%'}}/>
        </View>
      </View>



      <Animated.View style={{flex:1,transform:[{translateX:shakeAnim}]}}>
        <ScrollView contentContainerStyle={{padding:14,paddingBottom:30}}>
          <View style={{flexDirection:'row',gap:10}}>
            {/* Sol — Yazarlar / Kavramlar */}
            <View style={{flex:1}}>
              <View style={{flexDirection:'row',alignItems:'center',gap:6,marginBottom:10}}>
                <View style={{width:6,height:6,borderRadius:3,backgroundColor:ms.color}}/>
                <Text style={{fontSize:11,fontWeight:'800',color:'#94a3b8',letterSpacing:0.5}}>
                  {ms.title.includes('Roman')||ms.title.includes('Şiir')?'ESER':'YAZAR / KAVRAM'}
                </Text>
              </View>
              {leftItems.map((item,i)=>{
                const isMatched=matched.includes(item.L);
                const isSel=leftSel===item.L;
                const isWrong=wrongPair&&wrongPair.L===item.L;
                return(
                  <TouchableOpacity key={i} onPress={()=>pickLeft(item)} disabled={isMatched} activeOpacity={0.78}>
                    <View style={{
                      borderRadius:14,padding:13,marginBottom:8,borderWidth:2,
                      backgroundColor:isMatched?'#f0fdf4':isSel?ms.color:isWrong?'#fef2f2':'#f8fafc',
                      borderColor:isMatched?'#bbf7d0':isSel?ms.color:isWrong?'#fca5a5':'#e2e8f0',
                    }}>
                      <Text style={{
                        fontSize:12,fontWeight:'700',lineHeight:18,
                        color:isMatched?'#16a34a':isSel?'#fff':isWrong?'#b91c1c':'#1e293b',
                        textDecorationLine:isMatched?'line-through':'none',
                      }}>{item.L}</Text>
                      {isMatched&&<Text style={{fontSize:14,marginTop:2}}>✅</Text>}
                    </View>
                  </TouchableOpacity>
                );
              })}
            </View>

            {/* Sağ — Eserler / Eşlenikler */}
            <View style={{flex:1}}>
              <View style={{flexDirection:'row',alignItems:'center',gap:6,marginBottom:10}}>
                <View style={{width:6,height:6,borderRadius:3,backgroundColor:'#94a3b8'}}/>
                <Text style={{fontSize:11,fontWeight:'800',color:'#94a3b8',letterSpacing:0.5}}>
                  {ms.title.includes('Roman')||ms.title.includes('Şiir')?'YAZAR':'ESER / EŞLENİK'}
                </Text>
              </View>
              {rightItems.map((item,i)=>{
                const isMatched=!!matched.find(L=>pairs.find(p=>p.L===L&&p.R===item.R));
                const isWrong=wrongPair&&wrongPair.R===item.R;
                return(
                  <TouchableOpacity key={i} onPress={()=>pickRight(item)} disabled={isMatched} activeOpacity={0.78}>
                    <View style={{
                      borderRadius:14,padding:13,marginBottom:8,borderWidth:2,
                      backgroundColor:isMatched?'#f0fdf4':isWrong?'#fef2f2':'#f8fafc',
                      borderColor:isMatched?'#bbf7d0':isWrong?'#fca5a5':leftSel?ms.color+'50':'#e2e8f0',
                    }}>
                      <Text style={{
                        fontSize:12,fontWeight:'700',lineHeight:18,
                        color:isMatched?'#16a34a':isWrong?'#b91c1c':'#1e293b',
                        textDecorationLine:isMatched?'line-through':'none',
                      }}>{item.R}</Text>
                      {isMatched&&<Text style={{fontSize:14,marginTop:2}}>✅</Text>}
                      {isWrong&&<Text style={{fontSize:14,marginTop:2}}>❌</Text>}
                    </View>
                  </TouchableOpacity>
                );
              })}
            </View>
          </View>
        </ScrollView>
      </Animated.View>
    </View>
  );
}
/* ══ YAZIM OYUNU EKRANI ══════════════════════════════ */
function WritingGameScreen({gameId,onBack,user,setUser}){
  const wg=WRITING_GAMES.find(g=>g.id===gameId);
  if(!wg)return null;
  const questions=useMemo(()=>[...wg.q].map(q=>{
    // Rastgele üst/alt kutusunu çevir — doğru cevap her zaman tahmin edilemesin
    if(Math.random()<0.5){
      return {...q,ust:q.alt,alt:q.ust,dogru:q.dogru==='ust'?'alt':'ust'};
    }
    return q;
  }).sort(()=>Math.random()-0.5),[]);
  const[idx,setIdx]=useState(0);
  const[result,setResult]=useState(null); // 'correct'|'wrong'
  const[score,setScore]=useState(0);
  const[wrong,setWrong]=useState(0);
  const[done,setDone]=useState(false);
  const[explanation,setExplanation]=useState('');
  const startTime=useRef(Date.now());
  const fadeAnim=useRef(new Animated.Value(1)).current;
  const scaleAnim=useRef(new Animated.Value(1)).current;

  const current=questions[idx];

  const advance=useCallback(()=>{
    Animated.sequence([
      Animated.timing(fadeAnim,{toValue:0,duration:250,useNativeDriver:true}),
    ]).start(()=>{
      if(idx+1>=questions.length){setDone(true);}
      else{setIdx(i=>i+1);setResult(null);setExplanation('');}
      Animated.timing(fadeAnim,{toValue:1,duration:250,useNativeDriver:true}).start();
    });
  },[idx,questions.length,fadeAnim]);

  const pick=(choice)=>{
    if(result)return;
    const correct=choice===current.dogru;
    setResult(correct?'correct':'wrong');
    setExplanation(current.neden);
    if(correct){setScore(s=>s+1);}else{setWrong(w=>w+1);}
    // Pulse animation
    Animated.sequence([
      Animated.timing(scaleAnim,{toValue:1.04,duration:120,useNativeDriver:true}),
      Animated.timing(scaleAnim,{toValue:1,duration:120,useNativeDriver:true}),
    ]).start();
    setTimeout(advance,1400);
  };

  const restart=()=>{setIdx(0);setResult(null);setExplanation('');setScore(0);setWrong(0);setDone(false);startTime.current=Date.now();};

  const savePoints=async()=>{
    if(!user||!setUser)return;
    const elapsed=Math.round((Date.now()-startTime.current)/1000);
    const pts=score*10+Math.max(0,(questions.length*25-elapsed))*2;
    try{const upd={...user,points:(user.points||0)+pts};const saved=await db.update(upd);setUser(saved);}catch(e){}
  };

  if(done){
    const pct=Math.round(score/questions.length*100);
    const elapsed=Math.round((Date.now()-startTime.current)/1000);
    const earnedPts=score*10+Math.max(0,(questions.length*25-elapsed))*2;
    return(
      <View style={{flex:1,backgroundColor:'#fff',alignItems:'center',justifyContent:'center',padding:24}}>
        <View style={{width:110,height:110,borderRadius:55,backgroundColor:wg.color,alignItems:'center',justifyContent:'center',marginBottom:20,shadowColor:wg.color,shadowOpacity:0.4,shadowRadius:20}}>
          <Text style={{fontSize:38}}>{pct>=80?'🏆':pct>=60?'👍':'💪'}</Text>
        </View>
        <Text style={{fontSize:24,fontWeight:'900',color:'#1e293b',marginBottom:4}}>Harika!</Text>
        <Text style={{fontSize:15,color:'#64748b',marginBottom:20}}>{wg.title}</Text>
        <View style={{backgroundColor:'#f0fdf4',borderRadius:16,paddingVertical:12,paddingHorizontal:28,marginBottom:24,borderWidth:2,borderColor:'#16a34a'}}>
          <Text style={{fontSize:28,fontWeight:'900',color:'#16a34a',textAlign:'center'}}>+{earnedPts} puan</Text>
          <Text style={{fontSize:12,color:'#64748b',textAlign:'center',marginTop:2}}>{score}×10 doğru + hız bonusu</Text>
        </View>
        <View style={{flexDirection:'row',gap:14,marginBottom:28}}>
          <View style={{alignItems:'center',backgroundColor:'#f8fafc',borderRadius:16,padding:16,minWidth:76,borderWidth:1,borderColor:'#e2e8f0'}}>
            <Text style={{fontSize:26,fontWeight:'900',color:'#16a34a'}}>{score}</Text>
            <Text style={{fontSize:11,color:'#64748b',fontWeight:'600'}}>DOĞRU</Text>
          </View>
          <View style={{alignItems:'center',backgroundColor:'#f8fafc',borderRadius:16,padding:16,minWidth:76,borderWidth:1,borderColor:'#e2e8f0'}}>
            <Text style={{fontSize:26,fontWeight:'900',color:'#dc2626'}}>{wrong}</Text>
            <Text style={{fontSize:11,color:'#64748b',fontWeight:'600'}}>YANLIŞ</Text>
          </View>
          <View style={{alignItems:'center',backgroundColor:'#f8fafc',borderRadius:16,padding:16,minWidth:76,borderWidth:1,borderColor:'#e2e8f0'}}>
            <Text style={{fontSize:26,fontWeight:'900',color:wg.color}}>{pct}%</Text>
            <Text style={{fontSize:11,color:'#64748b',fontWeight:'600'}}>BAŞARI</Text>
          </View>
        </View>
        <TouchableOpacity onPress={()=>{savePoints();restart();}} style={{backgroundColor:wg.color,borderRadius:14,paddingHorizontal:32,paddingVertical:14,marginBottom:12,width:'100%',alignItems:'center'}}>
          <Text style={{color:'#fff',fontWeight:'800',fontSize:16}}>Tekrar Oyna</Text>
        </TouchableOpacity>
        <TouchableOpacity onPress={()=>{savePoints();onBack();}} style={{width:'100%',alignItems:'center',paddingVertical:12}}>
          <Text style={{color:'#64748b',fontWeight:'600',fontSize:14}}>← Geri Dön</Text>
        </TouchableOpacity>
      </View>
    );
  }

  if(!current)return null;

  const ustCorrect=result&&current.dogru==='ust';
  const altCorrect=result&&current.dogru==='alt';
  const ustWrong=result&&current.dogru!=='ust';
  const altWrong=result&&current.dogru!=='alt';

  return(
    <View style={{flex:1,backgroundColor:'#fff'}}>
      {/* Header */}
      <View style={{backgroundColor:wg.color,paddingTop:TOP_INSET+12,paddingBottom:20,paddingHorizontal:16}}>
        <View style={{flexDirection:'row',alignItems:'center',gap:12,marginBottom:14}}>
          <TouchableOpacity onPress={onBack} style={{width:36,height:36,borderRadius:18,backgroundColor:'rgba(255,255,255,0.2)',alignItems:'center',justifyContent:'center'}}>
            <Text style={{color:'#fff',fontSize:18,fontWeight:'700'}}>←</Text>
          </TouchableOpacity>
          <View style={{flex:1}}>
            <Text style={{color:'#fff',fontSize:16,fontWeight:'800'}}>{wg.emoji} {wg.title}</Text>
            <Text style={{color:'rgba(255,255,255,0.75)',fontSize:12,marginTop:1}}>Hangisi doğru yazılmış?</Text>
          </View>
          <View style={{backgroundColor:'rgba(255,255,255,0.2)',borderRadius:10,paddingHorizontal:10,paddingVertical:4}}>
            <Text style={{color:'#fff',fontSize:13,fontWeight:'700'}}>{idx+1}/{questions.length}</Text>
          </View>
        </View>
        <View style={{height:5,backgroundColor:'rgba(255,255,255,0.25)',borderRadius:3}}>
          <View style={{height:5,backgroundColor:'#fff',borderRadius:3,width:(idx/questions.length*100)+'%'}}/>
        </View>
      </View>

      {/* Skor */}
      <View style={{flexDirection:'row',justifyContent:'center',gap:24,paddingVertical:14}}>
        <View style={{flexDirection:'row',alignItems:'center',gap:6}}>
          <Text style={{fontSize:18}}>✅</Text>
          <Text style={{fontSize:18,fontWeight:'900',color:'#16a34a'}}>{score}</Text>
        </View>
        <View style={{flexDirection:'row',alignItems:'center',gap:6}}>
          <Text style={{fontSize:18}}>❌</Text>
          <Text style={{fontSize:18,fontWeight:'900',color:'#dc2626'}}>{wrong}</Text>
        </View>
      </View>

      {/* VS Alanı */}
      <Animated.View style={{flex:1,paddingHorizontal:20,justifyContent:'center',opacity:fadeAnim,transform:[{scale:scaleAnim}]}}>
        {/* Üst Kutu */}
        <TouchableOpacity onPress={()=>pick('ust')} activeOpacity={0.85} disabled={!!result}>
          <View style={{
            borderRadius:20,padding:28,alignItems:'center',justifyContent:'center',
            minHeight:110,marginBottom:12,borderWidth:3,
            backgroundColor: ustCorrect?'#f0fdf4':ustWrong?'#fef2f2':'#f8fafc',
            borderColor: ustCorrect?'#16a34a':ustWrong?'#dc2626':wg.color+'40',
          }}>
            <Text style={{fontSize:32,fontWeight:'900',color: ustCorrect?'#15803d':ustWrong?'#b91c1c':'#1e293b',letterSpacing:1,textAlign:'center'}}>
              {current.ust}
            </Text>
            {ustCorrect&&<Text style={{fontSize:28,marginTop:6}}>✅</Text>}
            {ustWrong&&<Text style={{fontSize:28,marginTop:6}}>❌</Text>}
          </View>
        </TouchableOpacity>

        {/* VS Rozeti */}
        <View style={{alignItems:'center',marginBottom:12}}>
          <View style={{width:52,height:52,borderRadius:26,backgroundColor:wg.color,alignItems:'center',justifyContent:'center',shadowColor:wg.color,shadowOpacity:0.5,shadowRadius:10,elevation:6}}>
            <Text style={{fontSize:14,fontWeight:'900',color:'#fff'}}>VS</Text>
          </View>
        </View>

        {/* Alt Kutu */}
        <TouchableOpacity onPress={()=>pick('alt')} activeOpacity={0.85} disabled={!!result}>
          <View style={{
            borderRadius:20,padding:28,alignItems:'center',justifyContent:'center',
            minHeight:110,borderWidth:3,
            backgroundColor: altCorrect?'#f0fdf4':altWrong?'#fef2f2':'#f8fafc',
            borderColor: altCorrect?'#16a34a':altWrong?'#dc2626':wg.color+'40',
          }}>
            <Text style={{fontSize:32,fontWeight:'900',color: altCorrect?'#15803d':altWrong?'#b91c1c':'#1e293b',letterSpacing:1,textAlign:'center'}}>
              {current.alt}
            </Text>
            {altCorrect&&<Text style={{fontSize:28,marginTop:6}}>✅</Text>}
            {altWrong&&<Text style={{fontSize:28,marginTop:6}}>❌</Text>}
          </View>
        </TouchableOpacity>

        {/* Açıklama */}
        {result&&(
          <View style={{marginTop:16,backgroundColor:result==='correct'?'#f0fdf4':'#fef2f2',borderRadius:14,padding:14,borderLeftWidth:4,borderLeftColor:result==='correct'?'#16a34a':'#dc2626'}}>
            <Text style={{fontSize:13,color:result==='correct'?'#15803d':'#b91c1c',fontWeight:'600',lineHeight:20}}>
              {result==='correct'?'✅ ':'❌ '}{explanation}
            </Text>
          </View>
        )}
      </Animated.View>
    </View>
  );
}

function GameScreen({type,onBack,user,setUser,hardMode=false}){
  const cfg=GC[type];
  // Ban kontrolü — oyun açılırken kontrol et
  useEffect(()=>{
    const checkBan=async()=>{
      const fresh=await db.byId(user.id);
      const banned=fresh&&fresh.banned&&fresh.bannedUntil&&new Date(fresh.bannedUntil)>new Date();
      if(banned){
        const days=daysLeft(fresh.bannedUntil);
        Alert.alert('🚫 Hesabın Banlandı',
          `Oyun oynama yetkin ${days} gün boyunca kısıtlandı.\nBan bitiş: ${new Date(fresh.bannedUntil).toLocaleDateString('tr-TR')}`,
          [{text:'Geri Dön',onPress:onBack}]);
      }
    };
    checkBan();
  },[]);
  const timeMultiplier=hardMode?0.5:1;
  const ptsMultiplier=hardMode?3:1;
  const baseTime=Math.round(cfg.t*(hardMode?0.5:1));
  const[qs]=useState(()=>pickQ(cfg.bank,cfg.n));
  const[favs,setFavs]=useState([]);
  useEffect(()=>{getFavorites(user.id).then(setFavs);},[]);
  const toggleFav=async()=>{
    const q=qs[idx];const isFav=favs.find(f=>f.q===q.q);
    if(isFav){await removeFavorite(user.id,q);setFavs(f=>f.filter(x=>x.q!==q.q));}
    else{await addFavorite(user.id,q);setFavs(f=>[...f,q]);}
  };
  const[idx,setIdx]=useState(0);
  const[sel,setSel]=useState(null);
  const[score,setScore]=useState(0);
  const[corr,setCorr]=useState(0);
  const[time,setTime]=useState(baseTime);
  const[done,setDone]=useState(false);
  const tmr=useRef(null);
  const goNext=useCallback(()=>{
    clearInterval(tmr.current);
    if(idx>=qs.length-1){setDone(true);return;}
    setIdx(i=>i+1);setSel(null);setTime(baseTime);
  },[idx,qs.length,cfg.t]);
  useEffect(()=>{
    if(done)return;
    tmr.current=setInterval(()=>setTime(t=>{if(t<=1){clearInterval(tmr.current);goNext();return cfg.t;}return t-1;}),1000);
    return()=>clearInterval(tmr.current);
  },[idx,done,goNext]);
  const pick=(ch,ok)=>{
    if(sel!==null)return;setSel(ch);
    if(ok){const pts=Math.max(10,time*3)*ptsMultiplier;setScore(s=>s+pts);setCorr(c=>c+1);}
    setTimeout(goNext,700);
  };
  const save=async()=>{
    const upd={...user,
      points:(user.points||0)+score,
      gamesPlayed:(user.gamesPlayed||0)+1,
      [cfg.f]:(user[cfg.f]||0)+score,
      [cfg.gf]:(user[cfg.gf]||0)+1,
    };
    await updateWeeklyStats(user.id,{games:1,pts:score,correct:corr});
    const saved=await db.update(upd);setUser(saved);
  };
  if(done)return<GameResult score={score} correct={corr} total={qs.length} onFinish={save} onBack={onBack} color={cfg.c} emoji={cfg.title}/>;
  const q=qs[idx],bc=time>cfg.t*.5?C.primary:time>cfg.t*.25?C.amber:C.red,lbs=['A','B','C','D'];
  const isFav=favs.find(f=>f.q===qs[idx]?.q);
  return(
    <SafeAreaView style={{flex:1,backgroundColor:C.bg,paddingTop:TOP_INSET}}>
      <Hdr title={cfg.title+(hardMode?' 🔥':'')} subtitle={`${idx+1}/${qs.length} · ${score} pt`} onBack={onBack}
        right={<View style={{backgroundColor:bc+'22',borderRadius:8,paddingHorizontal:10,paddingVertical:4}}>
          <Text style={{fontWeight:'800',color:bc,fontSize:16}}>{time}s</Text></View>}/>
      <View style={{height:4,backgroundColor:C.border,marginHorizontal:16,borderRadius:2,marginTop:8}}>
        <View style={{height:'100%',width:`${(idx/qs.length)*100}%`,backgroundColor:cfg.c,borderRadius:2}}/>
      </View>
      <ScrollView style={{flex:1}} contentContainerStyle={{padding:16}}>
        {q.img&&<Card style={{alignItems:'center',padding:8,marginBottom:12}}>
          <Image source={{uri:q.img}} style={{width:SW-80,height:100,borderRadius:8}} resizeMode="contain"/></Card>}
        <Card style={{padding:20,marginBottom:16,backgroundColor:cfg.c+'14',borderColor:cfg.c+'44'}}>
          <Text style={{fontSize:17,fontWeight:'700',color:C.text,textAlign:'center',lineHeight:26}}>{q.q}</Text>
        </Card>
        {q.choices.map((ch,ci)=>{
          let bg=C.card,brd=C.border,tc=C.text,fw='500';
          if(sel!==null){if(ch===q.ans){bg='#f0fdf4';brd=C.primary;tc=C.primary;fw='700';}else if(ch===sel){bg='#fef2f2';brd=C.red;tc=C.red;fw='700';}}
          return(<TouchableOpacity key={ci} onPress={()=>pick(ch,ch===q.ans)}
            style={{flexDirection:'row',alignItems:'center',padding:13,borderRadius:12,backgroundColor:bg,borderWidth:2,borderColor:brd,gap:10,marginBottom:8}}>
            <View style={{width:26,height:26,borderRadius:13,backgroundColor:sel===null?cfg.c+'22':ch===q.ans?'#bbf7d0':ch===sel?'#fecaca':C.bg,alignItems:'center',justifyContent:'center'}}>
              <Text style={{fontWeight:'700',fontSize:11,color:sel===null?cfg.c:ch===q.ans?C.primary:ch===sel?C.red:C.light}}>{lbs[ci]}</Text>
            </View>
            <Text style={{flex:1,fontSize:14,color:tc,fontWeight:fw}}>{ch}</Text>
            {sel!==null&&(ch===q.ans?<Text>✓</Text>:ch===sel?<Text>✗</Text>:null)}
          </TouchableOpacity>);
        })}
      </ScrollView>
    </SafeAreaView>
  );
}
function GameResult({score,correct,total,onFinish,onBack,color,emoji}){
  const[saved,setSaved]=useState(false);
  const pct=Math.round((correct/total)*100);
  const msg=pct>=80?'Mükemmel! 🔥':pct>=60?'İyi İş! 👏':pct>=40?'Fena Değil 👍':'Daha Çok Çalış 💪';
  const finish=async()=>{if(!saved){setSaved(true);await onFinish();}onBack();};
  return(
    <SafeAreaView style={{flex:1,backgroundColor:C.bg,paddingTop:TOP_INSET}}>
      <View style={{flex:1,justifyContent:'center',padding:24,alignItems:'center'}}>
        <Text style={{fontSize:64,marginBottom:12}}>{emoji.split(' ')[0]}</Text>
        <Text style={{fontSize:26,fontWeight:'900',color:C.text,marginBottom:4}}>Oyun Bitti!</Text>
        <Text style={{fontSize:18,color,fontWeight:'700',marginBottom:24}}>{msg}</Text>
        <Card style={{width:'100%',marginBottom:20}}>
          {[{l:'Kazanılan Puan',v:'+'+score,c:color},{l:'Doğru',v:`${correct}/${total}`,c:C.primary},{l:'Başarı',v:`%${pct}`,c:pct>=60?C.primary:C.red}].map(item=>(
            <View key={item.l} style={{flexDirection:'row',justifyContent:'space-between',paddingVertical:10,borderBottomWidth:1,borderBottomColor:C.border}}>
              <Text style={{color:C.mid,fontSize:14}}>{item.l}</Text>
              <Text style={{fontWeight:'800',fontSize:16,color:item.c}}>{item.v}</Text>
            </View>
          ))}
        </Card>
        <Btn label="Bitir & Puanı Kaydet" onPress={finish} color={color} style={{width:'100%'}}/>
      </View>
    </SafeAreaView>
  );
}


/* ══ LİDERLİK TABLOSU ═══════════════════════════════ */
function BoardTab({user,go}){
  const[users,setUsers]=useState([]);
  const[loading,setL]=useState(true);
  const load=async()=>{
    setL(true);
    const all=await db.all();
    const merged=all.map(u=>u.id===user.id?{...u,...user}:u);
    setUsers(merged.sort((a,b)=>(b.points||0)-(a.points||0)));
    setL(false);
  };
  useEffect(()=>{load();},[user.avatar,user.name,user.points]);
  const medals=['🥇','🥈','🥉'];
  const myRank=users.findIndex(u=>u.id===user.id)+1;
  return(
    <View style={{flex:1}}>
      <Hdr title="🏆 Liderlik Tablosu" subtitle={`${users.length} oyuncu yarışıyor`}
        right={<TouchableOpacity onPress={load} style={{padding:8}}><Text style={{fontSize:20}}>🔄</Text></TouchableOpacity>}/>
      {/* Kendi puanı */}
      {myRank>0&&<View style={{margin:12,padding:14,backgroundColor:'#f0fdf4',borderRadius:12,borderWidth:2,borderColor:C.primary,flexDirection:'row',alignItems:'center',gap:12}}>
        <Avatar user={user} size={40}/>
        <View style={{flex:1}}>
          <Text style={{fontSize:13,color:C.primary,fontWeight:'700'}}>SENİN PUANIN</Text>
          <Text style={{fontSize:18,fontWeight:'900',color:C.text}}>{user.points||0} puan</Text>
        </View>
        <View style={{alignItems:'center'}}>
          <Text style={{fontSize:22,fontWeight:'900',color:C.primary}}>#{myRank}</Text>
          <Text style={{fontSize:9,color:C.light}}>sıra</Text>
        </View>
      </View>}
      {loading?<ActivityIndicator color={C.primary} style={{marginTop:40}}/>:
       <FlatList data={users} keyExtractor={u=>u.id} contentContainerStyle={{padding:12,gap:8}}
         renderItem={({item,index})=>{
           const rk=getRank(item.points||0),isMe=item.id===user.id;
           return(
             <TouchableOpacity onPress={()=>go('viewProfile',item.id)} activeOpacity={0.85}>
               <Card style={{flexDirection:'row',alignItems:'center',gap:10,borderWidth:isMe?2:1,borderColor:isMe?C.primary:C.border}}>
                 {/* Sıra */}
                 <Text style={{fontSize:index<3?24:16,width:32,textAlign:'center',fontWeight:'700',color:index<3?C.amber:C.light}}>
                   {index<3?medals[index]:index+1}
                 </Text>
                 {/* Avatar — resimli */}
                 <Avatar user={item} size={40}/>
                 {/* İsim + rank */}
                 <View style={{flex:1}}>
                   <View style={{flexDirection:'row',alignItems:'center',gap:6}}>
                     <Text style={{fontSize:14,fontWeight:'700',color:C.text}} numberOfLines={1}>{item.name}</Text>
                     {isMe&&<View style={{backgroundColor:C.primary,borderRadius:4,paddingHorizontal:5,paddingVertical:1}}>
                       <Text style={{color:'#fff',fontSize:8,fontWeight:'700'}}>SEN</Text></View>}
                   </View>
                   <RankBadge pts={item.points||0}/>
                 </View>
                 {/* Puan */}
                 <View style={{alignItems:'flex-end'}}>
                   <Text style={{fontSize:15,fontWeight:'800',color:rk.c}}>{item.points||0}</Text>
                   <Text style={{fontSize:9,color:C.light}}>puan</Text>
                 </View>
               </Card>
             </TouchableOpacity>
           );
         }}
       />}
    </View>
  );
}

/* ══ BAŞARIMLAR ══════════════════════════════════════ */
function AchsTab({user}){
  const earned=new Set(ACHIEVEMENTS.filter(a=>a.check(user)).map(a=>a.id));
  const total=ACHIEVEMENTS.length, done=earned.size;
  const[filter,setFilter]=useState('all');
  const filtered=ACHIEVEMENTS.filter(a=>filter==='all'?true:filter==='done'?earned.has(a.id):!earned.has(a.id));
  return(
    <View style={{flex:1}}>
      <Hdr title="Başarımlar" subtitle="İlerlemeni ve kilometre taşlarını takip et"/>
      <View style={{paddingHorizontal:16,paddingTop:8,paddingBottom:4}}>
        <TouchableOpacity style={{backgroundColor:C.primary,borderRadius:20,paddingHorizontal:16,paddingVertical:8,alignSelf:'flex-start'}}>
          <Text style={{color:'#fff',fontWeight:'700',fontSize:13}}>{done} / {total} TAMAMLANDI</Text>
        </TouchableOpacity>
        {/* İlerleme çubuğu */}
        <View style={{backgroundColor:C.border,borderRadius:4,height:8,marginTop:10,overflow:'hidden'}}>
          <View style={{width:`${Math.round((done/total)*100)}%`,height:'100%',backgroundColor:C.primary,borderRadius:4}}/>
        </View>
      </View>
      {/* Filtreler */}
      <View style={{flexDirection:'row',gap:8,paddingHorizontal:16,paddingVertical:8}}>
        {[['all','Tümü'],['done','Kazanılanlar'],['locked','Kilitli']].map(([k,l])=>(
          <TouchableOpacity key={k} onPress={()=>setFilter(k)}
            style={{paddingHorizontal:14,paddingVertical:7,borderRadius:20,backgroundColor:filter===k?C.primary:C.card,borderWidth:1,borderColor:filter===k?C.primary:C.border}}>
            <Text style={{fontSize:12,fontWeight:'600',color:filter===k?'#fff':C.mid}}>{l}</Text>
          </TouchableOpacity>
        ))}
      </View>
      <ScrollView contentContainerStyle={{padding:12,gap:10}}>
        {filtered.map(a=>{
          const got=earned.has(a.id);
          return(
            <Card key={a.id} style={{flexDirection:'row',alignItems:'center',gap:14,opacity:got?1:0.55}}>
              <View style={{width:52,height:52,borderRadius:26,backgroundColor:got?C.primary+'22':C.border,alignItems:'center',justifyContent:'center'}}>
                <Text style={{fontSize:26}}>{a.emoji}</Text>
              </View>
              <View style={{flex:1}}>
                <View style={{flexDirection:'row',alignItems:'center',gap:6}}>
                  <Text style={{fontSize:14,fontWeight:'700',color:C.text}}>{a.title}</Text>
                  {!got&&<Text style={{fontSize:14}}>🔒</Text>}
                </View>
                <Text style={{fontSize:12,color:C.mid,marginTop:2}}>{a.desc}</Text>
                {/* İlerleme çubuğu: kazanılanlar için dolu */}
                <View style={{backgroundColor:C.border,borderRadius:3,height:6,marginTop:6,overflow:'hidden'}}>
                  <View style={{width:got?'100%':'0%',height:'100%',backgroundColor:C.primary,borderRadius:3}}/>
                </View>
              </View>
              {got&&<Text style={{fontSize:22}}>✅</Text>}
            </Card>
          );
        })}
      </ScrollView>
    </View>
  );
}

/* ══ AYARLAR ════════════════════════════════════════ */
/* ── Yardım/Koşullar/Gizlilik için modal bileşeni ── */
function InfoModal({visible,title,onClose,children}){
  return(
    <Modal visible={visible} animationType="slide" presentationStyle="pageSheet" onRequestClose={onClose}>
      <SafeAreaView style={{flex:1,backgroundColor:C.bg,paddingTop:TOP_INSET}}>
        <View style={{flexDirection:'row',alignItems:'center',padding:16,borderBottomWidth:1,borderBottomColor:C.border,backgroundColor:C.card}}>
          <Text style={{flex:1,fontSize:17,fontWeight:'800',color:C.text}}>{title}</Text>
          <TouchableOpacity onPress={onClose} style={{width:32,height:32,borderRadius:16,backgroundColor:C.bg,alignItems:'center',justifyContent:'center'}}>
            <Text style={{fontSize:18,color:C.mid}}>✕</Text>
          </TouchableOpacity>
        </View>
        <ScrollView contentContainerStyle={{padding:20}}>{children}</ScrollView>
      </SafeAreaView>
    </Modal>
  );
}

function SettingsTab({user,setUser,onLogout,go}){
  // Düzenleme alanları
  const[editName,setEN]=useState(false);
  const[editBio,setEB]=useState(false);
  const[editEmail,setEE]=useState(false);
  const[editPass,setEP]=useState(false);
  const[name,setName]=useState(user.name);
  const[bio,setBio]=useState(user.bio||'');
  const[newEmail,setNewEmail]=useState('');
  const[emailPass,setEmailPass]=useState('');
  const[oldPass,setOldPass]=useState('');
  const[newPass,setNewPass]=useState('');
  const[newPass2,setNewPass2]=useState('');
  const[saving,setSaving]=useState(false);
  // Sınav tercihi
  const[sinav,setSinav]=useState(user.sinav||'TYT+AYT');
  const[editSinav,setES]=useState(false);
  // Bildirimler
  const[notif,setNotif]=useState(user.notifications!==false);
  // Modaller
  const[modal,setModal]=useState(null); // 'help'|'terms'|'privacy'

  const pickPhoto=async()=>{
    try{
      const{status}=await ImagePicker.requestMediaLibraryPermissionsAsync();
      if(status!=='granted'){Alert.alert('İzin gerekli','Galeri erişimine izin verin.');return;}
      const r=await ImagePicker.launchImageLibraryAsync({
        mediaTypes:ImagePicker.MediaTypeOptions.Images,allowsEditing:true,aspect:[1,1],quality:0.15,base64:true
      });
      if(!r.canceled&&r.assets[0].base64){
        setSaving(true);
        const uri='data:image/jpeg;base64,'+r.assets[0].base64;
        const saved=await db.update({...user,avatar:uri});
        setUser(saved);setSaving(false);
        Alert.alert('✓','Fotoğraf güncellendi');
      }
    }catch{Alert.alert('Hata','Fotoğraf seçilemedi.');}
  };

  const saveName=async()=>{
    if(!name.trim()){Alert.alert('Hata','İsim boş olamaz');return;}
    setSaving(true);
    const saved=await db.update({...user,name:name.trim()});
    setUser(saved);setSaving(false);setEN(false);
    Alert.alert('✓','İsim güncellendi');
  };

  const saveBio=async()=>{
    setSaving(true);
    const saved=await db.update({...user,bio:bio.trim()});
    setUser(saved);setSaving(false);setEB(false);
    Alert.alert('✓','Biyografi güncellendi');
  };

  const saveEmail=async()=>{
    const e=newEmail.toLowerCase().trim();
    if(!e||!emailPass){Alert.alert('Hata','Tüm alanları doldurun');return;}
    if(!e.includes('@')){Alert.alert('Hata','Geçerli bir e-posta girin');return;}
    if(emailPass!==user.password){Alert.alert('Hata','Mevcut şifreniz hatalı');return;}
    // e-posta başka kullanıcıda var mı?
    setSaving(true);
    const ex=await db.byEmail(e);
    if(ex&&ex.id!==user.id){Alert.alert('Hata','Bu e-posta zaten kullanılıyor');setSaving(false);return;}
    const saved=await db.update({...user,email:e});
    setUser(saved);setSaving(false);setEE(false);setNewEmail('');setEmailPass('');
    Alert.alert('✓','E-posta güncellendi');
  };

  const savePass=async()=>{
    if(!oldPass||!newPass||!newPass2){Alert.alert('Hata','Tüm alanları doldurun');return;}
    if(oldPass!==user.password){Alert.alert('Hata','Mevcut şifreniz hatalı');return;}
    if(newPass.length<6){Alert.alert('Hata','Yeni şifre min. 6 karakter');return;}
    if(newPass!==newPass2){Alert.alert('Hata','Yeni şifreler eşleşmiyor');return;}
    setSaving(true);
    const saved=await db.update({...user,password:newPass});
    setUser(saved);setSaving(false);setEP(false);setOldPass('');setNewPass('');setNewPass2('');
    Alert.alert('✓','Şifre güncellendi');
  };

  const saveSinav=async(val)=>{
    setSinav(val);setES(false);
    const saved=await db.update({...user,sinav:val});
    setUser(saved);
  };

  const toggleNotif=async()=>{
    const val=!notif;setNotif(val);
    const saved=await db.update({...user,notifications:val});
    setUser(saved);
  };

  const confirmDelete=()=>{
    Alert.alert('Hesabı Sil','Tüm verilerin kalıcı olarak silinecek. Emin misin?',
      [{text:'İptal',style:'cancel'},{text:'Sil',style:'destructive',onPress:async()=>{
        try{
          const d=await db._r();
          d.users=d.users.filter(u=>u.id!==user.id);
          d.messages=d.messages.filter(m=>m.from!==user.id&&m.to!==user.id);
          await db._w(d);
        }catch{}
        await db.logout();onLogout();
      }}]
    );
  };

  /* ── Satır bileşeni ── */
  const Row=({emoji,title,sub,onPress,right,danger=false})=>(
    <TouchableOpacity onPress={onPress||undefined} activeOpacity={onPress?0.7:1}
      style={{flexDirection:'row',alignItems:'center',paddingVertical:14,gap:12}}>
      <Text style={{fontSize:20,width:28,textAlign:'center'}}>{emoji}</Text>
      <View style={{flex:1}}>
        <Text style={{fontSize:14,fontWeight:'600',color:danger?C.red:C.text}}>{title}</Text>
        {sub?<Text style={{fontSize:12,color:C.light,marginTop:1}}>{sub}</Text>:null}
      </View>
      {right||<Text style={{color:C.light,fontSize:16}}>›</Text>}
    </TouchableOpacity>
  );
  const Divider=()=><View style={{height:1,backgroundColor:C.border,marginLeft:40}}/>;

  return(
    <ScrollView style={{flex:1}} contentContainerStyle={{paddingBottom:40}}>
      <Text style={{fontSize:24,fontWeight:'900',color:C.text,padding:16,paddingBottom:8}}>Ayarlar</Text>

      {/* Profil kartı */}
      <View style={{paddingHorizontal:16,marginBottom:6}}>
        <Card style={{flexDirection:'row',alignItems:'center',gap:14}}>
          <TouchableOpacity onPress={pickPhoto} style={{position:'relative'}}>
            <Avatar user={user} size={64}/>
            <View style={{position:'absolute',bottom:0,right:0,width:22,height:22,borderRadius:11,
              backgroundColor:C.primary,alignItems:'center',justifyContent:'center',borderWidth:2,borderColor:'#fff'}}>
              <Text style={{fontSize:10}}>📷</Text></View>
          </TouchableOpacity>
          <View style={{flex:1}}>
            <Text style={{fontSize:16,fontWeight:'800',color:C.text}}>{user.name}</Text>
            <Text style={{fontSize:12,color:C.light}}>{user.email}</Text>
            <View style={{marginTop:4}}><RankBadge pts={user.points||0}/></View>
          </View>
          {saving&&<ActivityIndicator color={C.primary} size="small"/>}
        </Card>
      </View>

      {/* HESAP */}
      <Text style={[st.secHead,{paddingHorizontal:16,marginTop:14}]}>HESAP</Text>
      <View style={{backgroundColor:C.card,borderTopWidth:1,borderBottomWidth:1,borderColor:C.border,paddingHorizontal:16}}>

        {/* İsim */}
        <Row emoji="✏️" title="İsim Değiştir" sub={user.name} onPress={()=>{setEN(!editName);setEB(false);setEE(false);setEP(false);}}
          right={<Text style={{color:C.primary,fontWeight:'700',fontSize:13}}>{editName?'Kapat':'Düzenle'}</Text>}/>
        {editName&&<View style={{paddingBottom:12}}>
          <Inp placeholder="Yeni ad soyad" value={name} onChangeText={setName} style={{marginBottom:8}}/>
          <Btn label="Kaydet" onPress={saveName} small/>
        </View>}
        <Divider/>

        {/* Biyografi */}
        <Row emoji="📝" title="Hakkımda" sub={user.bio||'Biyografi ekle...'} onPress={()=>{setEB(!editBio);setEN(false);setEE(false);setEP(false);}}
          right={<Text style={{color:C.primary,fontWeight:'700',fontSize:13}}>{editBio?'Kapat':'Düzenle'}</Text>}/>
        {editBio&&<View style={{paddingBottom:12}}>
          <Inp placeholder="Kendinizi tanıtın..." value={bio} onChangeText={setBio} multiline style={{height:80,textAlignVertical:'top',marginBottom:8}}/>
          <Btn label="Kaydet" onPress={saveBio} small/>
        </View>}
        <Divider/>

        {/* E-posta */}
        <Row emoji="✉️" title="E-posta Değiştir" sub={user.email} onPress={()=>{setEE(!editEmail);setEN(false);setEB(false);setEP(false);}}
          right={<Text style={{color:C.primary,fontWeight:'700',fontSize:13}}>{editEmail?'Kapat':'Değiştir'}</Text>}/>
        {editEmail&&<View style={{paddingBottom:12}}>
          <Inp placeholder="Yeni e-posta" value={newEmail} onChangeText={setNewEmail} keyboardType="email-address" style={{marginBottom:8}}/>
          <Inp placeholder="Mevcut şifreniz" value={emailPass} onChangeText={setEmailPass} secureTextEntry style={{marginBottom:8}}/>
          <Btn label="E-postayı Güncelle" onPress={saveEmail} small/>
        </View>}
        <Divider/>

        {/* Şifre */}
        <Row emoji="🔑" title="Şifre Değiştir" sub="••••••••" onPress={()=>{setEP(!editPass);setEN(false);setEB(false);setEE(false);}}
          right={<Text style={{color:C.primary,fontWeight:'700',fontSize:13}}>{editPass?'Kapat':'Değiştir'}</Text>}/>
        {editPass&&<View style={{paddingBottom:12}}>
          <Inp placeholder="Mevcut şifre" value={oldPass} onChangeText={setOldPass} secureTextEntry style={{marginBottom:8}}/>
          <Inp placeholder="Yeni şifre (min. 6)" value={newPass} onChangeText={setNewPass} secureTextEntry style={{marginBottom:8}}/>
          <Inp placeholder="Yeni şifre tekrar" value={newPass2} onChangeText={setNewPass2} secureTextEntry style={{marginBottom:8}}/>
          <Btn label="Şifreyi Güncelle" onPress={savePass} small/>
        </View>}
      </View>

      {/* SINAV */}
      <Text style={[st.secHead,{paddingHorizontal:16,marginTop:14}]}>SINAV</Text>
      <View style={{backgroundColor:C.card,borderTopWidth:1,borderBottomWidth:1,borderColor:C.border,paddingHorizontal:16}}>
        <Row emoji="🎯" title="Sınav Tercihi" sub={sinav} onPress={()=>setES(!editSinav)}
          right={<Text style={{color:C.primary,fontWeight:'700',fontSize:13}}>{editSinav?'Kapat':'Değiştir'}</Text>}/>
        {editSinav&&<View style={{paddingBottom:12,gap:8}}>
          {['TYT+AYT','Sadece TYT','Sadece AYT'].map(opt=>(
            <TouchableOpacity key={opt} onPress={()=>saveSinav(opt)}
              style={{flexDirection:'row',alignItems:'center',padding:12,borderRadius:10,
                backgroundColor:sinav===opt?C.primary+'18':C.bg,
                borderWidth:1.5,borderColor:sinav===opt?C.primary:C.border}}>
              <View style={{width:20,height:20,borderRadius:10,borderWidth:2,
                borderColor:sinav===opt?C.primary:C.light,
                backgroundColor:sinav===opt?C.primary:'transparent',
                alignItems:'center',justifyContent:'center',marginRight:10}}>
                {sinav===opt&&<View style={{width:8,height:8,borderRadius:4,backgroundColor:'#fff'}}/>}
              </View>
              <Text style={{fontSize:14,fontWeight:sinav===opt?'700':'400',color:sinav===opt?C.primary:C.text}}>{opt}</Text>
            </TouchableOpacity>
          ))}
        </View>}
        <Divider/>
        {/* Bildirimler */}
        <Row emoji="🔔" title="Bildirimler" sub={notif?'Açık':'Kapalı'} onPress={toggleNotif}
          right={
            <TouchableOpacity onPress={toggleNotif}
              style={{width:46,height:26,borderRadius:13,backgroundColor:notif?C.primary:C.border,justifyContent:'center',paddingHorizontal:2}}>
              <View style={{width:22,height:22,borderRadius:11,backgroundColor:'#fff',
                marginLeft:notif?22:2,shadowColor:'#000',shadowOpacity:0.2,shadowRadius:2,shadowOffset:{width:0,height:1},elevation:2}}/>
            </TouchableOpacity>
          }/>
      </View>

      {/* DESTEK */}
      <Text style={[st.secHead,{paddingHorizontal:16,marginTop:14}]}>DESTEK</Text>
      <View style={{backgroundColor:C.card,borderTopWidth:1,borderBottomWidth:1,borderColor:C.border,paddingHorizontal:16}}>
        <Row emoji="❓" title="Yardım Merkezi" sub="SSS ve destek" onPress={()=>setModal('help')}/>
        <Divider/>
        <Row emoji="📄" title="Kullanım Koşulları" onPress={()=>setModal('terms')}/>
        <Divider/>
        <Row emoji="🔒" title="Gizlilik Politikası" onPress={()=>setModal('privacy')}/>
      </View>

      {/* HESAP İŞLEMLERİ */}
      <Text style={[st.secHead,{paddingHorizontal:16,marginTop:14}]}>HESAP İŞLEMLERİ</Text>
      <View style={{backgroundColor:C.card,borderTopWidth:1,borderBottomWidth:1,borderColor:C.border,paddingHorizontal:16}}>
        <Row emoji="🚪" title="Çıkış Yap" danger onPress={async()=>{await db.logout();onLogout();}} right={null}/>
        <Divider/>
        <Row emoji="🗑️" title="Hesabı Sil" sub="Tüm verilerin kalıcı olarak silinecek" danger onPress={confirmDelete}/>
      </View>

      <Text style={{textAlign:'center',color:C.light,fontSize:11,marginTop:24}}>YKS Takip v1.0.0 · 2025</Text>

      {/* YARDIM MODALİ */}
      <InfoModal visible={modal==='help'} title="❓ Yardım Merkezi" onClose={()=>setModal(null)}>
        {[
          {q:'Puanlar nasıl kazanılır?',a:'Her oyundan doğru cevap sayısına ve cevap hızına göre puan kazanırsınız. Hızlı cevaplar daha fazla puan verir.'},
          {q:'Rank sistemi nasıl çalışır?',a:'Bronz (0) → Gümüş (300) → Altın (800) → Platin (1800) → Elmas (3500) → Master (7000) → Efsane (12000) puan sıralamasıyla yükselirsiniz.'},
          {q:'Verilerim kaybolur mu?',a:'Hayır. Hesap verileriniz ve puanlarınız JSONBin sunucusunda, çalışma notlarınız ise telefonunuzda güvenle saklanır.'},
          {q:'Fotoğraf boyutu sınırı var mı?',a:'Profil fotoğrafı otomatik olarak sıkıştırılır. Herhangi bir boyuttaki fotoğrafı yükleyebilirsiniz.'},
          {q:'Başkalarıyla nasıl mesajlaşırım?',a:'Sıralama tablosunda herhangi bir kullanıcının profiline tıklayıp "Mesajlaş" butonunu kullanabilirsiniz.'},
          {q:'Başarımlar nasıl kazanılır?',a:'Oyun oynamak, puan kazanmak ve ders bazında belirli eşiklere ulaşmak başarım kazandırır. Başarımlar sekmesinden tüm koşulları görebilirsiniz.'},
          {q:'Çalışma takibi verileri senkronize oluyor mu?',a:'Çalışma takibi verileri gizliliğiniz için sadece kendi telefonunuzda saklanır ve senkronize edilmez.'},
        ].map(({q,a})=>(
          <View key={q} style={{marginBottom:18}}>
            <Text style={{fontSize:15,fontWeight:'700',color:C.text,marginBottom:6}}>• {q}</Text>
            <Text style={{fontSize:14,color:C.mid,lineHeight:21}}>{a}</Text>
          </View>
        ))}
      </InfoModal>

      {/* KULLANIM KOŞULLARI */}
      <InfoModal visible={modal==='terms'} title="📄 Kullanım Koşulları" onClose={()=>setModal(null)}>
        {[
          ['1. Hizmet Kapsamı','YKS Takip uygulaması, Türkiye Yükseköğretim Kurumları Sınavı\'na (YKS) hazırlanan öğrenciler için geliştirilmiş ücretsiz bir eğitim platformudur.'],
          ['2. Kullanıcı Hesabı','Kayıt olurken doğru bilgi vermelisiniz. Hesabınızın güvenliğinden siz sorumlusunuz. Şifrenizi kimseyle paylaşmayınız.'],
          ['3. Kullanım Kuralları','Platformu yasalara aykırı amaçlarla, başkalarını rahatsız edecek şekilde ya da hizmetin işleyişini bozacak biçimde kullanamazsınız.'],
          ['4. İçerik','Sorular eğitim amaçlı hazırlanmıştır. Soru içeriklerinin doğruluğu için azami özen gösterilmekle birlikte hatalar için sorumluluk kabul edilmez.'],
          ['5. Hizmet Değişiklikleri','Uygulama içeriği, özellikleri ve kullanım koşulları önceden haber verilmeksizin değiştirilebilir.'],
          ['6. Sorumluluk Sınırı','Uygulama "olduğu gibi" sunulmaktadır. Sınav sonuçlarına dair herhangi bir taahhüt verilmemektedir.'],
        ].map(([t,a])=>(
          <View key={t} style={{marginBottom:18}}>
            <Text style={{fontSize:15,fontWeight:'700',color:C.text,marginBottom:6}}>{t}</Text>
            <Text style={{fontSize:14,color:C.mid,lineHeight:21}}>{a}</Text>
          </View>
        ))}
      </InfoModal>

      {/* GİZLİLİK POLİTİKASI */}
      <InfoModal visible={modal==='privacy'} title="🔒 Gizlilik Politikası" onClose={()=>setModal(null)}>
        {[
          ['Toplanan Veriler','Ad soyad, e-posta adresi, profil fotoğrafı ve oyun puanlarınız toplanmaktadır. Çalışma notlarınız yalnızca cihazınızda saklanır.'],
          ['Verilerin Kullanımı','Verileriniz yalnızca hizmetin sunulması amacıyla kullanılır; üçüncü taraflarla paylaşılmaz veya satılmaz.'],
          ['Veri Saklama','Verileriniz JSONBin.io altyapısında saklanmaktadır. Hesabınızı sildiğinizde tüm verileriniz kalıcı olarak silinir.'],
          ['Profil Fotoğrafı','Yüklediğiniz profil fotoğrafı diğer kullanıcılar tarafından görülebilir. İstediğiniz zaman kaldırabilirsiniz.'],
          ['Çerezler ve Takip','Uygulama herhangi bir analitik takip veya çerez kullanmamaktadır.'],
          ['İletişim','Gizlilik ile ilgili sorularınız için uygulama içi mesajlaşma özelliğini kullanabilirsiniz.'],
        ].map(([t,a])=>(
          <View key={t} style={{marginBottom:18}}>
            <Text style={{fontSize:15,fontWeight:'700',color:C.text,marginBottom:6}}>{t}</Text>
            <Text style={{fontSize:14,color:C.mid,lineHeight:21}}>{a}</Text>
          </View>
        ))}
      </InfoModal>
    </ScrollView>
  );
}


/* ══ ÇALIŞMA TAKİP ═══════════════════════════════════ */
function StudyTab({user}){
  const[data,setData]=useState(null);
  const[wIdx,setWIdx]=useState(0);
  const[selDay,setSelDay]=useState(null);
  const[sec,setSec]=useState('ders');
  const[sharing,setSharing]=useState(false);
  useEffect(()=>{db.study(user.id).then(d=>{setData(d);});},[]);
  const save=async n=>{setData(n);await db.setStudy(user.id,n);};

  const shareStudy=async(allWeeks=false)=>{
    if(!data)return;
    setSharing(true);
    try{
      const ICON_MAP={'TÜR':'📚','MAT':'🔢','GEO':'🗺️','FİZ':'⚡','KİM':'⚗️','BİY':'🧬','TAR':'📜','COĞ':'🌍','FEL':'🏛️','DİN':'🕌'};
      const weeksToShare=allWeeks?data.weeks:[data.weeks[wIdx]];
      const dateStr=new Date().toLocaleDateString('tr-TR',{day:'numeric',month:'long',year:'numeric'});
      const nowStr=new Date().toLocaleString('tr-TR');

      // Tüm haftalar için genel toplam
      const grand={sure:0,soru:0,paraNet:0,probNet:0};
      weeksToShare.forEach(wk=>{
        DAYS.forEach(d=>{
          const day=wk.days[d];
          grand.sure+=toNum(day.sure);
          SUBS.forEach(s=>grand.soru+=toNum(day.s[s]));
          grand.paraNet+=calcNet(day.para.dogru,day.para.yanlis);
          grand.probNet+=calcNet(day.prob.dogru,day.prob.yanlis);
        });
      });

      // Her hafta için bölüm oluştur
      let weekSections='';
      weeksToShare.forEach(wk=>{
        const ws=DAYS.reduce((acc,d)=>{
          const day=wk.days[d];
          acc.sure+=toNum(day.sure);
          SUBS.forEach(s=>acc.soru+=toNum(day.s[s]));
          acc.paraNet+=calcNet(day.para.dogru,day.para.yanlis);
          acc.probNet+=calcNet(day.prob.dogru,day.prob.yanlis);
          return acc;
        },{sure:0,soru:0,paraNet:0,probNet:0});

        let dayRows='';
        DAYS.forEach(d=>{
          const day=wk.days[d];
          const toplamSoru=SUBS.reduce((a,s)=>a+toNum(day.s[s]),0);
          const paraN=calcNet(day.para.dogru,day.para.yanlis);
          const probN=calcNet(day.prob.dogru,day.prob.yanlis);
          const aktif=toNum(day.sure)>0||toplamSoru>0;
          const bg=aktif?'#f0fdf4':'#ffffff';
          const nameColor=aktif?'color:#166534':'color:#374151';
          const pc=paraN>=0?'#16a34a':'#dc2626';
          const rc=probN>=0?'#16a34a':'#dc2626';
          dayRows+='<tr style="background:'+bg+'">'
            +'<td style="padding:7px 10px;font-weight:700;'+nameColor+'">'+d+'</td>'
            +'<td style="padding:7px 10px;text-align:center;color:#6b7280">'+(day.sure||'—')+' dk</td>'
            +'<td style="padding:7px 10px;text-align:center;color:#6b7280">'+(toplamSoru||'—')+'</td>'
            +'<td style="padding:7px 10px;text-align:center;font-weight:700;color:'+pc+'">'+(paraN||'—')+'</td>'
            +'<td style="padding:7px 10px;text-align:center;font-weight:700;color:'+rc+'">'+(probN||'—')+'</td>'
            +'</tr>';
        });

        let subRows='';
        SUBS.forEach(s=>{
          const total=DAYS.reduce((a,d)=>a+toNum(wk.days[d].s[s]),0);
          if(total>0) subRows+='<span style="display:inline-block;background:#ede9fe;color:#4f46e5;border-radius:8px;padding:4px 10px;margin:3px;font-size:12px;font-weight:700">'+(ICON_MAP[s]||'📖')+' '+s+': '+total+'</span>';
        });

        const wPara=ws.paraNet>=0?'#16a34a':'#dc2626';
        const wProb=ws.probNet>=0?'#16a34a':'#dc2626';

        weekSections+='<div class="week-header"><span class="week-name">'+wk.name+'</span>'
          +'<div class="week-stats">'
          +'<span class="ws">⏱️ '+ws.sure+' dk</span>'
          +'<span class="ws">📝 '+ws.soru+' soru</span>'
          +'<span class="ws" style="color:'+wPara+'">Par: '+ws.paraNet.toFixed(1)+'</span>'
          +'<span class="ws" style="color:'+wProb+'">Pro: '+ws.probNet.toFixed(1)+'</span>'
          +'</div></div>'
          +(subRows?'<div style="padding:10px 16px 0;border-left:3px solid #e0e7ff;margin:0 16px 4px">'+subRows+'</div>':'')
          +'<div class="card" style="margin:12px 0 0">'
          +'<table><tr><th>Gün</th><th style="text-align:center">Süre</th><th style="text-align:center">Soru</th>'
          +'<th style="text-align:center">Par.Net</th><th style="text-align:center">Pro.Net</th></tr>'
          +dayRows+'</table></div>';
      });

      const gpara=grand.paraNet>=0?'#16a34a':'#dc2626';
      const gprob=grand.probNet>=0?'#16a34a':'#dc2626';
      const title=allWeeks?('Tüm Haftalar ('+weeksToShare.length+' hafta)'):(weeksToShare[0].name);

      const html='<!DOCTYPE html><html><head><meta charset="utf-8">'
        +'<meta name="viewport" content="width=device-width,initial-scale=1"><style>'
        +'body{font-family:-apple-system,BlinkMacSystemFont,Segoe UI,sans-serif;margin:0;padding:0;background:#f8fafc;}'
        +'.container{max-width:660px;margin:0 auto;padding:20px;}'
        +'.header{background:linear-gradient(135deg,#16a34a,#22c55e);border-radius:16px;padding:22px;margin-bottom:16px;color:#fff;}'
        +'.header h1{margin:0 0 3px;font-size:20px;font-weight:900;}'
        +'.header p{margin:0;opacity:0.85;font-size:12px;}'
        +'.grand{display:grid;grid-template-columns:repeat(4,1fr);gap:10px;margin-bottom:18px;}'
        +'.stat{background:#fff;border-radius:12px;padding:12px;text-align:center;box-shadow:0 1px 4px rgba(0,0,0,0.06);}'
        +'.stat-val{font-size:20px;font-weight:900;color:#4f46e5;margin-bottom:2px;}'
        +'.stat-lbl{font-size:9px;color:#9ca3af;font-weight:700;text-transform:uppercase;}'
        +'.week-header{background:#1e1b4b;border-radius:12px 12px 0 0;padding:12px 16px;margin-top:20px;}'
        +'.week-name{color:#fff;font-size:15px;font-weight:900;display:block;margin-bottom:6px;}'
        +'.week-stats{display:flex;gap:10px;flex-wrap:wrap;}'
        +'.ws{background:rgba(255,255,255,0.15);color:#e0e7ff;border-radius:6px;padding:3px 10px;font-size:11px;font-weight:700;}'
        +'.card{background:#fff;border-radius:0 0 12px 12px;padding:0;overflow:hidden;box-shadow:0 2px 6px rgba(0,0,0,0.06);}'
        +'table{width:100%;border-collapse:collapse;}'
        +'th{background:#f8fafc;padding:7px 10px;text-align:left;font-size:10px;color:#9ca3af;font-weight:700;text-transform:uppercase;}'
        +'td{border-top:1px solid #f1f5f9;font-size:12px;}'
        +'.footer{text-align:center;padding:20px 0 8px;color:#9ca3af;font-size:11px;}'
        +'.badge{display:inline-block;background:#dcfce7;color:#16a34a;border-radius:6px;padding:2px 10px;font-size:11px;font-weight:700;}'
        +'</style></head><body><div class="container">'
        +'<div class="header"><h1>📊 Çalışma Raporu</h1>'
        +'<p>'+user.name+' · '+title+' · '+dateStr+'</p></div>'
        +(allWeeks?
          '<div class="grand">'
          +'<div class="stat"><div class="stat-val">'+grand.sure+'</div><div class="stat-lbl">Top. Dakika</div></div>'
          +'<div class="stat"><div class="stat-val">'+grand.soru+'</div><div class="stat-lbl">Top. Soru</div></div>'
          +'<div class="stat"><div class="stat-val" style="color:'+gpara+'">'+grand.paraNet.toFixed(1)+'</div><div class="stat-lbl">Top. Par.</div></div>'
          +'<div class="stat"><div class="stat-val" style="color:'+gprob+'">'+grand.probNet.toFixed(1)+'</div><div class="stat-lbl">Top. Pro.</div></div>'
          +'</div>':''
        )
        +weekSections
        +'<div class="footer"><span class="badge">YKS Takip</span><br>Oluşturuldu: '+nowStr+'</div>'
        +'</div></body></html>';

      const result=await Print.printToFileAsync({html,base64:false});
      if(await Sharing.isAvailableAsync()){
        await Sharing.shareAsync(result.uri,{mimeType:'application/pdf',dialogTitle:'Çalışma Raporu Paylaş'});
      }else{
        Alert.alert('Uyarı','Paylaşım bu cihazda desteklenmiyor.');
      }
    }catch(e){Alert.alert('Hata','Rapor oluşturulamadı: '+e.message);}
    setSharing(false);
  };

  const updSubj=(day,sub,val)=>{
    if(!data)return;
    const n=JSON.parse(JSON.stringify(data));
    n.weeks[wIdx].days[day].s[sub]=val;
    save(n);
  };
  const updField=(day,key,field,val)=>{
    if(!data)return;
    const n=JSON.parse(JSON.stringify(data));
    if(field===null)n.weeks[wIdx].days[day][key]=val;
    else n.weeks[wIdx].days[day][key][field]=val;
    save(n);
  };
  const addWeek=()=>{
    if(!data)return;
    const n=JSON.parse(JSON.stringify(data));
    n.weeks.push(mkWeek(n.weeks.length+1));
    setWIdx(n.weeks.length-1);save(n);
  };
  if(!data)return<View style={{flex:1,justifyContent:'center',alignItems:'center'}}><ActivityIndicator color={C.primary}/></View>;
  const cw=data.weeks[wIdx];
  const dd=selDay?cw.days[selDay]:null;

  // Haftalık özet hesapla
  const weekStats=DAYS.reduce((acc,d)=>{
    const day=cw.days[d];
    acc.sure+=toNum(day.sure);
    SUBS.forEach(s=>acc.soru+=toNum(day.s[s]));
    acc.paraNet+=calcNet(day.para.dogru,day.para.yanlis);
    acc.probNet+=calcNet(day.prob.dogru,day.prob.yanlis);
    return acc;
  },{sure:0,soru:0,paraNet:0,probNet:0});

  // Günün toplam aktivitesi (renk için)
  const dayScore=(day)=>{
    const d=cw.days[day];
    const s=SUBS.reduce((a,k)=>a+toNum(d.s[k]),0);
    const t=toNum(d.sure);
    if(s>0||t>0)return 2; // aktif
    return 0;
  };

  const DAY_SHORT=['Pzt','Sal','Çar','Per','Cum','Cmt','Paz'];

  return(
    <View style={{flex:1,backgroundColor:C.bg}}>
      {/* BAŞLIK + HAFTA SEÇİCİ */}
      <View style={{backgroundColor:C.primary,paddingHorizontal:16,paddingTop:14,paddingBottom:18}}>
        <View style={{flexDirection:'row',justifyContent:'space-between',alignItems:'center',marginBottom:14}}>
          <View>
            <Text style={{color:'rgba(255,255,255,0.7)',fontSize:12,fontWeight:'600'}}>ÇALIŞMA TAKİBİ</Text>
            <Text style={{color:'#fff',fontSize:20,fontWeight:'900'}}>{cw.name}</Text>
          </View>
          <View style={{flexDirection:'row',gap:8}}>
            <TouchableOpacity onPress={()=>Alert.alert('📤 Paylaş','Hangi verileri paylaşmak istiyorsun?',[
              {text:'İptal',style:'cancel'},
              {text:'📅 Bu Hafta',onPress:()=>shareStudy(false)},
              {text:'📊 Tüm Haftalar',onPress:()=>shareStudy(true)},
            ])} disabled={sharing}
              style={{backgroundColor:'rgba(255,255,255,0.9)',borderRadius:10,paddingHorizontal:12,paddingVertical:7,flexDirection:'row',alignItems:'center',gap:5}}>
              {sharing?<ActivityIndicator size="small" color={C.primary}/>:<Text style={{fontSize:14}}>📤</Text>}
              <Text style={{color:C.primary,fontWeight:'800',fontSize:12}}>Paylaş</Text>
            </TouchableOpacity>
            <TouchableOpacity onPress={addWeek}
              style={{backgroundColor:'rgba(255,255,255,0.2)',borderRadius:10,paddingHorizontal:12,paddingVertical:7}}>
              <Text style={{color:'#fff',fontWeight:'700',fontSize:12}}>+ Hafta</Text>
            </TouchableOpacity>
          </View>
        </View>
        {/* Hafta chips */}
        <ScrollView horizontal showsHorizontalScrollIndicator={false} contentContainerStyle={{gap:6}}>
          {data.weeks.map((w,i)=>(
            <TouchableOpacity key={w.id} onPress={()=>{setWIdx(i);setSelDay(null);}}
              style={{paddingHorizontal:12,paddingVertical:5,borderRadius:14,
                backgroundColor:i===wIdx?'#fff':'rgba(255,255,255,0.2)'}}>
              <Text style={{fontSize:11,fontWeight:'700',color:i===wIdx?C.primary:'#fff'}}>{w.name}</Text>
            </TouchableOpacity>
          ))}
        </ScrollView>
      </View>

      {/* HAFTALİK ÖZET KARTLARI */}
      <View style={{flexDirection:'row',gap:8,paddingHorizontal:14,marginTop:-10}}>
        {[
          {l:'Süre',v:weekStats.sure?weekStats.sure+' dk':'-',e:'⏱️'},
          {l:'Par. Net',v:weekStats.paraNet?weekStats.paraNet.toFixed(1):'-',e:'📖'},
          {l:'Pro. Net',v:weekStats.probNet?weekStats.probNet.toFixed(1):'-',e:'🧮'},
        ].map(s=>(
          <View key={s.l} style={{flex:1,backgroundColor:'#fff',borderRadius:12,padding:10,alignItems:'center',
            shadowColor:'#000',shadowOpacity:0.06,shadowRadius:6,elevation:3}}>
            <Text style={{fontSize:16}}>{s.e}</Text>
            <Text style={{fontSize:14,fontWeight:'800',color:C.primary,marginTop:3}}>{s.v}</Text>
            <Text style={{fontSize:9,color:C.light,marginTop:1}}>{s.l}</Text>
          </View>
        ))}
      </View>

      {/* 7 GÜN TAKVİM GÖRÜNÜMÜ */}
      <View style={{flexDirection:'row',paddingHorizontal:14,marginTop:14,gap:6}}>
        {DAYS.map((day,i)=>{
          const score=dayScore(day);
          const isSelected=selDay===day;
          return(
            <TouchableOpacity key={day} onPress={()=>setSelDay(isSelected?null:day)} style={{flex:1}}>
              <View style={{borderRadius:12,padding:6,alignItems:'center',
                backgroundColor:isSelected?C.primary:score===2?'#dcfce7':'#fff',
                borderWidth:1.5,borderColor:isSelected?C.primary:score===2?C.primary+'44':C.border,
                shadowColor:'#000',shadowOpacity:0.04,shadowRadius:4,elevation:2}}>
                <Text style={{fontSize:9,fontWeight:'600',color:isSelected?'rgba(255,255,255,0.8)':C.light}}>{DAY_SHORT[i]}</Text>
                <View style={{width:28,height:28,borderRadius:14,marginTop:4,
                  backgroundColor:isSelected?'rgba(255,255,255,0.25)':score===2?C.primary:'#f1f5f9',
                  alignItems:'center',justifyContent:'center'}}>
                  <Text style={{fontSize:14}}>{score===2?(isSelected?'✓':'✅'):''}</Text>
                </View>
                <Text style={{fontSize:9,color:isSelected?'#fff':C.mid,fontWeight:'700',marginTop:3}}>{i+1}</Text>
              </View>
            </TouchableOpacity>
          );
        })}
      </View>

      {/* GÜN DETAYI */}
      {selDay&&dd?(
        <ScrollView style={{flex:1,marginTop:14}} contentContainerStyle={{padding:14,paddingBottom:20}}>
          {/* Seksiyon seçici */}
          <Text style={{fontSize:15,fontWeight:'800',color:C.text,marginBottom:10}}>{selDay}</Text>
          <View style={{flexDirection:'row',gap:8,marginBottom:14}}>
            {[{id:'ders',l:'📚 Ders Saatleri'},{id:'sinav',l:'📝 Sınav Verisi'}].map(t=>(
              <TouchableOpacity key={t.id} onPress={()=>setSec(t.id)}
                style={{flex:1,paddingVertical:10,borderRadius:10,alignItems:'center',
                  backgroundColor:sec===t.id?C.primary:'#fff',
                  borderWidth:1.5,borderColor:sec===t.id?C.primary:C.border}}>
                <Text style={{fontSize:12,fontWeight:'700',color:sec===t.id?'#fff':C.mid}}>{t.l}</Text>
              </TouchableOpacity>
            ))}
          </View>

          {sec==='ders'?(
            <>
              {/* Toplam süre */}
              <View style={{backgroundColor:'#fff',borderRadius:14,padding:14,marginBottom:12,
                borderWidth:1,borderColor:C.border,flexDirection:'row',alignItems:'center',gap:12}}>
                <Text style={{fontSize:28}}>⏱️</Text>
                <View style={{flex:1}}>
                  <Text style={{fontSize:12,color:C.mid,fontWeight:'600'}}>GÜNLÜK ÇALIŞMA SÜRESİ</Text>
                  <TextInput
                    value={dd.sure} onChangeText={v=>updField(selDay,'sure',null,v)}
                    keyboardType="numeric" placeholder="Kaç dakika?"
                    placeholderTextColor={C.light}
                    style={{fontSize:22,fontWeight:'800',color:C.primary,marginTop:2,padding:0}}
                  />
                </View>
                <Text style={{color:C.light,fontSize:14,fontWeight:'600'}}>dk</Text>
              </View>

              {/* Dersler - kart grid */}
              <Text style={{fontSize:12,fontWeight:'700',color:C.mid,marginBottom:8,letterSpacing:0.5}}>DERS BAŞINA SORU SAYISI</Text>
              <View style={{flexDirection:'row',flexWrap:'wrap',gap:8}}>
                {SUBS.map(sub=>{
                  const ICONS={TÜR:'📚',MAT:'🔢',GEO:'🗺️',FİZ:'⚡',KİM:'⚗️',BİY:'🧬',TAR:'📜',COĞ:'🌍',FEL:'🏛️',DİN:'🕌'};
                  const val=dd.s[sub];
                  const hasVal=val&&val!=='0';
                  return(
                    <View key={sub} style={{width:(SW-28-8)/3-1,backgroundColor:hasVal?C.primary+'12':'#fff',
                      borderRadius:12,padding:10,borderWidth:1.5,
                      borderColor:hasVal?C.primary:C.border}}>
                      <Text style={{fontSize:18,marginBottom:4}}>{ICONS[sub]||'📖'}</Text>
                      <Text style={{fontSize:10,fontWeight:'700',color:C.mid}}>{sub}</Text>
                      <TextInput
                        value={dd.s[sub]} onChangeText={v=>updSubj(selDay,sub,v)}
                        keyboardType="numeric" placeholder="0"
                        placeholderTextColor={C.light}
                        style={{fontSize:18,fontWeight:'800',color:hasVal?C.primary:C.text,marginTop:2,padding:0}}
                      />
                    </View>
                  );
                })}
              </View>
            </>
          ):(
            <>
              {/* Paragraf */}
              <View style={{backgroundColor:'#fff',borderRadius:14,padding:16,marginBottom:12,borderWidth:1,borderColor:C.border}}>
                <View style={{flexDirection:'row',alignItems:'center',marginBottom:12,gap:8}}>
                  <Text style={{fontSize:22}}>📖</Text>
                  <Text style={{fontSize:15,fontWeight:'800',color:C.text}}>Paragraf</Text>
                  <View style={{flex:1,alignItems:'flex-end'}}>
                    <View style={{backgroundColor:calcNet(dd.para.dogru,dd.para.yanlis)>=0?'#dcfce7':'#fee2e2',
                      borderRadius:8,paddingHorizontal:10,paddingVertical:4}}>
                      <Text style={{fontSize:13,fontWeight:'800',
                        color:calcNet(dd.para.dogru,dd.para.yanlis)>=0?C.primary:C.red}}>
                        Net: {calcNet(dd.para.dogru,dd.para.yanlis)||'—'}
                      </Text>
                    </View>
                  </View>
                </View>
                <View style={{flexDirection:'row',gap:8}}>
                  {[{f:'soru',l:'Soru',e:'📝'},{f:'dogru',l:'Doğru',e:'✅'},{f:'yanlis',l:'Yanlış',e:'❌'}].map(({f,l,e})=>(
                    <View key={f} style={{flex:1,backgroundColor:C.bg,borderRadius:10,padding:10,alignItems:'center',borderWidth:1,borderColor:C.border}}>
                      <Text style={{fontSize:16}}>{e}</Text>
                      <Text style={{fontSize:9,color:C.mid,fontWeight:'600',marginTop:3}}>{l}</Text>
                      <TextInput value={dd.para[f]} onChangeText={v=>updField(selDay,'para',f,v)}
                        keyboardType="numeric" placeholder="0" placeholderTextColor={C.light}
                        style={{fontSize:18,fontWeight:'800',color:C.text,marginTop:2,textAlign:'center',padding:0,width:'100%'}}
                      />
                    </View>
                  ))}
                </View>
              </View>

              {/* Problem */}
              <View style={{backgroundColor:'#fff',borderRadius:14,padding:16,borderWidth:1,borderColor:C.border}}>
                <View style={{flexDirection:'row',alignItems:'center',marginBottom:12,gap:8}}>
                  <Text style={{fontSize:22}}>🧮</Text>
                  <Text style={{fontSize:15,fontWeight:'800',color:C.text}}>Problem</Text>
                  <View style={{flex:1,alignItems:'flex-end'}}>
                    <View style={{backgroundColor:calcNet(dd.prob.dogru,dd.prob.yanlis)>=0?'#dcfce7':'#fee2e2',
                      borderRadius:8,paddingHorizontal:10,paddingVertical:4}}>
                      <Text style={{fontSize:13,fontWeight:'800',
                        color:calcNet(dd.prob.dogru,dd.prob.yanlis)>=0?C.primary:C.red}}>
                        Net: {calcNet(dd.prob.dogru,dd.prob.yanlis)||'—'}
                      </Text>
                    </View>
                  </View>
                </View>
                <View style={{flexDirection:'row',gap:8}}>
                  {[{f:'soru',l:'Soru',e:'📝'},{f:'dogru',l:'Doğru',e:'✅'},{f:'yanlis',l:'Yanlış',e:'❌'}].map(({f,l,e})=>(
                    <View key={f} style={{flex:1,backgroundColor:C.bg,borderRadius:10,padding:10,alignItems:'center',borderWidth:1,borderColor:C.border}}>
                      <Text style={{fontSize:16}}>{e}</Text>
                      <Text style={{fontSize:9,color:C.mid,fontWeight:'600',marginTop:3}}>{l}</Text>
                      <TextInput value={dd.prob[f]} onChangeText={v=>updField(selDay,'prob',f,v)}
                        keyboardType="numeric" placeholder="0" placeholderTextColor={C.light}
                        style={{fontSize:18,fontWeight:'800',color:C.text,marginTop:2,textAlign:'center',padding:0,width:'100%'}}
                      />
                    </View>
                  ))}
                </View>
              </View>
            </>
          )}
        </ScrollView>
      ):(
        /* GÜN SEÇİLMEDİYSE rehber */
        <View style={{flex:1,alignItems:'center',justifyContent:'center',padding:24}}>
          <Text style={{fontSize:52,marginBottom:16}}>👆</Text>
          <Text style={{fontSize:16,fontWeight:'800',color:C.text,textAlign:'center'}}>Bir gün seç</Text>
          <Text style={{fontSize:13,color:C.mid,textAlign:'center',marginTop:8,lineHeight:20}}>
            Yukarıdaki takvimden bir güne dokunarak o günün çalışma verilerini gir.
          </Text>
        </View>
      )}
    </View>
  );
}

/* ══ MESAJLAR ════════════════════════════════════════ */
function MsgsTab({user,go,unreadMap={}}){
  const[allUsers,setAllUsers]=useState([]);
  const[query,setQuery]=useState('');
  const[loading,setL]=useState(true);
  useEffect(()=>{
    db.all().then(all=>{
      setAllUsers(all.map(u=>u.id===user.id?{...u,...user}:u).filter(u=>u.id!==user.id));
      setL(false);
    });
  },[]);
  const filtered=query.trim()===''
    ?allUsers
    :allUsers.filter(u=>u.name.toLowerCase().includes(query.toLowerCase().trim())||
                        false);
  return(
    <View style={{flex:1}}>
      <Hdr title="💬 Mesajlar" subtitle={`${allUsers.length} kullanıcı`}/>
      {/* Arama kutusu */}
      <View style={{paddingHorizontal:12,paddingVertical:8,backgroundColor:C.card,
        borderBottomWidth:1,borderBottomColor:C.border}}>
        <View style={{flexDirection:'row',alignItems:'center',backgroundColor:C.bg,
          borderRadius:12,paddingHorizontal:12,paddingVertical:8,gap:8,
          borderWidth:1,borderColor:C.border}}>
          <Text style={{fontSize:16}}>🔍</Text>
          <TextInput
            value={query} onChangeText={setQuery}
            placeholder="Kullanıcı adı ara..."
            placeholderTextColor={C.light}
            autoCapitalize="none"
            style={{flex:1,fontSize:14,color:C.text,padding:0}}
          />
          {query.length>0&&(
            <TouchableOpacity onPress={()=>setQuery('')}>
              <Text style={{fontSize:16,color:C.light}}>✕</Text>
            </TouchableOpacity>
          )}
        </View>
      </View>
      {loading?(
        <ActivityIndicator color={C.primary} style={{marginTop:40}}/>
      ):filtered.length===0?(
        <View style={{flex:1,alignItems:'center',justifyContent:'center',padding:24}}>
          <Text style={{fontSize:44,marginBottom:12}}>{query?'🔍':'👥'}</Text>
          <Text style={{fontSize:15,fontWeight:'700',color:C.text,textAlign:'center'}}>
            {query?`"${query}" bulunamadı`:'Henüz başka kullanıcı yok'}
          </Text>
          {query?<TouchableOpacity onPress={()=>setQuery('')} style={{marginTop:12}}>
            <Text style={{color:C.primary,fontWeight:'600'}}>Aramayı temizle</Text>
          </TouchableOpacity>:null}
        </View>
      ):(
        <FlatList data={filtered} keyExtractor={u=>u.id} contentContainerStyle={{padding:12,gap:8}}
          keyboardShouldPersistTaps="handled"
          renderItem={({item})=>{
            const r=getRank(item.points||0);
            return(
              <TouchableOpacity onPress={()=>go('chat',item)} activeOpacity={0.85}>
                <Card style={{flexDirection:'row',alignItems:'center',gap:12}}>
                  <View style={{position:'relative'}}>
                    <Avatar user={item} size={48}/>
                    {(unreadMap[item.id]||0)>0&&(
                      <View style={{position:'absolute',top:-2,right:-2,width:18,height:18,borderRadius:9,
                        backgroundColor:C.red,alignItems:'center',justifyContent:'center',
                        borderWidth:2,borderColor:C.card}}>
                        <Text style={{color:'#fff',fontSize:8,fontWeight:'900'}}>{unreadMap[item.id]>9?'9+':unreadMap[item.id]}</Text>
                      </View>
                    )}
                  </View>
                  <View style={{flex:1}}>
                    <Text style={{fontSize:14,fontWeight:(unreadMap[item.id]||0)>0?'900':'700',color:C.text}}>{item.name}</Text>
                    <Text style={{fontSize:11,color:C.light,marginTop:1}}>{'•'.repeat(6)+'@'+item.email.split('@')[1]}</Text>
                    <View style={{marginTop:4}}><RankBadge pts={item.points||0}/></View>
                  </View>
                  <View style={{alignItems:'center',gap:4}}>
                    <View style={{width:36,height:36,borderRadius:18,backgroundColor:(unreadMap[item.id]||0)>0?C.red:C.primary,
                      alignItems:'center',justifyContent:'center'}}>
                      <Text style={{fontSize:16}}>💬</Text>
                    </View>
                  </View>
                </Card>
              </TouchableOpacity>
            );
          }}
        />
      )}
    </View>
  );
}

function ChatScreen({user,peer,onBack}){
  const[msgs,setMsgs]=useState([]);
  const[showReport,setShowReport]=useState(false);
  const[reportReason,setReportReason]=useState('');
  const[reportDetail,setReportDetail]=useState('');
  const[reportSent,setReportSent]=useState(false);
  const[text,setText]=useState('');
  const[sending,setSending]=useState(false);
  const scrollRef=useRef(null);
  const pollRef=useRef(null);
  const load=async()=>{const m=await db.thread(user.id,peer.id);setMsgs(m);};
  useEffect(()=>{load();pollRef.current=setInterval(load,3000);return()=>clearInterval(pollRef.current);},[]);
  useEffect(()=>{setTimeout(()=>scrollRef.current?.scrollToEnd({animated:true}),150);},[msgs]);
  const send=async()=>{
    if(!text.trim()||sending)return;
    // Susturma kontrolü — DB'den taze oku
    const freshUser=await db.byId(user.id);
    const nowMuted=freshUser&&freshUser.muted&&freshUser.mutedUntil&&new Date(freshUser.mutedUntil)>new Date();
    if(nowMuted){
      const days=daysLeft(freshUser.mutedUntil);
      Alert.alert('🔇 Mesaj Gönderilemedi',
        `Mesajlaşma yetkin ${days} gün boyunca kısıtlandı.\nBitiş: ${new Date(freshUser.mutedUntil).toLocaleDateString('tr-TR')}`);
      return;
    }
    const t=filterText(text.trim());setText('');setSending(true);
    await db.msg(user.id,peer.id,t);await load();setSending(false);
  };
  return(
    <SafeAreaView style={{flex:1,backgroundColor:C.bg,paddingTop:TOP_INSET}}>
      <Hdr onBack={onBack}
        title={peer.name}
        subtitle={getRank(peer.points||0).l+' '+getRank(peer.points||0).e}
        right={
          <View style={{flexDirection:'row',alignItems:'center',gap:8}}>
            <TouchableOpacity onPress={()=>setShowReport(true)}
              style={{backgroundColor:'#fee2e2',borderRadius:8,paddingHorizontal:10,paddingVertical:6}}>
              <Text style={{fontSize:11,fontWeight:'700',color:C.red}}>🚩 Şikayet</Text>
            </TouchableOpacity>
            <Avatar user={peer} size={36}/>
          </View>
        }/>
      <KeyboardAvoidingView behavior={Platform.OS==='ios'?'padding':'height'} style={{flex:1}}>
        <ScrollView ref={scrollRef} style={{flex:1,padding:12}} contentContainerStyle={{paddingBottom:8}}>
          {msgs.length===0&&<View style={{alignItems:'center',padding:40}}>
            <Text style={{fontSize:36,marginBottom:8}}>💬</Text>
            <Text style={{color:C.mid}}>Konuşmayı başlat!</Text></View>}
          {msgs.map(m=>{
            const mine=m.from===user.id;
            return(<View key={m.id} style={{alignItems:mine?'flex-end':'flex-start',marginBottom:8}}>
              {!mine&&<View style={{flexDirection:'row',alignItems:'center',gap:6,marginBottom:3}}>
                <Avatar user={peer} size={22}/>
                <Text style={{fontSize:10,color:C.mid,fontWeight:'600'}}>{peer.name}</Text>
              </View>}
              <View style={{maxWidth:'75%',backgroundColor:mine?C.primary:C.card,borderRadius:16,
                borderBottomRightRadius:mine?4:16,borderBottomLeftRadius:mine?16:4,
                padding:12,borderWidth:mine?0:1,borderColor:C.border}}>
                <Text style={{color:mine?'#fff':C.text,fontSize:14}}>{m.text}</Text>
              </View>
              <Text style={{fontSize:9,color:C.light,marginTop:3,marginHorizontal:4}}>
                {new Date(m.ts).toLocaleTimeString('tr-TR',{hour:'2-digit',minute:'2-digit'})}
              </Text>
            </View>);
          })}
        </ScrollView>
        <View style={{flexDirection:'row',gap:8,padding:12,backgroundColor:C.card,
          borderTopWidth:1,borderTopColor:C.border,paddingBottom:BOTTOM+12}}>
          <TextInput value={text} onChangeText={setText} placeholder="Mesaj yaz..."
            placeholderTextColor={C.light} multiline
            style={{flex:1,backgroundColor:C.bg,borderRadius:24,paddingHorizontal:16,paddingVertical:10,fontSize:14,color:C.text}}/>
          <TouchableOpacity onPress={send} disabled={sending}
            style={{width:44,height:44,borderRadius:22,backgroundColor:sending?C.light:C.primary,alignItems:'center',justifyContent:'center'}}>
            {sending?<ActivityIndicator color="#fff" size="small"/>:<Text style={{color:'#fff',fontSize:18,fontWeight:'700'}}>↑</Text>}
          </TouchableOpacity>
        </View>
      </KeyboardAvoidingView>
      {/* Şikayet Modalı */}
      <Modal visible={showReport} animationType="slide" presentationStyle="pageSheet" onRequestClose={()=>{setShowReport(false);setReportSent(false);}}>
        <SafeAreaView style={{flex:1,backgroundColor:C.bg,paddingTop:TOP_INSET}}>
          <View style={{flexDirection:'row',alignItems:'center',padding:16,borderBottomWidth:1,borderBottomColor:C.border}}>
            <Text style={{flex:1,fontSize:17,fontWeight:'900',color:C.text}}>🚩 Kullanıcıyı Şikayet Et</Text>
            <TouchableOpacity onPress={()=>{setShowReport(false);setReportSent(false);setReportReason('');setReportDetail('');}} style={{padding:6}}>
              <Text style={{fontSize:18,color:C.mid}}>✕</Text>
            </TouchableOpacity>
          </View>
          <ScrollView contentContainerStyle={{padding:20}}>
            {reportSent?(
              <View style={{alignItems:'center',paddingVertical:40}}>
                <Text style={{fontSize:56,marginBottom:12}}>✅</Text>
                <Text style={{fontSize:18,fontWeight:'800',color:C.text,marginBottom:8}}>Şikayet Gönderildi</Text>
                <Text style={{fontSize:13,color:C.mid,textAlign:'center',lineHeight:20}}>Şikayetin admin tarafından incelenecek. Teşekkürler.</Text>
                <Btn label="Kapat" onPress={()=>{setShowReport(false);setReportSent(false);setReportReason('');setReportDetail('');}} style={{marginTop:24,width:'100%'}}/>
              </View>
            ):(
              <>
                <View style={{flexDirection:'row',alignItems:'center',gap:10,padding:14,backgroundColor:'#fef2f2',borderRadius:12,marginBottom:20}}>
                  <Avatar user={peer} size={44}/>
                  <View>
                    <Text style={{fontSize:15,fontWeight:'800',color:C.text}}>{peer.name}</Text>
                    <Text style={{fontSize:11,color:C.light}}>{peer.email?('•'.repeat(5)+'@'+peer.email.split('@')[1]):'—'}</Text>
                  </View>
                </View>
                <Text style={{fontSize:13,fontWeight:'700',color:C.text,marginBottom:10}}>Şikayet Sebebi</Text>
                {['Hakaret / Küfür','Taciz / Tehdit','Spam / Reklam','Uygunsuz İçerik','Sahte Hesap','Diğer'].map(r=>(
                  <TouchableOpacity key={r} onPress={()=>setReportReason(r)}
                    style={{flexDirection:'row',alignItems:'center',gap:10,padding:12,borderRadius:10,
                      backgroundColor:reportReason===r?C.primary+'18':C.bg,
                      borderWidth:1.5,borderColor:reportReason===r?C.primary:C.border,marginBottom:8}}>
                    <View style={{width:18,height:18,borderRadius:9,borderWidth:2,
                      borderColor:reportReason===r?C.primary:C.border,
                      backgroundColor:reportReason===r?C.primary:'transparent',
                      alignItems:'center',justifyContent:'center'}}>
                      {reportReason===r&&<View style={{width:8,height:8,borderRadius:4,backgroundColor:'#fff'}}/>}
                    </View>
                    <Text style={{fontSize:14,color:reportReason===r?C.primary:C.text,fontWeight:reportReason===r?'700':'400'}}>{r}</Text>
                  </TouchableOpacity>
                ))}
                <Text style={{fontSize:13,fontWeight:'700',color:C.text,marginTop:16,marginBottom:8}}>Detay (isteğe bağlı)</Text>
                <TextInput value={reportDetail} onChangeText={setReportDetail}
                  placeholder="Ne yaşandığını kısaca açıkla..."
                  placeholderTextColor={C.light} multiline
                  style={{backgroundColor:C.bg,borderRadius:10,borderWidth:1,borderColor:C.border,
                    padding:12,fontSize:14,color:C.text,height:100,textAlignVertical:'top',marginBottom:20}}/>
                <Btn label="🚩 Şikayeti Gönder"
                  onPress={async()=>{
                    if(!reportReason){Alert.alert('Uyarı','Lütfen bir sebep seç');return;}
                    await db.report(user.id,peer.id,reportReason,reportDetail);
                    setReportSent(true);
                  }}
                  color={C.red} disabled={!reportReason}/>
              </>
            )}
          </ScrollView>
        </SafeAreaView>
      </Modal>
    </SafeAreaView>
  );
}


