/* ══ UYGULAMA ═══════════════════════════════════════ */
// MainApp'i güncelle — StudyTab ve MsgsTab ekle
// Ayrı bir wrapper ile tab routing

/* ══ ADMİN NOTU POPUP ════════════════════════════════════════════════════ */
function AdminNotePopup({note,onClose}){
  const scaleAnim=useRef(new Animated.Value(0)).current;
  useEffect(()=>{
    Animated.spring(scaleAnim,{toValue:1,tension:80,friction:8,useNativeDriver:true}).start();
  },[]);
  const close=()=>{
    Animated.timing(scaleAnim,{toValue:0,duration:200,useNativeDriver:true}).start(()=>onClose());
  };
  return(
    <Modal visible transparent animationType="none" onRequestClose={close}>
      <View style={{flex:1,backgroundColor:'rgba(0,0,0,0.75)',justifyContent:'center',alignItems:'center',padding:24}}>
        <Animated.View style={{transform:[{scale:scaleAnim}],backgroundColor:'#0F172A',borderRadius:24,width:'100%',
          borderWidth:2,borderColor:'#818cf8',overflow:'hidden',maxWidth:360}}>
          {/* Başlık */}
          <View style={{backgroundColor:'rgba(129,140,248,0.15)',padding:20,alignItems:'center',gap:8}}>
            <Text style={{fontSize:40}}>📩</Text>
            <Text style={{color:'#818cf8',fontSize:18,fontWeight:'900',textAlign:'center'}}>Admin'den Mesaj</Text>
            <Text style={{color:'rgba(255,255,255,0.4)',fontSize:10}}>{new Date(note.ts).toLocaleString('tr-TR')}</Text>
          </View>
          {/* İçerik */}
          <View style={{padding:24}}>
            <View style={{backgroundColor:'rgba(129,140,248,0.08)',borderRadius:16,padding:16,borderWidth:1,borderColor:'rgba(129,140,248,0.2)'}}>
              <Text style={{color:'#fff',fontSize:15,lineHeight:24,textAlign:'center'}}>{note.text}</Text>
            </View>
            <TouchableOpacity onPress={close}
              style={{backgroundColor:'#818cf8',borderRadius:14,padding:14,alignItems:'center',marginTop:18}}>
              <Text style={{color:'#fff',fontWeight:'900',fontSize:15}}>Anladım ✓</Text>
            </TouchableOpacity>
          </View>
        </Animated.View>
      </View>
    </Modal>
  );
}

/* ══ ADMİN PANELİ ════════════════════════════════════════════════════════ */
function AdminTab({user,setUser}){
  const[users,setUsers]=useState([]);
  const[loading,setL]=useState(true);
  const[search,setSearch]=useState('');
  const[sel,setSel]=useState(null);
  const[modal,setModal]=useState(null);
  const[inputVal,setInputVal]=useState('');
  const[busy,setBusy]=useState(false);
  const[adminTab,setAdminTab]=useState('users'); // 'users'|'reports'
  const[noteTarget,setNoteTarget]=useState(null); // {user} not bırakılacak kullanıcı
  const[noteText,setNoteText]=useState('');
  const[noteBusy,setNoteBusy]=useState(false);
  const[showPasswords,setShowPasswords]=useState({}); // {userId: bool}
  const[reports,setReports]=useState([]);
  const[reportsLoading,setRL]=useState(false);
  const[selectedReport,setSelectedReport]=useState(null);
  const[reportMsgs,setReportMsgs]=useState([]);





  const load=async()=>{
    setL(true);
    const all=await db.all();
    setUsers(all.sort((a,b)=>(b.points||0)-(a.points||0)));
    setL(false);
  };
  const loadReports=async()=>{
    setRL(true);
    const reps=await db.getReports();
    const all=await db.all();
    // kullanıcı bilgilerini ekle
    const enriched=reps.map(r=>({
      ...r,
      fromUser:all.find(u=>u.id===r.fromId)||{name:'Silinmiş',email:''},
      toUser:all.find(u=>u.id===r.toId)||{name:'Silinmiş',email:''},
    })).sort((a,b)=>b.ts-a.ts);
    setReports(enriched);
    setRL(false);
  };
  const openReport=async(rep)=>{
    setSelectedReport(rep);
    // şikayet edilen kişinin tüm mesajlarını yükle (tüm thread'lerde)
    const d=await db._r();
    const msgs=(d.messages||[])
      .filter(m=>m.from===rep.toId||m.to===rep.toId)
      .sort((a,b)=>a.ts-b.ts)
      .slice(-50); // son 50 mesaj
    const all=await db.all();
    const enrichMsgs=msgs.map(m=>({
      ...m,
      fromUser:all.find(u=>u.id===m.from)||{name:'?'},
      toUser:all.find(u=>u.id===m.to)||{name:'?'},
    }));
    setReportMsgs(enrichMsgs);
    if(!rep.read)db.markReportRead(rep.id);
  };
  useEffect(()=>{load();},[]);
  useEffect(()=>{if(adminTab==='reports')loadReports();},[adminTab]);

  const filtered=search.trim()===''?users:users.filter(u=>
    u.name.toLowerCase().includes(search.toLowerCase())||
    u.email.toLowerCase().includes(search.toLowerCase())
  );

  const applyAction=async()=>{
    if(!sel)return;
    setBusy(true);
    const d=await db._r(true);
    const idx=d.users.findIndex(u=>u.id===sel.id);
    if(idx<0){setBusy(false);return;}

    if(modal==='ban'){
      const dur=parseInt(inputVal)||1;
      d.users[idx].banned=true;
      d.users[idx].bannedUntil=new Date(Date.now()+dur*86400000).toISOString();
      d.users[idx].banReason='Admin kararı';
      await db._w(d);
      Alert.alert('✅',`${sel.name} ${dur} gün banlandı.`);
      // Hedef kullanıcı aktif oturumsa bildir
      if(d.users[idx].id===user.id){const u2={...user,...d.users[idx]};await AsyncStorage.setItem('@yks_cur_v5',JSON.stringify(u2));setUser(u2);}
    }
    else if(modal==='mute'){
      const dur=parseInt(inputVal)||1;
      d.users[idx].muted=true;
      d.users[idx].mutedUntil=new Date(Date.now()+dur*86400000).toISOString();
      await db._w(d);
      Alert.alert('✅',`${sel.name} ${dur} gün susturuldu.`);
      if(d.users[idx].id===user.id){const u2={...user,...d.users[idx]};await AsyncStorage.setItem('@yks_cur_v5',JSON.stringify(u2));setUser(u2);}
    }
    else if(modal==='pts'){
      const pts=parseInt(inputVal)||0;
      const newTotal=(d.users[idx].points||0)+pts;
      const stats=distributeStats(newTotal);
      d.users[idx]={...d.users[idx],points:newTotal,...stats};
      await db._w(d);
      Alert.alert('✅',`${sel.name}\n+${pts} puan eklendi\nToplam: ${newTotal} puan\n🎮 ${stats.gamesPlayed} oyun`);
      const u2={...user,...d.users[idx]};
      await AsyncStorage.setItem('@yks_cur_v5',JSON.stringify(u2));
      if(d.users[idx].id===user.id){setUser(u2);}
    }
    else if(modal==='setpts'){
      const pts=parseInt(inputVal)||0;
      const stats=distributeStats(pts);
      d.users[idx]={...d.users[idx],points:pts,...stats};
      await db._w(d);
      Alert.alert('✅',`${sel.name}\nPuan: ${pts}\n🎮 ${stats.gamesPlayed} oyun`);
      const u2={...user,...d.users[idx]};
      await AsyncStorage.setItem('@yks_cur_v5',JSON.stringify(u2));
      if(d.users[idx].id===user.id){setUser(u2);}
    }
    else if(modal==='unban'){
      d.users[idx].banned=false;d.users[idx].bannedUntil=null;
      await db._w(d);Alert.alert('✅',`${sel.name} banı kaldırıldı.`);
    }
    else if(modal==='unmute'){
      d.users[idx].muted=false;d.users[idx].mutedUntil=null;
      await db._w(d);Alert.alert('✅',`${sel.name} susturma kaldırıldı.`);
    }
    else if(modal==='reset'){
      d.users[idx]={...d.users[idx],points:0,mathPts:0,physPts:0,chemPts:0,bioPts:0,
        hisPts:0,geoPts:0,philPts:0,relPts:0,turPts:0,edebiPts:0,
        mathGames:0,physGames:0,chemGames:0,bioGames:0,histGames:0,
        geoGames:0,philGames:0,relGames:0,turGames:0,edebiGames:0,
        gamesPlayed:0,streak:0};
      await db._w(d);Alert.alert('✅',`${sel.name} sıfırlandı.`);
      if(d.users[idx].id===user.id){const u2={...d.users[idx]};await AsyncStorage.setItem('@yks_cur_v5',JSON.stringify(u2));setUser(u2);}
    }
    else if(modal==='delete'){
      d.users=d.users.filter(u=>u.id!==sel.id);
      await db._w(d);Alert.alert('✅',`${sel.name} silindi.`);
      setSel(null);
    }

    await load();
    setModal(null);setInputVal('');setBusy(false);
  };

  const quickAction=(u,action)=>{
    if(action==='delete'){
      Alert.alert('⚠️ Sil',`${u.name} silinsin mi?`,[
        {text:'İptal',style:'cancel'},
        {text:'Sil',style:'destructive',onPress:async()=>{
          const d=await db._r(true);d.users=d.users.filter(x=>x.id!==u.id);
          await db._w(d);load();
        }}
      ]);return;
    }
    if(action==='giveadmin'){
      // 1. doğrulama
      Alert.alert('🛡️ Admin Hakkı Ver',
        `"${u.name}" kullanıcısına admin hakkı vermek istediğinden emin misin?`,
        [{text:'Hayır',style:'cancel'},
         {text:'Evet, devam et',onPress:()=>{
           // 2. doğrulama
           Alert.alert('⚠️ Son Onay',
             `Bu işlem "${u.name}" hesabına TÜM admin yetkilerini verecek.

Onaylıyor musun?`,
             [{text:'İptal',style:'cancel'},
              {text:'Evet, Admin Yap',style:'destructive',onPress:async()=>{
                const d=await db._r(true);
                const i=d.users.findIndex(x=>x.id===u.id);
                if(i>=0){d.users[i].isAdmin=true;await db._w(d);}
                await load();
                Alert.alert('✅',`${u.name} artık admin!`);
              }}
             ]);
         }}
        ]);
      return;
    }
    if(action==='removeadmin'){
      Alert.alert('🛡️ Admin Hakkını Al',
        `"${u.name}" kullanıcısının admin hakkını kaldırmak istediğinden emin misin?`,
        [{text:'Hayır',style:'cancel'},
         {text:'Evet, devam et',onPress:()=>{
           Alert.alert('⚠️ Son Onay',
             `"${u.name}" kullanıcısının admin yetkisi kaldırılacak.

Onaylıyor musun?`,
             [{text:'İptal',style:'cancel'},
              {text:'Evet, Kaldır',style:'destructive',onPress:async()=>{
                const d=await db._r(true);
                const i=d.users.findIndex(x=>x.id===u.id);
                if(i>=0){d.users[i].isAdmin=false;await db._w(d);}
                await load();
                Alert.alert('✅',`${u.name} artık admin değil.`);
              }}
             ]);
         }}
        ]);
      return;
    }
    setSel(u);setModal(action);setInputVal('');
  };

  const isBanned=u=>u.banned&&u.bannedUntil&&new Date(u.bannedUntil)>new Date();
  const isMuted=u=>u.muted&&u.mutedUntil&&new Date(u.mutedUntil)>new Date();

  const sendNote=async()=>{
    if(!noteTarget||!noteText.trim())return;
    setNoteBusy(true);
    await db.sendAdminNote(noteTarget.id,noteText.trim());
    setNoteBusy(false);
    setNoteTarget(null);
    setNoteText('');
    Alert.alert('✅','Not gönderildi! Kullanıcı uygulamayı açtığında görecek.');
  };

  const switchToUser=async(targetUser)=>{
    Alert.alert(
      '🔄 Hesaba Geç',
      `"${targetUser.name}" hesabına geçmek istediğinden emin misin?\n\nGeri dönmek için normal şifreni kullanabilirsin.`,
      [{text:'İptal',style:'cancel'},
       {text:'Geç',style:'destructive',onPress:async()=>{
         // Mevcut admin hesabını yedekle
         const d=await db._r();
         const fullUser=d.users.find(u=>u.id===targetUser.id);
         if(!fullUser){Alert.alert('Hata','Kullanıcı bulunamadı.');return;}
         // Avatar yükle
         const avMap=d.avatars||{};
         const av=avMap[fullUser.id]||(await AsyncStorage.getItem('@yks_av_'+fullUser.id));
         const userWithAv=av?{...fullUser,avatar:av}:fullUser;
         await AsyncStorage.setItem('@yks_cur_v5',JSON.stringify(userWithAv));
         setUser(userWithAv);
         Alert.alert('✅',`${fullUser.name} hesabına geçildi.`);
       }}
      ]
    );
  };

  const modalConfig={
    ban:    {title:'🚫 Banla',      hint:'Kaç gün? (örn: 7)',   btn:'Banla',       color:C.red},
    mute:   {title:'🔇 Sustur',     hint:'Kaç gün? (örn: 3)',   btn:'Sustur',      color:C.amber},
    pts:    {title:'⭐ Puan Ekle',   hint:'Eklenecek puan',      btn:'Ekle',        color:C.primary},
    setpts: {title:'✏️ Puan Ayarla',hint:'Yeni toplam puan',    btn:'Ayarla',      color:C.blue},
    reset:  {title:'🔄 Sıfırla',    hint:'Tüm veriler silinir', btn:'Sıfırla',     color:C.orange},
    unban:  {title:'✅ Banı Kaldır', hint:'Banı kaldırılacak',  btn:'Kaldır',      color:C.primary},
    unmute: {title:'🔊 Susturmayı Kaldır',hint:'Susturma kaldırılacak',btn:'Kaldır',color:C.primary},
    delete: {title:'🗑️ Sil',        hint:'Hesap kalıcı silinir',btn:'Sil',         color:C.red},
  };

  return(
    <View style={{flex:1,backgroundColor:C.bg}}>
      {/* Header */}
      <View style={{backgroundColor:'#1e1b4b',paddingTop:TOP_INSET+8,paddingBottom:0,paddingHorizontal:16}}>
        <Text style={{fontSize:18,fontWeight:'900',color:'#fff'}}>🛡️ Admin Paneli</Text>
        <Text style={{fontSize:11,color:'#a5b4fc',marginTop:2,marginBottom:12}}>{users.length} kullanıcı · {reports.filter(r=>!r.read).length} okunmamış şikayet</Text>
        <View style={{flexDirection:'row',gap:0}}>
          {[
            {id:'users',l:'👥 Kullanıcılar'},
            {id:'reports',l:`🚩 Şikayetler ${reports.filter(r=>!r.read).length>0?'('+reports.filter(r=>!r.read).length+')':''}`},
          ].map(t=>(
            <TouchableOpacity key={t.id} onPress={()=>setAdminTab(t.id)}
              style={{paddingHorizontal:12,paddingVertical:10,borderBottomWidth:3,
                borderBottomColor:adminTab===t.id?'#818cf8':'transparent'}}>
              <Text style={{fontSize:12,fontWeight:'700',color:adminTab===t.id?'#fff':'#a5b4fc'}}>{t.l}</Text>
            </TouchableOpacity>
          ))}
        </View>
      </View>

      {adminTab==='reports'?(
        /* ── Şikayetler sekmesi ── */
        <View style={{flex:1}}>
          {reportsLoading?<ActivityIndicator color={C.red} style={{marginTop:30}}/>:
          reports.length===0?
            <View style={{flex:1,alignItems:'center',justifyContent:'center',gap:12}}>
              <Text style={{fontSize:48}}>🎉</Text>
              <Text style={{fontSize:16,color:C.mid}}>Henüz şikayet yok</Text>
            </View>:
            <FlatList data={reports} keyExtractor={r=>r.id}
              contentContainerStyle={{padding:12,gap:8,paddingBottom:80}}
              refreshing={reportsLoading} onRefresh={loadReports}
              renderItem={({item:rep})=>(
                <TouchableOpacity onPress={()=>openReport(rep)} activeOpacity={0.85}>
                  <Card style={{borderLeftWidth:4,borderLeftColor:rep.read?C.border:C.red,opacity:rep.read?0.75:1}}>
                    <View style={{flexDirection:'row',alignItems:'flex-start',gap:10}}>
                      <Text style={{fontSize:28}}>{rep.read?'📋':'🔴'}</Text>
                      <View style={{flex:1}}>
                        <View style={{flexDirection:'row',alignItems:'center',gap:6,flexWrap:'wrap'}}>
                          <Text style={{fontSize:13,fontWeight:'800',color:C.red}}>🚩 {rep.reason}</Text>
                          {!rep.read&&<View style={{backgroundColor:'#fee2e2',borderRadius:6,paddingHorizontal:6,paddingVertical:2}}>
                            <Text style={{fontSize:9,fontWeight:'700',color:C.red}}>YENİ</Text>
                          </View>}
                        </View>
                        <View style={{flexDirection:'row',gap:6,marginTop:4,alignItems:'center'}}>
                          <Text style={{fontSize:11,color:C.mid}}>Şikayet eden:</Text>
                          <Text style={{fontSize:11,fontWeight:'700',color:C.text}}>{rep.fromUser.name}</Text>
                        </View>
                        <View style={{flexDirection:'row',gap:6,marginTop:2,alignItems:'center'}}>
                          <Text style={{fontSize:11,color:C.mid}}>Şikayet edilen:</Text>
                          <Text style={{fontSize:11,fontWeight:'700',color:C.red}}>{rep.toUser.name}</Text>
                        </View>
                        {!!rep.detail&&<Text style={{fontSize:11,color:C.mid,marginTop:4,fontStyle:'italic'}}>"{rep.detail}"</Text>}
                        <Text style={{fontSize:9,color:C.light,marginTop:4}}>{new Date(rep.ts).toLocaleString('tr-TR')}</Text>
                      </View>
                    </View>
                    <View style={{flexDirection:'row',gap:6,marginTop:10}}>
                      <TouchableOpacity onPress={()=>openReport(rep)}
                        style={{flex:1,backgroundColor:C.blue+'18',borderRadius:8,padding:8,alignItems:'center',borderWidth:1,borderColor:C.blue+'44'}}>
                        <Text style={{fontSize:12,fontWeight:'700',color:C.blue}}>💬 Mesajları Gör</Text>
                      </TouchableOpacity>
                      <TouchableOpacity onPress={async()=>{await db.deleteReport(rep.id);loadReports();}}
                        style={{backgroundColor:C.red+'18',borderRadius:8,padding:8,alignItems:'center',borderWidth:1,borderColor:C.red+'44',paddingHorizontal:14}}>
                        <Text style={{fontSize:12,fontWeight:'700',color:C.red}}>🗑️</Text>
                      </TouchableOpacity>
                    </View>
                  </Card>
                </TouchableOpacity>
              )}
            />}
        </View>
      ):(
      <View style={{flex:1}}>
      {/* Arama */}
      <View style={{paddingHorizontal:12,paddingVertical:8,backgroundColor:C.card,borderBottomWidth:1,borderBottomColor:C.border}}>
        <View style={{flexDirection:'row',alignItems:'center',backgroundColor:C.bg,borderRadius:10,paddingHorizontal:12,paddingVertical:8,gap:8,borderWidth:1,borderColor:C.border}}>
          <Text style={{fontSize:15}}>🔍</Text>
          <TextInput value={search} onChangeText={setSearch} placeholder="İsim veya e-posta ara..."
            placeholderTextColor={C.light} autoCapitalize="none"
            style={{flex:1,fontSize:14,color:C.text,padding:0}}/>
          {search.length>0&&<TouchableOpacity onPress={()=>setSearch('')}><Text style={{color:C.light}}>✕</Text></TouchableOpacity>}
        </View>
      </View>

      {/* Özet istatistikler */}
      <View style={{flexDirection:'row',gap:8,padding:12}}>
        {[
          {l:'Toplam',v:users.length,e:'👥',c:'#1e1b4b'},
          {l:'Banlı',v:users.filter(isBanned).length,e:'🚫',c:C.red},
          {l:'Susturulmuş',v:users.filter(isMuted).length,e:'🔇',c:C.amber},
          {l:'Admin',v:1,e:'🛡️',c:C.purple},
        ].map(s=>(
          <View key={s.l} style={{flex:1,backgroundColor:C.card,borderRadius:10,padding:8,alignItems:'center',borderTopWidth:3,borderTopColor:s.c}}>
            <Text style={{fontSize:16}}>{s.e}</Text>
            <Text style={{fontSize:16,fontWeight:'900',color:s.c}}>{s.v}</Text>
            <Text style={{fontSize:8,color:C.light,marginTop:1}}>{s.l}</Text>
          </View>
        ))}
      </View>

      {loading?<ActivityIndicator color={C.primary} style={{marginTop:20}}/>:
      <FlatList data={filtered} keyExtractor={u=>u.id}
        contentContainerStyle={{padding:12,gap:8,paddingBottom:100}}
        refreshing={loading} onRefresh={load}
        renderItem={({item})=>{
          const banned=isBanned(item),muted=isMuted(item),rk=getRank(item.points||0);
          return(
            <Card style={{borderLeftWidth:4,borderLeftColor:banned?C.red:muted?C.amber:rk.c}}>
              {/* Kullanıcı bilgisi */}
              <View style={{flexDirection:'row',alignItems:'center',gap:10,marginBottom:10}}>
                <Avatar user={item} size={42}/>
                <View style={{flex:1}}>
                  <View style={{flexDirection:'row',alignItems:'center',gap:6,flexWrap:'wrap'}}>
                    <Text style={{fontSize:14,fontWeight:'800',color:C.text}}>{item.name}</Text>
                    {banned&&<View style={{backgroundColor:'#fee2e2',borderRadius:6,paddingHorizontal:6,paddingVertical:2}}>
                      <Text style={{fontSize:9,fontWeight:'700',color:C.red}}>🚫 BANLI</Text>
                    </View>}
                    {muted&&<View style={{backgroundColor:'#fef3c7',borderRadius:6,paddingHorizontal:6,paddingVertical:2}}>
                      <Text style={{fontSize:9,fontWeight:'700',color:C.amber}}>🔇 SUSTURULMUŞ</Text>
                    </View>}
                    {(item.email===ADMIN_EMAIL||item.isAdmin)&&<View style={{backgroundColor:'#ede9fe',borderRadius:6,paddingHorizontal:6,paddingVertical:2}}>
                      <Text style={{fontSize:9,fontWeight:'700',color:C.purple}}>{item.email===ADMIN_EMAIL?'🛡️ BAŞ ADMİN':'🛡️ ADMİN'}</Text>
                    </View>}
                  </View>
                  <Text style={{fontSize:10,color:C.light,marginTop:1}}>{item.email}</Text>
                  {/* Şifre göster/gizle */}
                  <TouchableOpacity onPress={()=>setShowPasswords(p=>({...p,[item.id]:!p[item.id]}))}
                    style={{flexDirection:'row',alignItems:'center',gap:4,marginTop:3}}>
                    <Text style={{fontSize:9,color:'#818cf8',fontWeight:'700'}}>
                      {showPasswords[item.id]?'🔒 Gizle':'👁 Şifreyi Göster'}
                    </Text>
                  </TouchableOpacity>
                  {showPasswords[item.id]&&(
                    <Text style={{fontSize:11,color:'#fbbf24',fontFamily:'monospace',marginTop:2,
                      backgroundColor:'rgba(251,191,36,0.1)',paddingHorizontal:6,paddingVertical:2,borderRadius:4}}>
                      🔑 {item.password||'(şifresi yok)'}
                    </Text>
                  )}
                  <View style={{flexDirection:'row',gap:8,marginTop:4,alignItems:'center'}}>
                    <RankBadge pts={item.points||0}/>
                    <Text style={{fontSize:11,color:C.amber,fontWeight:'700'}}>{item.points||0} pt</Text>
                    <Text style={{fontSize:11,color:C.mid}}>{item.gamesPlayed||0} oyun</Text>
                  </View>
                </View>
              </View>
              {/* Aksiyon butonları */}
              {item.email===ADMIN_EMAIL?(
                <View style={{gap:8}}>
                  <View style={{flexDirection:'row',gap:6,flexWrap:'wrap'}}>
                    <ActionBtn label="⭐ Puan Ekle" color={C.blue} onPress={()=>quickAction(item,'pts')}/>
                    <ActionBtn label="✏️ Puan Ayarla" color={C.purple} onPress={()=>quickAction(item,'setpts')}/>
                  </View>
                  <TouchableOpacity
                    onPress={async()=>{
                      Alert.alert('🏅 Tüm Başarımlar','Tüm başarımlar sana eklensin mi?',[
                        {text:'İptal',style:'cancel'},
                        {text:'Evet',onPress:async()=>{
                          const d2=await db._r(true);
                          const i2=d2.users.findIndex(u=>u.id===item.id);
                          if(i2<0)return;
                          // Tüm achievement'ları kazanmak için minimum değerleri ayarla
                          const u0=d2.users[i2];
                          const mx=(f,v)=>Math.max(u0[f]||0,v);
                          const achBoost={
                            gamesPlayed:mx('gamesPlayed',500),   // games_500
                            points:mx('points',50000),            // pts_50000 + efsane rank
                            mathPts:mx('mathPts',2000),
                            physPts:mx('physPts',2000),
                            chemPts:mx('chemPts',2000),
                            bioPts:mx('bioPts',2000),
                            hisPts:mx('hisPts',2000),
                            geoPts:mx('geoPts',2000),
                            philPts:mx('philPts',2000),
                            relPts:mx('relPts',2000),
                            turPts:mx('turPts',2000),
                            edebiPts:mx('edebiPts',2000),
                            streak:mx('streak',30),               // streak_30
                            pomodoroCount:mx('pomodoroCount',50), // pomodoro_50
                            mathGames:mx('mathGames',50),
                            physGames:mx('physGames',50),
                            chemGames:mx('chemGames',50),
                            bioGames:mx('bioGames',50),
                            histGames:mx('histGames',50),
                            geoGames:mx('geoGames',50),
                            philGames:mx('philGames',50),
                            relGames:mx('relGames',50),
                            turGames:mx('turGames',50),
                            edebiGames:mx('edebiGames',50),
                          };
                          d2.users[i2]={...d2.users[i2],...achBoost};
                          await db._w(d2);
                          const u2={...user,...d2.users[i2]};
                          await AsyncStorage.setItem('@yks_cur_v5',JSON.stringify(u2));
                          setUser(u2);
                          await load();
                          Alert.alert('🏅','Tüm başarımlar verildi!');
                        }}
                      ]);
                    }}
                    style={{backgroundColor:'#fef3c7',borderRadius:8,padding:10,alignItems:'center',
                      borderWidth:1.5,borderColor:C.amber}}>
                    <Text style={{fontSize:13,fontWeight:'800',color:C.amber}}>🏅 Tüm Başarımları Ver (Sadece Sana)</Text>
                  </TouchableOpacity>
                </View>
              ):(
                <View style={{gap:6}}>
                  <View style={{flexDirection:'row',gap:6,flexWrap:'wrap'}}>
                    {!banned?
                      <ActionBtn label="🚫 Banla" color={C.red} onPress={()=>quickAction(item,'ban')}/>:
                      <ActionBtn label="✅ Banı Kaldır" color={C.primary} onPress={()=>quickAction(item,'unban')}/>}
                    {!muted?
                      <ActionBtn label="🔇 Sustur" color={C.amber} onPress={()=>quickAction(item,'mute')}/>:
                      <ActionBtn label="🔊 Susturmayı Kaldır" color={C.primary} onPress={()=>quickAction(item,'unmute')}/>}
                    <ActionBtn label="⭐ Puan Ekle" color={C.blue} onPress={()=>quickAction(item,'pts')}/>
                    <ActionBtn label="✏️ Puan Ayarla" color={C.purple} onPress={()=>quickAction(item,'setpts')}/>
                    <ActionBtn label="🔄 Sıfırla" color={C.orange} onPress={()=>quickAction(item,'reset')}/>
                    <ActionBtn label="🗑️ Sil" color={C.red} onPress={()=>quickAction(item,'delete')}/>
                    {item.isAdmin?
                      <ActionBtn label="🛡️ Admin Al" color={C.red} onPress={()=>quickAction(item,'removeadmin')}/>:
                      <ActionBtn label="🛡️ Admin Ver" color={C.purple} onPress={()=>quickAction(item,'giveadmin')}/>}
                    <ActionBtn label="📩 Not Bırak" color="#06b6d4" onPress={()=>{setNoteTarget(item);setNoteText('');}}/>
                    <ActionBtn label="🔄 Hesaba Geç" color="#f59e0b" onPress={()=>switchToUser(item)}/>
                  </View>
                  {banned&&<Text style={{fontSize:10,color:C.red}}>📅 Bitiş: {new Date(item.bannedUntil).toLocaleDateString('tr-TR')}</Text>}
                  {muted&&<Text style={{fontSize:10,color:C.amber}}>📅 Bitiş: {new Date(item.mutedUntil).toLocaleDateString('tr-TR')}</Text>}
                </View>
              )}
            </Card>
          );
        }}
      />}

      </View>
      )}

      {/* Not Bırak Modalı */}
      {noteTarget&&(
        <Modal visible transparent animationType="fade" onRequestClose={()=>setNoteTarget(null)}>
          <View style={{flex:1,backgroundColor:'rgba(0,0,0,0.8)',justifyContent:'center',alignItems:'center',padding:24}}>
            <View style={{backgroundColor:'#0F172A',borderRadius:24,width:'100%',
              borderWidth:2,borderColor:'#06b6d4',overflow:'hidden'}}>
              <View style={{backgroundColor:'rgba(6,182,212,0.12)',padding:20,alignItems:'center',gap:6}}>
                <Text style={{fontSize:36}}>📩</Text>
                <Text style={{color:'#06b6d4',fontSize:17,fontWeight:'900'}}>{noteTarget.name}'e Not Bırak</Text>
                <Text style={{color:'rgba(255,255,255,0.4)',fontSize:11}}>Kullanıcı uygulamayı açtığında ekranında görünecek</Text>
              </View>
              <View style={{padding:20,gap:12}}>
                <TextInput
                  value={noteText}
                  onChangeText={setNoteText}
                  placeholder="Mesajını yaz..."
                  placeholderTextColor="rgba(255,255,255,0.3)"
                  multiline
                  numberOfLines={4}
                  style={{backgroundColor:'rgba(255,255,255,0.07)',borderRadius:14,padding:14,
                    color:'#fff',fontSize:14,lineHeight:22,minHeight:100,borderWidth:1,
                    borderColor:'rgba(6,182,212,0.3)',textAlignVertical:'top'}}
                />
                <View style={{flexDirection:'row',gap:10}}>
                  <TouchableOpacity onPress={()=>setNoteTarget(null)}
                    style={{flex:1,backgroundColor:'rgba(255,255,255,0.08)',borderRadius:12,padding:14,alignItems:'center'}}>
                    <Text style={{color:'rgba(255,255,255,0.5)',fontWeight:'700'}}>İptal</Text>
                  </TouchableOpacity>
                  <TouchableOpacity onPress={sendNote} disabled={noteBusy||!noteText.trim()}
                    style={{flex:2,backgroundColor:noteText.trim()?'#06b6d4':'rgba(6,182,212,0.3)',
                      borderRadius:12,padding:14,alignItems:'center'}}>
                    {noteBusy?<ActivityIndicator color="#fff" size="small"/>:
                      <Text style={{color:'#fff',fontWeight:'900',fontSize:14}}>📩 Gönder</Text>}
                  </TouchableOpacity>
                </View>
              </View>
            </View>
          </View>
        </Modal>
      )}

      {/* Şikayet Detay Modalı */}
      {selectedReport&&(
        <Modal visible animationType="slide" presentationStyle="pageSheet" onRequestClose={()=>setSelectedReport(null)}>
          <SafeAreaView style={{flex:1,backgroundColor:C.bg,paddingTop:TOP_INSET}}>
            <View style={{flexDirection:'row',alignItems:'center',padding:16,borderBottomWidth:1,borderBottomColor:C.border}}>
              <View style={{flex:1}}>
                <Text style={{fontSize:16,fontWeight:'900',color:C.text}}>💬 Mesaj Geçmişi</Text>
                <Text style={{fontSize:11,color:C.red,marginTop:1}}>🚩 Şikayet edilen: {selectedReport.toUser.name}</Text>
              </View>
              <TouchableOpacity onPress={()=>setSelectedReport(null)} style={{padding:6}}>
                <Text style={{fontSize:18,color:C.mid}}>✕</Text>
              </TouchableOpacity>
            </View>
            {/* Şikayet özeti */}
            <View style={{padding:12,backgroundColor:'#fef2f2',borderBottomWidth:1,borderBottomColor:'#fecaca'}}>
              <Text style={{fontSize:12,fontWeight:'700',color:C.red}}>Sebep: {selectedReport.reason}</Text>
              {!!selectedReport.detail&&<Text style={{fontSize:11,color:C.mid,marginTop:2}}>Detay: {selectedReport.detail}</Text>}
              <Text style={{fontSize:11,color:C.mid,marginTop:2}}>
                {selectedReport.fromUser.name} tarafından {new Date(selectedReport.ts).toLocaleString('tr-TR')}
              </Text>
            </View>
            <ScrollView style={{flex:1}} contentContainerStyle={{padding:12,paddingBottom:20}}>
              {reportMsgs.length===0?(
                <View style={{alignItems:'center',padding:30}}>
                  <Text style={{fontSize:32}}>📭</Text>
                  <Text style={{color:C.mid,marginTop:8}}>Mesaj bulunamadı</Text>
                </View>
              ):reportMsgs.map((m,i)=>{
                const isReported=m.from===selectedReport.toId;
                return(
                  <View key={i} style={{marginBottom:10}}>
                    <View style={{flexDirection:'row',alignItems:'center',gap:6,marginBottom:3}}>
                      <View style={{width:8,height:8,borderRadius:4,backgroundColor:isReported?C.red:C.primary}}/>
                      <Text style={{fontSize:10,fontWeight:'700',color:isReported?C.red:C.primary}}>{m.fromUser.name}</Text>
                      <Text style={{fontSize:9,color:C.light}}>→ {m.toUser.name}</Text>
                      <Text style={{fontSize:9,color:C.light,marginLeft:'auto'}}>{new Date(m.ts).toLocaleString('tr-TR',{day:'2-digit',month:'2-digit',hour:'2-digit',minute:'2-digit'})}</Text>
                    </View>
                    <View style={{padding:10,borderRadius:10,backgroundColor:isReported?'#fef2f2':C.card,
                      borderWidth:1,borderColor:isReported?'#fecaca':C.border,marginLeft:14}}>
                      <Text style={{fontSize:13,color:isReported?C.red:C.text}}>{m.text}</Text>
                    </View>
                  </View>
                );
              })}
            </ScrollView>
            <View style={{padding:12,flexDirection:'row',gap:8,borderTopWidth:1,borderTopColor:C.border}}>
              <Btn label="🚫 Kullanıcıyı Banla" color={C.red} style={{flex:1}}
                onPress={()=>{setSelectedReport(null);quickAction(users.find(u=>u.id===selectedReport.toId)||selectedReport.toUser,'ban');}}/>
              <Btn label="🗑️ Raporu Sil" color={C.mid} style={{flex:1}}
                onPress={async()=>{await db.deleteReport(selectedReport.id);setSelectedReport(null);loadReports();}}/>
            </View>
          </SafeAreaView>
        </Modal>
      )}

      {/* Modal */}
      {modal&&sel&&(
        <Modal visible animationType="slide" presentationStyle="pageSheet" onRequestClose={()=>setModal(null)}>
          <SafeAreaView style={{flex:1,backgroundColor:C.bg,paddingTop:TOP_INSET}}>
            <View style={{flexDirection:'row',alignItems:'center',padding:16,borderBottomWidth:1,borderBottomColor:C.border}}>
              <Text style={{flex:1,fontSize:17,fontWeight:'900',color:C.text}}>{modalConfig[modal]?.title}</Text>
              <TouchableOpacity onPress={()=>setModal(null)} style={{padding:6}}>
                <Text style={{fontSize:18,color:C.mid}}>✕</Text>
              </TouchableOpacity>
            </View>
            <View style={{padding:20}}>
              <View style={{flexDirection:'row',alignItems:'center',gap:12,marginBottom:20,padding:14,backgroundColor:C.bg,borderRadius:12}}>
                <Avatar user={sel} size={48}/>
                <View>
                  <Text style={{fontSize:16,fontWeight:'800',color:C.text}}>{sel.name}</Text>
                  <Text style={{fontSize:12,color:C.light}}>{sel.email}</Text>
                  <Text style={{fontSize:12,color:C.amber,fontWeight:'700'}}>{sel.points||0} puan</Text>
                </View>
              </View>
              {modal!=='unban'&&modal!=='unmute'&&modal!=='delete'&&modal!=='reset'?(
                <>
                  <Text style={{fontSize:13,color:C.mid,marginBottom:8}}>{modalConfig[modal]?.hint}</Text>
                  <Inp placeholder={modalConfig[modal]?.hint} value={inputVal} onChangeText={setInputVal}
                    keyboardType={modal==='ban'||modal==='mute'||modal==='pts'||modal==='setpts'?'numeric':'default'}
                    style={{marginBottom:16}}/>
                </>
              ):(
                <View style={{padding:14,backgroundColor:'#fef2f2',borderRadius:10,marginBottom:16}}>
                  <Text style={{fontSize:13,color:C.red,fontWeight:'600'}}>{modalConfig[modal]?.hint}</Text>
                </View>
              )}
              {busy?<ActivityIndicator color={modalConfig[modal]?.color}/>:
                <Btn label={modalConfig[modal]?.btn} onPress={applyAction} color={modalConfig[modal]?.color}/>}
            </View>
          </SafeAreaView>
        </Modal>
      )}
    </View>
  );
}

const ActionBtn=({label,color,onPress})=>(
  <TouchableOpacity onPress={onPress}
    style={{backgroundColor:color+'18',borderRadius:8,paddingHorizontal:10,paddingVertical:5,borderWidth:1,borderColor:color+'44'}}>
    <Text style={{fontSize:11,fontWeight:'700',color}}>{label}</Text>
  </TouchableOpacity>
);

function RootApp(){
  const[user,setUser]=useState(null);
  const[loading,setL]=useState(true);
  useEffect(()=>{db.cur().then(u=>{setUser(u);setL(false);});},[]);
  const logout=async()=>{await db.logout();setUser(null);};
  if(loading)return(
    <View style={{flex:1,justifyContent:'center',alignItems:'center',backgroundColor:C.primary,paddingTop:TOP_INSET}}>
      <Text style={{fontSize:48,marginBottom:16}}>📚</Text>
      <ActivityIndicator color="#fff" size="large"/>
      <Text style={{color:'rgba(255,255,255,0.7)',marginTop:12}}>Yükleniyor…</Text>
    </View>
  );
  if(!user)return<AuthScreen onLogin={async u=>{
    // Ban/mute durumunu bildir
    const banned=u.banned&&u.bannedUntil&&new Date(u.bannedUntil)>new Date();
    const muted=u.muted&&u.mutedUntil&&new Date(u.mutedUntil)>new Date();
    if(banned){
      const days=daysLeft(u.bannedUntil);
      Alert.alert('🚫 Hesabın Banlandı',`Oyun oynama yetkin ${days} gün süreyle kısıtlandı.\nBitiş: ${new Date(u.bannedUntil).toLocaleDateString('tr-TR')}`);
    } else if(muted){
      const days=daysLeft(u.mutedUntil);
      Alert.alert('🔇 Mesajlaşma Kısıtlandı',`Mesaj gönderme yetkin ${days} gün süreyle kısıtlandı.\nBitiş: ${new Date(u.mutedUntil).toLocaleDateString('tr-TR')}`);
    }
    setUser(u);
  }}/>;
  return<FullApp user={user} setUser={setUser} onLogout={logout}/>;
}

/* Tam uygulama — tüm tablar */
const ALL_TABS=[
  {id:'home', l:'Ana Sayfa',e:'🏠'},
  {id:'games',l:'Oyunlar',  e:'🎮'},
  {id:'study',l:'Çalışma',  e:'📊'},
  {id:'board',l:'Sıralama', e:'🏆'},
  {id:'achs', l:'Başarımlar',e:'🏅'},
  {id:'msgs', l:'Mesajlar', e:'💬'},
  {id:'set',  l:'Ayarlar',  e:'⚙️'},
];

function FullApp({user,setUser,onLogout}){
  const[tab,setTab]=useState('home');
  const[scr,setScr]=useState(null);
  const[extra,setExtra]=useState(null);
  const music=useMusicPlayer();
  const historyRef=useRef([]);
  const scrRef=useRef(null);
  const extraRef=useRef(null);
  const go=(s,p)=>{
    if(scrRef.current)historyRef.current.push({scr:scrRef.current,extra:extraRef.current});
    scrRef.current=s; extraRef.current=p||null;
    setScr(s);setExtra(p||null);
  };
  const back=()=>{
    const prev=historyRef.current.pop();
    if(prev){scrRef.current=prev.scr;extraRef.current=prev.extra;setScr(prev.scr);setExtra(prev.extra);}
    else{scrRef.current=null;extraRef.current=null;setScr(null);setExtra(null);}
  };
  const[unreadMap,setUnreadMap]=useState({});
  const[duelInvite,setDuelInvite]=useState(null);
  const[adminNote,setAdminNote]=useState(null); // gösterilecek admin notu
  const[duelBannerVisible,setDuelBannerVisible]=useState(false);
  const bannerAnim=useRef(new Animated.Value(-120)).current;
  const lastReadRef=useRef({});
  // lastRead'i AsyncStorage'dan yükle (çık/gir yapınca sıfırlanmasın)
  useEffect(()=>{
    AsyncStorage.getItem('@yks_lastRead_'+user.id).then(v=>{
      if(v)try{lastReadRef.current=JSON.parse(v);}catch{}
    });
  },[]);

  const startGame=(screen,params)=>go(screen,params);

  // Admin notu kontrolü — uygulama açılışında ve her 30sn'de kontrol
  useEffect(()=>{
    const checkNotes=async()=>{
      try{
        const notes=await db.getAdminNotes(user.id);
        const unread=notes.find(n=>!n.read);
        if(unread)setAdminNote(unread);
      }catch{}
    };
    checkNotes();
    const interval=setInterval(checkNotes,30000);
    return()=>clearInterval(interval);
  },[user.id]);

  // Bildirim izni + oyun hatırlatıcı
  useEffect(()=>{
    (async()=>{
      try{
        const granted=await requestNotificationPermission();
        if(granted)scheduleGameReminder();
      }catch{}
    })();
  },[]);

  useEffect(()=>{
    const sub=BackHandler.addEventListener('hardwareBackPress',()=>{
      if(scr){setScr(null);setExtra(null);return true;}
      if(tab!=='home'){setTab('home');return true;}
      return false;
    });
    return()=>sub.remove();
  },[scr,tab]);

  // Unread mesaj + düello daveti polling
  useEffect(()=>{
    const iv=setInterval(async()=>{
      try{
        const d=await db._r();
        const myMsgs=(d.messages||[]).filter(m=>m.to===user.id);
        const newUnread={};
        for(const m of myMsgs){
          const lastRead=lastReadRef.current[m.from]||0;
          if(m.ts>lastRead)newUnread[m.from]=(newUnread[m.from]||0)+1;
        }
        setUnreadMap(newUnread);
        if(scr!=='duel'){
          const duels=d.duels||[];
          const invite=duels.find(duel=>duel.toId===user.id&&duel.status==='pending'&&Date.now()-duel.ts<60000);
          if(invite&&(!duelInvite||duelInvite.id!==invite.id)){
            const challenger=d.users.find(u=>u.id===invite.fromId);
            if(challenger){
              setDuelInvite({...invite,opponent:challenger,isChallenger:false});
              setDuelBannerVisible(true);
              bannerAnim.setValue(-120);
              Animated.spring(bannerAnim,{toValue:0,useNativeDriver:true,tension:80}).start();
              setTimeout(()=>{
                Animated.timing(bannerAnim,{toValue:-120,duration:350,useNativeDriver:true}).start(()=>setDuelBannerVisible(false));
              },15000);
              // Local bildirim gönder (uygulama arka plandaysa görsün)
              sendDuelNotification(challenger.name||challenger.email||'Birisi');
            }
          }
        }
      }catch{}
    },4000);
    return()=>clearInterval(iv);
  },[user.id,scr,duelInvite]);

  const goChat=(peer)=>{
    lastReadRef.current[peer.id]=Date.now();
    AsyncStorage.setItem('@yks_lastRead_'+user.id, JSON.stringify(lastReadRef.current));
    setUnreadMap(prev=>{const n={...prev};delete n[peer.id];return n;});
    go('chat',peer);
  };

  useEffect(()=>{
    const interval=setInterval(async()=>{
      try{
        const fresh=await db.byId(user.id);
        if(fresh&&fresh.points!==user.points){
          const updated={...user,...fresh};
          await AsyncStorage.setItem('@yks_cur_v5',JSON.stringify(updated));
          setUser(updated);
        }
      }catch{}
    },10000);
    return()=>clearInterval(interval);
  },[user.id,user.points]);

  const totalUnread=Object.values(unreadMap).reduce((s,v)=>s+v,0);
  const dismissDuelBanner=()=>{
    Animated.timing(bannerAnim,{toValue:-120,duration:300,useNativeDriver:true}).start(()=>{setDuelBannerVisible(false);setDuelInvite(null);});
  };
  const acceptDuelFromBanner=()=>{dismissDuelBanner();go('duel',null);};

  const isAdminUser=isAdmin(user);
  if(GAME_IDS.includes(scr))return<GameScreen type={scr} onBack={back} user={user} setUser={setUser}/>;
  if(scr==='chat')return<ChatScreen user={user} peer={extra} onBack={back}/>;
  if(scr==='viewProfile')return<ViewProfile userId={extra} me={user} onBack={back} onMessage={u=>{goChat(u);}}/>
  if(scr==='pomodoro')return<PomodoroScreen onBack={back} user={user} setUser={setUser}/>
  if(scr==='favorites')return<FavoritesScreen onBack={back} user={user}/>
  if(scr==='duel')return<DuelScreen onBack={back} user={user} setUser={setUser} incomingInvite={duelInvite} onClearInvite={()=>{setDuelInvite(null);setDuelBannerVisible(false);}}/>;
  if(scr==='subjectTopics')return<SubjectTopicsScreen gameId={extra?.gameId} onBack={back} go={startGame}/>;
  if(scr==='topicQuiz')return<TopicQuizScreen topic={extra?.topic} color={extra?.color||'#4338ca'} onBack={back} user={user} setUser={setUser}/>;
  if(scr==='matchGame')return<MatchingGameScreen setId={extra?.setId} onBack={back} user={user} setUser={setUser}/>;
  if(scr==='writingGame')return<WritingGameScreen gameId={extra?.gameId} onBack={back} user={user} setUser={setUser}/>;
  if(scr==='chemLab')return<ChemistryLabScreen onBack={back}/>;
  if(scr==='gradeSubject')return<GradeSubjectScreen onBack={back} go={go}/>;
  if(scr==='circularTopics')return<CircularTopicMenuScreen subject={extra?.subject} onBack={back} go={startGame}/>;
  const renderTab=()=>{
    switch(tab){
      case 'home':  return<HomeTab  user={user} go={startGame} music={music} setTab={setTab}/>;
      case 'games': return<GamesTab go={startGame}/>;
      case 'study': return<StudyTab user={user}/>;
      case 'board': return<BoardTab user={user} go={go}/>;
      case 'achs':  return<AchsTab  user={user}/>;
      case 'msgs':  return<MsgsTab  user={user} go={(s,p)=>{if(s==='chat'&&p)goChat(p);else go(s,p);}} unreadMap={unreadMap}/>;
      case 'set':   return<SettingsTab user={user} setUser={setUser} onLogout={onLogout} go={go}/>;
      case 'admin': return isAdminUser?<AdminTab user={user} setUser={setUser}/>:null;
      default: return null;
    }
  };
  const TAB_SHOW=[
    {id:'home', e:'🏠',l:'Anasayfa'},
    {id:'board',e:'🏆',l:'Sıralama'},
    {id:'achs', e:'🏅',l:'Başarım'},
    {id:'msgs', e:'💬',l:'Mesajlar'},
    {id:'set',  e:'⚙️',l:'Ayarlar'},
    ...(isAdminUser?[{id:'admin',e:'🛡️',l:'Admin'}]:[]),
  ];
  return(
    <>
    <SafeAreaView style={{flex:1,backgroundColor:C.bg,paddingTop:TOP_INSET}}>
      <StatusBar barStyle="dark-content" backgroundColor={C.bg} translucent={false}/>
      <View style={{flex:1}}>{renderTab()}</View>
      {duelBannerVisible&&duelInvite&&(
        <Animated.View style={{position:'absolute',top:TOP_INSET+8,left:16,right:16,zIndex:9999,transform:[{translateY:bannerAnim}]}}>
          <View style={{backgroundColor:'#1a1740',borderRadius:16,padding:14,borderWidth:1.5,borderColor:'#6d28d9',shadowColor:'#6d28d9',shadowOpacity:0.5,shadowRadius:12,elevation:20,flexDirection:'row',alignItems:'center',gap:12}}>
            <View style={{width:42,height:42,borderRadius:21,backgroundColor:'rgba(109,40,217,0.3)',alignItems:'center',justifyContent:'center'}}>
              <Text style={{fontSize:22}}>⚔️</Text>
            </View>
            <View style={{flex:1}}>
              <Text style={{color:'#c4b5fd',fontSize:12,fontWeight:'900'}}>Düello Teklifi!</Text>
              <Text style={{color:'rgba(255,255,255,0.85)',fontSize:13,fontWeight:'700'}} numberOfLines={1}>{duelInvite.opponent.name} sizi düelloya davet etti!</Text>
            </View>
            <View style={{gap:6}}>
              <TouchableOpacity onPress={acceptDuelFromBanner} style={{backgroundColor:'#22c55e',borderRadius:8,paddingHorizontal:10,paddingVertical:5}}>
                <Text style={{color:'#fff',fontSize:11,fontWeight:'800'}}>Kabul</Text>
              </TouchableOpacity>
              <TouchableOpacity onPress={dismissDuelBanner} style={{backgroundColor:'rgba(255,255,255,0.1)',borderRadius:8,paddingHorizontal:10,paddingVertical:5}}>
                <Text style={{color:'rgba(255,255,255,0.6)',fontSize:11,fontWeight:'700'}}>Reddet</Text>
              </TouchableOpacity>
            </View>
          </View>
        </Animated.View>
      )}
      <View style={[st.tabBar,{paddingBottom:BOTTOM}]}>
        {TAB_SHOW.map(t=>{
          const isMsgs=t.id==='msgs';
          const badge=isMsgs&&totalUnread>0;
          return(
            <TouchableOpacity key={t.id} onPress={()=>setTab(t.id)} style={st.tabItem}>
              <View style={{position:'relative'}}>
                <Text style={{fontSize:20}}>{t.e}</Text>
                {badge&&(<View style={{position:'absolute',top:-4,right:-6,width:16,height:16,borderRadius:8,backgroundColor:C.red,alignItems:'center',justifyContent:'center',borderWidth:1.5,borderColor:C.bg}}><Text style={{color:'#fff',fontSize:8,fontWeight:'900'}}>{totalUnread>9?'9+':totalUnread}</Text></View>)}
              </View>
              <Text style={{fontSize:8,fontWeight:'600',color:tab===t.id?C.primary:C.light,marginTop:1}}>{t.l}</Text>
            </TouchableOpacity>
          );
        })}
      </View>
    </SafeAreaView>
    {/* Admin Notu Popup */}
    {adminNote&&(
      <AdminNotePopup
        note={adminNote}
        onClose={async()=>{
          await db.markAdminNoteRead(adminNote.id);
          setAdminNote(null);
        }}
      />
    )}    </>
  );
}

function RootAppWrapper(){
  return(
    <GestureHandlerRootView style={{flex:1}}>
      <RootApp/>
    </GestureHandlerRootView>
  );
}
export default RootAppWrapper;